-- Poems batch 215
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('660b447f-31e9-4d75-9232-95ccb93eb9c6','句  其一九','元絳','宋','宋诗','song-poetry','','[]','小雨疎疎向晚晴。',8,'全唐诗/poet.song.20000.json','["小雨疎疎向晚晴。"]'),
('f3d668b1-bd7a-4ee4-9463-4d17b70a707d','寒食遊九仙烏石二山','程師孟','宋','宋诗','song-poetry','','[]','城中無事喜尋山，千里提封並海寬。',64,'全唐诗/poet.song.20000.json','["城中無事喜尋山，千里提封並海寬。", "賓客相從筵既冷，士民同出食猶寒。", "芳園病葉堆何限，古院閑花落幾般。", "誰道異鄉多感慨，登臨遲却十年官。"]'),
('6a4901dc-9769-4e2e-aa04-2fc000b921c8','曉登威武軍鼓角樓','程師孟','宋','宋诗','song-poetry','','[]','百尺譙門戍萬兵，黄昏初動畫龍聲。',64,'全唐诗/poet.song.20000.json','["百尺譙門戍萬兵，黄昏初動畫龍聲。", "銅鉦猶是閩王點，銀秤纔懸漢守更。", "四面僧誇金作界，半年人看玉爲城。", "官程稍近千餘里，不到儂家向此行。"]'),
('e794fa4f-6d94-46b1-a5ff-cd82fbe0bf28','科漏新成','程師孟','宋','宋诗','song-poetry','','[]','臺門新漏一聲聞，從此朝昏百刻分。',64,'全唐诗/poet.song.20000.json','["臺門新漏一聲聞，從此朝昏百刻分。", "他日郡人思太守，也須談及葉參軍。", "風雨雖昏漏不移，百年應未失毫釐。", "須知萬戶千門裏，正得人間吉凶時。"]'),
('f2f90068-8f81-4cd7-aa2b-fb59226743bd','昇山祠堂','程師孟','宋','宋诗','song-poetry','','[]','行處松蘿深似幄，望中城郭細如棋。',32,'全唐诗/poet.song.20000.json','["行處松蘿深似幄，望中城郭細如棋。", "清泉可惜藏巖下，不作先生洗藥池。"]'),
('4de89e15-b811-487d-bbe4-169ecdd83ded','卧龍山','程師孟','宋','宋诗','song-poetry','','[]','聞說林泉便訪尋，平田一逕上孤岑。',64,'全唐诗/poet.song.20000.json','["聞說林泉便訪尋，平田一逕上孤岑。", "榕陰落處宜千客，荔子生時直萬金。", "盡放遲回官舍近，不妨閑坐石門深。", "四邊稻熟征租了，稍愜農家出郭心。"]'),
('4c4727d6-de9d-4854-867d-42d9bfb63086','靜遊亭','程師孟','宋','宋诗','song-poetry','','[]','石磴高軒榜靜遊，度年紅葉少驚秋。',32,'全唐诗/poet.song.20000.json','["石磴高軒榜靜遊，度年紅葉少驚秋。", "使君會得山僧意，不放笙歌到上頭。"]'),
('357bcd60-9e14-4454-88b6-a59600089837','上巳遊東禪','程師孟','宋','宋诗','song-poetry','','[]','出城林徑起蒼煙，白馬遺蹤俗尚傳。',64,'全唐诗/poet.song.20000.json','["出城林徑起蒼煙，白馬遺蹤俗尚傳。", "第一僧居蘭若處，幾番身醉荔枝前。", "百年騷客來題寺，三月遊人作樂天。", "更愛堂頭迎太守，路旁先墜碧雲編。"]'),
('2e110dbf-606d-4aa4-a023-6ce499d2e8b5','端午出遊','程師孟','宋','宋诗','song-poetry','','[]','三山縹緲藹蓬萊，一望青天十里平。',64,'全唐诗/poet.song.20000.json','["三山縹緲藹蓬萊，一望青天十里平。", "千騎臨流搴翠帷，萬人擁道出重城。", "參差螮蝀橫波瀾，飛躍鯨鯢鬭楫輕。", "且醉樽前金瀲灧，笙歌歸道月華明。"]'),
('550d23be-c1f0-462a-a278-93fda8c804a2','植槦','程師孟','宋','宋诗','song-poetry','','[]','三樓相望枕城隅，臨去重栽木萬株。',32,'全唐诗/poet.song.20000.json','["三樓相望枕城隅，臨去重栽木萬株。", "試問國人行往處，不知還憶使君無。"]'),
('89245b60-eb74-479b-934a-0cd99c637f5f','楓橋寺','程師孟','宋','宋诗','song-poetry','','[]','門對雲山畫不如，師今一念六年居。',32,'全唐诗/poet.song.20000.json','["門對雲山畫不如，師今一念六年居。", "邇來寺好尤瀟灑，張繼留題內翰書。"]'),
('0f00c649-c6b5-47e7-8f49-5026630c1038','遊楓橋偶成','程師孟','宋','宋诗','song-poetry','','[]','晚泊橋邊寺，迎風坐一軒。',48,'全唐诗/poet.song.20000.json','["晚泊橋邊寺，迎風坐一軒。", "好山平隔岸，流水漫過門。", "朱舫朝天路，青林近郭村。", "主人頭似雪，怪我到多番。"]'),
('322c6b94-6062-4ddf-ab1a-7c351dc67a3a','入湧泉道中  其一','程師孟','宋','宋诗','song-poetry','','["\u592a\u6e56"]','小航時過越溪頭，當日吳宮事可求。',64,'全唐诗/poet.song.20000.json','["小航時過越溪頭，當日吳宮事可求。", "西子冶容來作餌，伍員忠憤反爲讎。", "雖無別館虹蜺带，但有荒臺麋鹿遊。", "高望太湖千萬頃，夕陽依舊水東流。"]'),
('28af17fb-a4ee-432b-8f3a-0a0d0d9f5f11','入湧泉道中  其二','程師孟','宋','宋诗','song-poetry','','[]','窮冬未見六花飄，春意微微動柳梢。',64,'全唐诗/poet.song.20000.json','["窮冬未見六花飄，春意微微動柳梢。", "千丈龍形蟠暮嶺，一條虹影落溪橋。", "閶門飛跨何清泚，茂苑繁雄未寂寥。", "切幸早歸頻出郭，西山隠客不須招。"]'),
('3146e5e0-674b-4810-8d7f-d85ce770b888','入湧泉道中  其三','程師孟','宋','宋诗','song-poetry','','[]','因省先塋到故都，不妨閒步問耕夫。',64,'全唐诗/poet.song.20000.json','["因省先塋到故都，不妨閒步問耕夫。", "水雲蒼莽遥連洞，田野低漥稍近湖。", "秋熟幾家收橘柚，日生衆口藉菰蒲。", "今朝偶得西華稻，僧飯年年出玉腴。"]'),
('3be0bace-a6aa-4fb0-ad0c-6c6f214d903b','入湧泉道中  其四','程師孟','宋','宋诗','song-poetry','','[]','道出橫塘跨石梁，塘南塘北稻花香。',64,'全唐诗/poet.song.20000.json','["道出橫塘跨石梁，塘南塘北稻花香。", "風吹舴艋輕如駛，日照浮圖峻若翔。", "遠岸漁樵三兩兩，近村鵝鴨一行行。", "回頭却指城南路，雲屋朱樓氣鬰蒼。"]'),
('5e0197ad-9e93-4f62-9956-c506a93274e3','入湧泉道中  其五','程師孟','宋','宋诗','song-poetry','','[]','寒林已見早梅芳，盡日臨流野興長。',64,'全唐诗/poet.song.20000.json','["寒林已見早梅芳，盡日臨流野興長。", "門外牛羊人自得，籬邊雞犬盜誰防。", "三江夜色滄浪白，千里秋香𥝧䅉黄。", "借問船中何所有，橙虀鱸鱠酒先嘗。"]'),
('5318f58f-8e3b-4b39-9795-a763cdd028e2','入湧泉道中  其六','程師孟','宋','宋诗','song-poetry','','[]','舟行如葉泛長川，解水吳兒力可全。',64,'全唐诗/poet.song.20000.json','["舟行如葉泛長川，解水吳兒力可全。", "風急輒先千浪破，岸欹能把一䉡牽。", "湖沈日影山頭畫，雲漏天光雨足懸。", "試向中流東北望，城南寶塔在門前。"]'),
('34ad146e-597d-44e7-8f00-fc16cb852eb7','入湧泉道中  其七','程師孟','宋','宋诗','song-poetry','','[]','告老清朝分自安，從今榮悴不相關。',64,'全唐诗/poet.song.20000.json','["告老清朝分自安，從今榮悴不相關。", "有愁方見田家樂，無事纔知釣叟閒。", "世故要看終始後，人生未免是非間。", "婦墳更在公塋側，一舸夷猶遂往還。"]'),
('d8135d86-15c0-4191-8962-27244ea4c078','入湧泉道中  其八','程師孟','宋','宋诗','song-poetry','','[]','誰何不欲蚤忘機，今已高年古亦稀。',64,'全唐诗/poet.song.20000.json','["誰何不欲蚤忘機，今已高年古亦稀。", "翠柳陰中黄鳥過，青山影裏白鷗飛。", "新春已到無高下，故里重過有是非。", "人意不如毛羽意，聲聲猶道不如歸。"]'),
('edc22ea1-1c66-4869-849f-ba9856246e63','南安軍','程師孟','宋','宋诗','song-poetry','','[]','今日平安出嶺時，瘴氛猶覺潤征衣。',32,'全唐诗/poet.song.20000.json','["今日平安出嶺時，瘴氛猶覺潤征衣。", "一條路入江南去，萬里人從海上歸。"]'),
('dbc0a6e2-97c5-47c3-81ad-111365aa1cdf','題共樂亭','程師孟','宋','宋诗','song-poetry','','[]','千門日照珍珠市，萬瓦煙生碧玉城。',32,'全唐诗/poet.song.20000.json','["千門日照珍珠市，萬瓦煙生碧玉城。", "山海是爲中國藏，梯航尤見外夷情。"]'),
('142fe107-7bfa-46f1-b9d7-7531703def72','湯泉  其一','程師孟','宋','宋诗','song-poetry','','[]','曾看華清舊浴池，此泉何日落天涯。',32,'全唐诗/poet.song.20000.json','["曾看華清舊浴池，此泉何日落天涯。", "徘徊却想開元事，不見蓮花見荔枝。"]'),
('1f43b450-a326-46b2-937a-deb4b9bd6624','湯泉  其二','程師孟','宋','宋诗','song-poetry','','[]','山半炎泉湧不停，陰陽爲炭自燻蒸。',32,'全唐诗/poet.song.20000.json','["山半炎泉湧不停，陰陽爲炭自燻蒸。", "天公不許楊妃見，留待年年浴衆僧。"]'),
('e490e0d7-db4c-44b8-935e-7269f7edef70','越山亭','程師孟','宋','宋诗','song-poetry','','[]','江山千古仙人地，城郭三春刺史天。',32,'全唐诗/poet.song.20000.json','["江山千古仙人地，城郭三春刺史天。", "文士莫如今日盛，方袍更比別州偏。"]'),
('ce34cfea-f06a-4158-856c-db5f9f241063','荔枝  其一','程師孟','宋','宋诗','song-poetry','','[]','水浮蓬島通賓館，日出扶桑照戟門。',32,'全唐诗/poet.song.20000.json','["水浮蓬島通賓館，日出扶桑照戟門。", "一等翠林無別水，四邊惟有荔枝園。"]'),
('9625646b-47b7-4bdb-b0c3-2f95847359fa','荔枝  其二','程師孟','宋','宋诗','song-poetry','','[]','重門畫戟公堂峻，萬瓦清煙使宅雄。',32,'全唐诗/poet.song.20000.json','["重門畫戟公堂峻，萬瓦清煙使宅雄。", "草服勸耕菖葉綠，羅裙送酒荔枝紅。"]'),
('9b0d46c4-d21f-4350-a08d-4f414a033685','寶嚴院','程師孟','宋','宋诗','song-poetry','','[]','路口百餘松，南唐古梵宮。',48,'全唐诗/poet.song.20000.json','["路口百餘松，南唐古梵宮。", "溪邊石不斷，鉢裏飯無窮。", "山態時時別，泉聲處處同。", "元宗遺手墨，猶足耀門風。"]'),
('bc05d738-23b7-4191-8162-bd7d9ddf0bcc','遊玉尺山寺','程師孟','宋','宋诗','song-poetry','','[]','永日清陰喜獨來，野僧題石作吟臺。',32,'全唐诗/poet.song.20000.json','["永日清陰喜獨來，野僧題石作吟臺。", "無詩可比顔光祿，每憶登臨却自回。"]'),
('f98ad651-e009-4549-9243-624d2c9cf40a','牛頭寺','程師孟','宋','宋诗','song-poetry','','[]','前日閩都舊長官，窮冬從此據征鞍。',64,'全唐诗/poet.song.20000.json','["前日閩都舊長官，窮冬從此據征鞍。", "牛頭寺裏千峰月，水口村邊萬石灘。", "竹葉盡來堂少暖，荔枝無處地多寒。", "明朝出境重回首，已約三山馬上看。"]'),
('52553a2b-5fad-4b96-b904-a7d4702e9a37','與伯常會宿宿猿洞','程師孟','宋','宋诗','song-poetry','','[]','雙塔和雲宿翠屏，夢魂千里到禪扃。',32,'全唐诗/poet.song.20000.json','["雙塔和雲宿翠屏，夢魂千里到禪扃。", "還教畫手添新意，一簇林猿伴二星。"]'),
('cd787db7-ae7a-41e7-b47e-0581f35fda6d','宿猿洞和張徽韻','程師孟','宋','宋诗','song-poetry','','[]','更深應是枕雙欹，思得臯夔事業齊。',32,'全唐诗/poet.song.20000.json','["更深應是枕雙欹，思得臯夔事業齊。", "終爲清時難退隠，出山甘被百禽啼。"]'),
('1e9de7a8-a658-426a-9e62-a85347ecd923','又會宿猿洞','程師孟','宋','宋诗','song-poetry','','[]','永感無心戀搢紳，十年不起卧龍身。',32,'全唐诗/poet.song.20000.json','["永感無心戀搢紳，十年不起卧龍身。", "一朝黄紙除書下，八郡衣冠盡望塵。"]'),
('8cfe9378-4e98-4ccc-9e4b-93f831e5b35d','越二年正旦又會宿猿洞','程師孟','宋','宋诗','song-poetry','','[]','夜半春歸曉始驚，鬰然佳氣入山亭。',64,'全唐诗/poet.song.20000.json','["夜半春歸曉始驚，鬰然佳氣入山亭。", "千門喜慶逢元日，一座光華見使星。", "難得同時傳壽斝，合將新句勒詩屏。", "漁郎莫向遊人道，洞口而今盡不扃。"]'),
('c42870cb-546d-4baf-bef7-c385a49189e7','宿猿洞餞仲謨','程師孟','宋','宋诗','song-poetry','','[]','洞口車輪欲去時，江山風物動光輝。',32,'全唐诗/poet.song.20000.json','["洞口車輪欲去時，江山風物動光輝。", "不須猿鶴相驚怨，自是君王未放歸。"]'),
('3bb93a68-bad9-43fd-907f-af420fef5540','次韻元厚之少保留題朱伯原祕校園亭  其一','程師孟','宋','宋诗','song-poetry','','[]','少年爲學已名家，才折丹枝病可嗟。',64,'全唐诗/poet.song.20000.json','["少年爲學已名家，才折丹枝病可嗟。", "節带冰霜凌萬竹，文含風露麗于花。", "也憐美玉猶存璞，人恨良金未出沙。", "頼有隠居如谷口，直將高意抗青霞。"]'),
('43f666b4-e76c-462d-8927-a8cdcf684d0a','次韻元厚之少保留題朱伯原祕校園亭  其二','程師孟','宋','宋诗','song-poetry','','[]','君家幽寂似山家，聞者其誰不見嗟。',64,'全唐诗/poet.song.20000.json','["君家幽寂似山家，聞者其誰不見嗟。", "閉戶幾多閑日月，掃園有限舊煙花。", "書窗燕坐琴橫石，吟徑徐行杖卓沙。", "壁有謝公題好句，國人方此識餘霞。"]'),
('1b95c5f1-ef05-4715-83a7-39e7e573f51a','次韻元厚之少保留題朱伯原祕校園亭  其三','程師孟','宋','宋诗','song-poetry','','[]','碧瓦春城十萬家，可憐夫子獨堪嗟。',64,'全唐诗/poet.song.20000.json','["碧瓦春城十萬家，可憐夫子獨堪嗟。", "園林猶有前朝木，完蓋難尋故主花。", "亭瞰夕陽鄰古剎，池通野水見晴沙。", "天然操尚無塵滓，合住蓬萊弄綵霞。"]'),
('447d8bb4-1926-4c3f-9a29-d57b9d62468f','書仲謨先人功德院','程師孟','宋','宋诗','song-poetry','','[]','高門餘慶本光山，不幸流離五代間。',32,'全唐诗/poet.song.20000.json','["高門餘慶本光山，不幸流離五代間。", "今日太平家可樂，郎君富貴錦衣還。"]'),
('72dc8296-096b-4c3c-b364-ff6b7454a888','送虔州通判周茂叔對移永州','程師孟','宋','宋诗','song-poetry','','[]','移官遠過耒陽西，好景重重合盡題。',64,'全唐诗/poet.song.20000.json','["移官遠過耒陽西，好景重重合盡題。", "永水自然勝灨水，浯溪應不讓濂溪。", "沙頭候吏瞻旗脚，境上鄉人待馬蹄。", "會是忠賢流落處，至今蘭芷尚萋萋。"]'),
('bbae5b63-e420-4288-b93c-b69904b74f4a','秦少遊題郡中蓬萊閣次其韻','程師孟','宋','宋诗','song-poetry','','[]','半天鐘鼓宴崢嶸，早晚陰晴景旋生。',64,'全唐诗/poet.song.20000.json','["半天鐘鼓宴崢嶸，早晚陰晴景旋生。", "湖暖水香春載酒，月寒雲白夜聞笙。", "金鼇破海頭爭出，玉鷺排煙陣自橫。", "我是蓬萊東道主，倚欄長占日初明。"]'),
('c5ab54e0-10df-48be-b87a-06667204e39b','句  其一','程師孟','宋','宋诗','song-poetry','','[]','蒼煙巷陌青榕木。',8,'全唐诗/poet.song.20000.json','["蒼煙巷陌青榕木。"]'),
