('8b9fdc70-a67f-43af-a40a-8f7a7e604208','句  其一七','程師孟','宋','宋诗','song-poetry','','[]','亭爲新成號獅子，人曾舊隠作龍頭。',16,'全唐诗/poet.song.20000.json','["亭爲新成號獅子，人曾舊隠作龍頭。"]'),
('e36d2db5-9161-419e-a13b-cbaf1dbfe059','句  其一八','程師孟','宋','宋诗','song-poetry','','[]','香焚薝蔔巖雲院，花發莎羅海山春。',16,'全唐诗/poet.song.20000.json','["香焚薝蔔巖雲院，花發莎羅海山春。"]'),
('c76c58ec-ce81-4a98-9158-b573b3a6c6cc','句  其一九','程師孟','宋','宋诗','song-poetry','','[]','山自昔來多積雪，寺從興後有遺風。',16,'全唐诗/poet.song.20000.json','["山自昔來多積雪，寺從興後有遺風。"]'),
('be307939-5591-49af-b81a-e6dbe7981477','句  其二○','程師孟','宋','宋诗','song-poetry','','[]','江山自是長生境，城郭今爲極樂坊。',16,'全唐诗/poet.song.20000.json','["江山自是長生境，城郭今爲極樂坊。"]'),
('f839170c-e894-495a-8b3d-2f50c425c11e','句  其二一','程師孟','宋','宋诗','song-poetry','','[]','每日要忙須一到，夜深長是點燈來。',16,'全唐诗/poet.song.20000.json','["每日要忙須一到，夜深長是點燈來。"]'),
('f5d3681d-999c-4fea-90f7-bc9cbde2aa4d','句  其二二','程師孟','宋','宋诗','song-poetry','','[]','收得一般瀟灑物，龜形人送鶴書來。',16,'全唐诗/poet.song.20000.json','["收得一般瀟灑物，龜形人送鶴書來。"]'),
('1768dc49-049f-4f39-b474-1a491d56237b','句  其二三','程師孟','宋','宋诗','song-poetry','','[]','珊瑚花發客疑真。',8,'全唐诗/poet.song.20000.json','["珊瑚花發客疑真。"]'),
('531ba5d4-f04d-4e89-b735-1e6e3576fd98','句','熊岑','宋','宋诗','song-poetry','','[]','溪藤頻得句，雪舫夜留賓。',12,'全唐诗/poet.song.20000.json','["溪藤頻得句，雪舫夜留賓。"]'),
('f7d610dd-378a-45cb-b8f8-ec0488b1d7b6','宿猿洞和程師孟韻','福州運判','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','曉來人語□□驚，空有三元□□亭。',64,'全唐诗/poet.song.20000.json','["曉來人語□□驚，空有三元□□亭。", "凍酒點唇浮白蟻，穠桃迷眼落紅星。", "地名小酉神仙窟，天設湘陰水墨屏。", "藴藉莫誇洞庭記，移文休勒北山扃。"]'),
('ffb0a699-52d0-4dd1-bade-0c71d3161539','嘲願成','釋文瑩','宋','宋诗','song-poetry','','[]','童頭浮屠浙東客，傳呼避道長以陌。',128,'全唐诗/poet.song.20000.json','["童頭浮屠浙東客，傳呼避道長以陌。", "寶撾青蓋官儀雄，新賜袈裟椹猶黑。", "察車後乘從驅挈，庸夫無謀動蠻穴。", "暗灘夜被猿猱擒，縛入新溪哭殘月。", "牂牁畏佛不敢烹，脫身腥窟存餘生。", "放師回目不自愧，反以意氣湘南行。", "我聞辛有適伊川，變戎預讖麟經編。", "暌車載鬼吁可怪，宜入熙寧志怪篇。"]'),
('dd918b60-c2d0-4d33-86fb-ed5daa6b3cd0','三生藏','釋文瑩','宋','宋诗','song-poetry','','[]','達者性不晦，鍊形重入胎。',48,'全唐诗/poet.song.20000.json','["達者性不晦，鍊形重入胎。", "一元真璞在，三指舊山來。", "流俗見去住，法身無往回。", "昔經行道院，香撥一星灰。"]'),
('38852d02-6cf4-422f-9c55-452566568a38','寶積寺小雨','釋文瑩','宋','宋诗','song-poetry','','[]','老木垂紺髮，野花翻麯塵。',48,'全唐诗/poet.song.20000.json','["老木垂紺髮，野花翻麯塵。", "明霞送孤鶩，僻路少雙鱗。", "天近易得雨，洞深無早春。", "山祗認來客，曾是洞中真。"]'),
('1275a550-e919-47e1-9acd-56d55906d946','題陳相別業','張宗永','宋','宋诗','song-poetry','','[]','喬松翠竹絕纖埃，門對南山盡日開。',32,'全唐诗/poet.song.20000.json','["喬松翠竹絕纖埃，門對南山盡日開。", "應是主人貪報國，功成名遂不歸來。"]'),
('b1877076-e7dd-444f-be69-9b3f8c035cd4','句','張宗永','宋','宋诗','song-poetry','','[]','大書文字隄防老，剩買峯巒淮備閑。',16,'全唐诗/poet.song.20000.json','["大書文字隄防老，剩買峯巒淮備閑。"]'),
('b26ffab7-afba-4b5b-801d-bcfd54e3f698','詩一首','沈邈','宋','宋诗','song-poetry','','[]','背郭千峯起，涵空一水泓。',24,'全唐诗/poet.song.20000.json','["背郭千峯起，涵空一水泓。", "風帆人共遠，潮嶼歲重耕。"]'),
('3e522b21-0da7-4bb3-b780-3b35ba3f690f','贈蘇軾兄弟','劉巨','宋','宋诗','song-poetry','','[]','驚人事業傳三館，動地文章震九州。',32,'全唐诗/poet.song.20000.json','["驚人事業傳三館，動地文章震九州。", "老夫欲別無他祝，以願雙封萬戶侯。"]'),
('54a9dc38-3f38-40e2-99f6-9d8b7b93539c','句','劉巨','宋','宋诗','song-poetry','','[]','漁人忽驚起，雪片逐風斜。',12,'全唐诗/poet.song.20000.json','["漁人忽驚起，雪片逐風斜。"]'),
('fd8059d9-b40d-4af8-bb8f-1a31ec488fee','隠居','危固','宋','宋诗','song-poetry','','[]','高士隠居處，迢迢綠水灣。',48,'全唐诗/poet.song.20000.json','["高士隠居處，迢迢綠水灣。", "數間玉川屋，七里子陵灘。", "出入是非外，醉醒文字間。", "千鐘天子祿，不肯換清閑。"]'),
('deb76fbb-722d-4904-96b0-50f9eff4b971','送僧歸西林院','危固','宋','宋诗','song-poetry','','[]','振錫西林去，清閑稱所依。',48,'全唐诗/poet.song.20000.json','["振錫西林去，清閑稱所依。", "高巢孤鶴返，深谷片雲歸。", "野色供吟筆，秋光射衲衣。", "長亭携別處，落日半沉暉。"]'),
('15c90ebe-2d60-4daa-96bd-44af62a008e0','廣福院','危固','宋','宋诗','song-poetry','','[]','二月楊花滿路飛，鶑篁清巧弄晴暉。',32,'全唐诗/poet.song.20000.json','["二月楊花滿路飛，鶑篁清巧弄晴暉。", "誰知騷雅尋芳客，寂寞東風馬上歸。"]'),
('c9ed7187-1d50-409d-bc0e-4c0f61a7a5df','福山寺','危固','宋','宋诗','song-poetry','','[]','覆船山色翠峨峨，栽石藏雲不厭多。',32,'全唐诗/poet.song.20000.json','["覆船山色翠峨峨，栽石藏雲不厭多。", "達理禪師超彼岸，莫疑身外有風波。"]'),
('318d6fcd-5fc7-422a-9a06-8f930f51bddf','咏麻姑山','陳陀','宋','宋诗','song-poetry','','[]','曉入麻姑瑞氣浮，羽人重喜故人游。',64,'全唐诗/poet.song.20000.json','["曉入麻姑瑞氣浮，羽人重喜故人游。", "鶴從仙仗歸丹穴，藥種靈苗滿舊洲。", "喬木老含春色澹，夜溪寒带月光流。", "登臨已覺凡塵少，何必區區慕虎邱。"]'),
('098ffac1-913f-4339-80dd-5bd691f26088','絕筆','陳大雅','宋','宋诗','song-poetry','','[]','胡柳陂中過，令人念戰功。',48,'全唐诗/poet.song.20000.json','["胡柳陂中過，令人念戰功。", "兵交千騎沒，血染一川紅。", "朱氏皆豚犬，唐家盡虎龍。", "壯圖成慷慨，擲劒向西風。"]'),
('19937e84-7ec3-4e24-83ae-6ae72a29efee','題招提院靜照堂','聞人安壽','宋','宋诗','song-poetry','','[]','名藍小隠愜高情，雅構堂深豁眼明。',64,'全唐诗/poet.song.20000.json','["名藍小隠愜高情，雅構堂深豁眼明。", "萬慮平時身可外，一軒安處道初生。", "花縈寶砌當春盛，香滿金爐入座清。", "復有高人乘興至，爲題佳句遍雕甍。"]'),
('ec7668da-975d-489d-bba7-932ec398f356','句','張唐卿','宋','宋诗','song-poetry','','[]','一舉首登龍虎榜，十年身到鳳凰池。',16,'全唐诗/poet.song.20000.json','["一舉首登龍虎榜，十年身到鳳凰池。"]'),
('563dd38a-6e03-4fb3-b96d-feb8f32bf816','賜武元亨','宋仁宗','宋','宋诗','song-poetry','','[]','只向身邊有大還，胎神月殿在秋天。',32,'全唐诗/poet.song.20000.json','["只向身邊有大還，胎神月殿在秋天。", "三靈密像誰分別，尺質清虛本自然。"]'),
('2ef8335a-767c-49db-bc66-29b7184da615','幸資善堂','宋仁宗','宋','宋诗','song-poetry','','[]','先皇教善敞東闈，菲德承宗頼慶暉。',64,'全唐诗/poet.song.20000.json','["先皇教善敞東闈，菲德承宗頼慶暉。", "爲感儲筵驚歲月，因瞻臺像駐驂騑。", "楹書乍啟欽遺澤，庭樹重攀記舊圍。", "疇日學文親政地，仰懷慈訓倍依依。"]'),
('167105b6-784a-4399-a07a-de38a2205a37','送李端懿帥鄆','宋仁宗','宋','宋诗','song-poetry','','[]','魯館名臣子，皇家外弟親。',48,'全唐诗/poet.song.20000.json','["魯館名臣子，皇家外弟親。", "詩書謀帥舊，金竹剖符新。", "九郡提封遠，一圻甘澤均。", "純誠宜報國，撫士愛吾民。"]'),
('fcc5678b-cc3c-4e3f-80f0-351ed54388ac','賜梅摯知杭州','宋仁宗','宋','宋诗','song-poetry','','[]','地有湖山美，東南第一州。',48,'全唐诗/poet.song.20000.json','["地有湖山美，東南第一州。", "剖符宣政化，持橐輟才流。", "暫出論思列，遥分旰昃憂。", "循良勤撫俗，來暮聽歌謳。"]'),
('e9e52c88-6e90-4765-bb0d-f43bf74c4e89','輓劉沆','宋仁宗','宋','宋诗','song-poetry','','[]','早富經綸業，終成輔弼功。',48,'全唐诗/poet.song.20000.json','["早富經綸業，終成輔弼功。", "立朝無黨勢，爲國盡公忠，此日悲遺直，誰人嗣匪躬。", "深嗟亡一鑑，何以慰予衷。"]'),
('a4b392b5-9744-402f-bd4b-2f14077bfd37','慶曆八年四月二十八日漢體書二詩  其一','宋仁宗','宋','宋诗','song-poetry','','[]','花領紅鬃一向偏，綠槐香陌欲朝天。',32,'全唐诗/poet.song.20000.json','["花領紅鬃一向偏，綠槐香陌欲朝天。", "仍嫌衆裏驕行疾，傍鐙深藏白玉鞭。"]'),
('2dacdc38-f1f1-48f8-8ec7-a24d66e754fe','慶曆八年四月二十八日漢體書二詩  其二','宋仁宗','宋','宋诗','song-poetry','','[]','腰間寶劍七星文，臂上雕弓百戰勳。',32,'全唐诗/poet.song.20000.json','["腰間寶劍七星文，臂上雕弓百戰勳。", "見說雲中擒醜虜，始知天上有將軍。"]'),
('ba577ded-1118-454d-8232-d28bcf91a281','佛牙讚','宋仁宗','宋','宋诗','song-poetry','','[]','三皇掩質皆歸土，五帝潛形已化塵。',64,'全唐诗/poet.song.20000.json','["三皇掩質皆歸土，五帝潛形已化塵。", "夫子域中誇是聖，老君世上亦言真。", "埋軀祗見空遺冢，何處將身示後人。", "唯有吾師金骨在，曾經百鍊色長新。"]'),
('1b3b53ba-2812-45ec-8a4e-7754ed611ff2','蓮花經讚','宋仁宗','宋','宋诗','song-poetry','','[]','六萬餘言七軸裝，無邊妙義內含藏。',64,'全唐诗/poet.song.20000.json','["六萬餘言七軸裝，無邊妙義內含藏。", "溢心甘露時時潤，灌頂醍醐滴滴凉。", "白玉齒邊流舍利，紅蓮舌上放毫光。", "假饒造罪如山嶽，只消妙法兩三行。"]'),
('2daaf1bb-8f6c-4773-90ee-4f6e90e68462','賜劉煇及第','宋仁宗','宋','宋诗','song-poetry','','[]','治世求才重，公朝校藝精。',48,'全唐诗/poet.song.20000.json','["治世求才重，公朝校藝精。", "臨軒升造士，入彀得羣英。", "并躡雲梯峻，聊登桂籍榮。", "庇民思善政，慈惠體予情。"]'),
('83f4267e-9a0c-4d7f-a4e9-a74bdc87ddf1','賞花釣魚','宋仁宗','宋','宋诗','song-poetry','','[]','晴旭輝輝苑籞開，氤氳花氣好風來。',64,'全唐诗/poet.song.20000.json','["晴旭輝輝苑籞開，氤氳花氣好風來。", "游絲罥絮縈行仗，墮蕊飄香入酒杯。", "魚躍文波時撥剌，鶑留深樹久徘徊。", "青春朝野方無事，故許遊觀近侍陪。"]'),
('6dd747fe-310f-4818-a9dc-3b01a84d8087','嘉祐六年八月十五日賜林悅  其一','宋仁宗','宋','宋诗','song-poetry','','[]','長林派出下邳先，移入閩邦遠更延。',64,'全唐诗/poet.song.20000.json','["長林派出下邳先，移入閩邦遠更延。", "忠孝有聲天地老，古今無數子孫賢。", "故家喬木盤根大，新出猗蘭奕葉鮮。", "上下相承同紀載，三千年後萬千年。"]'),
('cd429f54-7abc-4356-99e5-72942013e20f','嘉祐六年八月十五日賜林悅  其二','宋仁宗','宋','宋诗','song-poetry','','[]','郡莆卿家名望族，三仁而下爵王公。',64,'全唐诗/poet.song.20000.json','["郡莆卿家名望族，三仁而下爵王公。", "存孤實抗回天義，報國常攄貫日忠。", "德潤豐姿人有異，光增譜牒世同無。", "古今紀載難窮盡，一代强如一代隆。"]'),
('2ee94490-8833-4228-978a-b2467020ed94','句  其一','宋仁宗','宋','宋诗','song-poetry','','[]','寒儒逢景運，報德合如何。',12,'全唐诗/poet.song.20000.json','["寒儒逢景運，報德合如何。"]'),
('237ce650-1a4b-41a6-96d0-cc321aa4ac28','句  其二','宋仁宗','宋','宋诗','song-poetry','','[]','恩袍草色動，仙籍桂香浮。',12,'全唐诗/poet.song.20000.json','["恩袍草色動，仙籍桂香浮。"]'),
('c232421c-c766-4974-8942-3118ba92a1a8','招通判沈興宗遊五泄','丁寶臣','宋','宋诗','song-poetry','','[]','路緣蘿蔦蔭杉松，翠壁丹崖不計重。',64,'全唐诗/poet.song.20000.json','["路緣蘿蔦蔭杉松，翠壁丹崖不計重。", "天作錦屏環十里，僧開朱屋面千峯。", "花閒越鳥鉤輈語，谿外秦人髣髴逢。", "早晚車騶到山下，籃輿多日待追從。"]'),
('469856e5-984f-4fda-a605-b27a4d3b174c','遊五泄書呈完夫節推','丁寶臣','宋','宋诗','song-poetry','','[]','莫厭幽尋路險辛，細思容易是山神。',64,'全唐诗/poet.song.20000.json','["莫厭幽尋路險辛，細思容易是山神。", "能收地巧藏深處，不惜天奇示俗人。", "古有少陵吟未到，今無摩詰畫難真。", "海邊見說天童好，祗待君詩判等倫。"]'),
('eb47d774-9b1c-4d43-91a1-ac770a57c3b7','留題崇法院','丁寶臣','宋','宋诗','song-poetry','','[]','瀕湖三寺倚崢嶸，梵剎相高對縣城。',64,'全唐诗/poet.song.20000.json','["瀕湖三寺倚崢嶸，梵剎相高對縣城。", "樓殿盡知隨處盛，山林獨愛此中清。", "翦開木末簷牙出，鑿破巖腰磴道成。", "悟得祖師心印法，禪僧遥指塔燈明。"]'),
('cce26ded-15f2-49fa-8a2c-83d7a6ac113d','次韻十五日菊  其一','丁寶臣','宋','宋诗','song-poetry','','[]','秋香多日閟英華，霜脫離離抱砌斜。',64,'全唐诗/poet.song.20000.json','["秋香多日閟英華，霜脫離離抱砌斜。", "趁節不隨時俗眼，近冬真是歲寒花。", "摛辭舊入騷人筆，載酒誰尋醉令家。", "曾讀南華齊物論，均無遲速可驚嗟。"]'),
('77725536-1e81-40bd-800a-afa8171b7c2e','次韻十五日菊  其二','丁寶臣','宋','宋诗','song-poetry','','[]','寒芳開晚獨堪嘉，開日仍逢小雨斜。',64,'全唐诗/poet.song.20000.json','["寒芳開晚獨堪嘉，開日仍逢小雨斜。", "秋盡亭臺凋木葉，月圓時節伴蓂花。", "幽香不入登高會，清賞終存好事家。", "黄蕊綠莖如舊歲，人心徒有後時嗟。"]'),
('95abfdb2-e4f9-4e78-a316-019fdb7b5c79','題慧山翠麓亭','丁寶臣','宋','宋诗','song-poetry','','[]','諦看軒軒面翠微，暫來登此已忘機。',64,'全唐诗/poet.song.20000.json','["諦看軒軒面翠微，暫來登此已忘機。", "地連佛寺樓臺古，泉落山田稻蟹肥。", "曉徑忽穿清氣入，夜船多載白雲歸。", "世人誰識紅塵外，終老功名未拂衣。"]'),
('52824c06-585d-4698-8294-e94f482ef580','和慧山泉','丁寶臣','宋','宋诗','song-poetry','','[]','誰識澄淵萬古清，潢汙擾擾謾縱橫。',64,'全唐诗/poet.song.20000.json','["誰識澄淵萬古清，潢汙擾擾謾縱橫。", "出從山底應無極，流落人間自有聲。", "江漢想能同浩渺，塵沙雖混更分明。", "從來旱歲爲膏澤，安和茶經浪得名。"]'),
('8b6ff4ee-af3a-4653-a7a4-debe0838070f','和永叔新晴獨過東山','丁寶臣','宋','宋诗','song-poetry','','[]','芳辰百五前，選勝到林泉。',72,'全唐诗/poet.song.20000.json','["芳辰百五前，選勝到林泉。", "萬樹綠初染，羣花紅未然。", "陰巖猶貯雪，暖谷自生煙。", "婦汲溪頭水，人耕草際田。", "日中林影直，風靜鳥聲圓。", "健令多情甚，尋春最占先。"]'),
('4d7e2c96-e749-4bb2-a884-712f6858dccc','謫官渡淮舟中遇風欲覆舟而作','唐介','宋','宋诗','song-poetry','','[]','聖宋非狂楚，清淮異汩羅。',48,'全唐诗/poet.song.20000.json','["聖宋非狂楚，清淮異汩羅。", "平生仗忠信，今日任風波。", "舟楫顛危甚，黿鼉出沒多。", "斜陽幸無事，沽酒聽漁歌。"]'),
('51e8da10-eb69-41a6-8347-969f4d32322b','九日贈僧','唐介','宋','宋诗','song-poetry','','[]','今日是重陽，勞師訪野堂。',24,'全唐诗/poet.song.20000.json','["今日是重陽，勞師訪野堂。", "相逢又無語，籬下菊花黄。"]'),
('e974011e-1d4a-4ced-98c8-4c70a7937ff0','碧落洞','唐介','宋','宋诗','song-poetry','','[]','余生本孤拙，所志在雲石。',240,'全唐诗/poet.song.20000.json','["余生本孤拙，所志在雲石。", "薄宦偶纏鎖，未遂林泉適。", "邇來備臺選，幸一當言責。", "狂愚抵罪辜，遽從遐徼謫。", "區區數千里，車馬倦行役。", "湞陽頗善地，解轡喜安席。", "官散無所事，度日多閑隙。", "太守蘇宣甫，邀我訪奇跡。", "西山有石室，疑是靈仙宅。", "翛然煙徑入，訝若天門闢。", "中瀉一溪清，傍映千峯碧。", "萬穴滴瑶乳，兩岸張翠幕。", "爽氣來先秋，昏嵐生未夕。", "不知造化意，何爲置窮僻。", "周生說到難，茲文不虛摭。", "怪容誠莫狀，勝跡今始獲。", "暫已瑩耳目，久覺生虛白。", "拂拭纓上塵，回頭謝朝客。", "雖非吾所樂，聊以慰奇隻。", "聖恩未放還，屢遊君莫惜。"]'),
('9fd2e032-527a-4458-9ecc-f268c630cf0d','明王寺','唐介','宋','宋诗','song-poetry','','[]','日高霞散彩，松老鶴巢枝。',24,'全唐诗/poet.song.20000.json','["日高霞散彩，松老鶴巢枝。", "壞壁詩猶在，紗籠何用之。"]'),
('eab56a83-7df8-41f9-a6cf-db02e88105c4','句  其一','唐介','宋','宋诗','song-poetry','','[]','越林多蔽天，黄柑雜丹橘。',12,'全唐诗/poet.song.20000.json','["越林多蔽天，黄柑雜丹橘。"]'),
('8ada37a7-6836-4953-89e0-d9aaf6d2d83b','句  其二','唐介','宋','宋诗','song-poetry','','[]','著要及春前後到，趁賦梅花庾嶺東。',16,'全唐诗/poet.song.20000.json','["著要及春前後到，趁賦梅花庾嶺東。"]'),
('7d7102f6-0dc6-433b-ae12-9acdc9c50801','威惠廟','呂璹','宋','宋诗','song-poetry','','[]','當年平賊立殊勳，時不旌賢事忍聞。',32,'全唐诗/poet.song.20000.json','["當年平賊立殊勳，時不旌賢事忍聞。", "唐史無人修列傳，漳江有廟祀將軍。"]'),
('7963ab76-c939-4e2e-8a30-6e0379b29ecb','書高辛氏廟','祖無擇','宋','宋诗','song-poetry','','[]','平昔敘星辰，元功祀事分。',96,'全唐诗/poet.song.20000.json','["平昔敘星辰，元功祀事分。", "因人列官紀，行道亞皇墳。", "高躅追顓頊，徽聲壓放勳。", "淳風今不競，帝典世無聞。", "陵古森喬木，祠新際遠氛。", "樵蘇當季運，血食屬明君。", "舊壤資庥廕，遺黎薦苾芬。", "春秋奏簫鼓，疑是六英文。"]'),
('b7b2db88-d6f5-4225-bb96-7ab820153ce6','依韻和登州推官張同年之梁山','祖無擇','宋','宋诗','song-poetry','','[]','峻極乾蒼蒼，班移自混茫。',288,'全唐诗/poet.song.20000.json','["峻極乾蒼蒼，班移自混茫。", "勢臨坤軸斷，根入海濤殭。", "屹立踰千仞，孤標冠四荒。", "興雲山近泰，出日谷連暘。", "絕墳于斯勝，煩襟到此涼。", "山經終寂寂，祀典謾煌煌。", "岩黑驪龍睡，煙清來鳳翔。", "藏書陋羣玉，中瑟小空桑。", "禹載無遺跡，秦碑有舊章。", "乘輿曾直上，鞭石宛居傍。", "在昔初遷鼎，當時異省方。", "縱心師誕妄，恃力逞强梁。", "儒學微言絕，神仙怪說彰。", "錫符尊德水，留識著吾漿。", "豈念思王度，惟期至帝鄉。", "齋男何杳杳，秋祝自琅琅。", "詎得三山藥，翻同一國狂。", "八神寧爾福，二世果斯亡。", "始禍聞陳涉，遺書見子長。", "龍興成大定，虎噬免交攘。", "往事真塗炭，寒心劇刺芒。", "自從茲滅國，誰復此祠陽。", "冤毒疑淪髓，凋殘競沐瘡。", "鑒宜觀夏后，道合慕陶唐。"]'),
('a7e5f5ef-7c86-431c-99c9-70e705a64f34','暮秋江上逢端州朱使君詩以申餞','祖無擇','宋','宋诗','song-poetry','','[]','奕葉清棻遠，夫君素履恢。',96,'全唐诗/poet.song.20000.json','["奕葉清棻遠，夫君素履恢。", "人皆推世德，我亦愛卿材。", "新命一麾守，長途萬里來。", "畫船江雨暗，紅斾海風開。", "服嶺先聲浹，編甿美化該。", "此行真邂逅，幾日共沿洄。", "去矣瞻仙棹，依然對酒杯。", "前程如見憶，爲寄早春梅。"]'),
('f2aef06f-3d41-48ed-a94a-fa0f53773fb9','落星寺','祖無擇','宋','宋诗','song-poetry','','[]','金碧共玲瓏，樓臺浩渺中。',96,'全唐诗/poet.song.20000.json','["金碧共玲瓏，樓臺浩渺中。", "雨花僧講盛，星石寺基雄。", "巖岫廬峯對，波瀾蠡澤通。", "微紅看海日，遠綠認江楓。", "鷗鳥機心息，潮音梵唱同。", "人間羣玉府，物外廣寒宮。", "雲衲烝多壞，塵襟到自空。", "扁舟五湖客，長此伴支公。"]'),
('36285183-c9af-4826-be61-46f1903c0d8b','瀑布','祖無擇','宋','宋诗','song-poetry','','[]','絕巘千尋勢，飛泉萬疊痕。',72,'全唐诗/poet.song.20000.json','["絕巘千尋勢，飛泉萬疊痕。", "寒光涵玉岫，靈派析璇源。", "峭壁河流立，蒼崖井浪翻。", "猿悲經樹急，龍駭落潭渾。", "氣爽諸峰秀，聲和衆籟喧。", "功成身退日，期此灌中園。"]'),
('5938b42a-6eb6-44c4-baff-c8e49a3c72fe','游真陽石室','祖無擇','宋','宋诗','song-poetry','','[]','昔讀到難篇，乃聞真陽室。',192,'全唐诗/poet.song.20000.json','["昔讀到難篇，乃聞真陽室。", "亦嘗惟斯人，稱道或浮實。", "邈在數千里，莫覿烟霞質。", "青山有獨往，吾志久已必。", "如何驂俗駕，尚此紆朝紱。", "謬分南顧憂，惟刑在欽卹。", "孤宦雖云遠，勝踐其敢失。", "行行訪雲巖，草樹披蒙密。", "呀然一穴開，勢欲吞朝日。", "嵐光屏障展，乳溜龍蛇屈。", "溪流自清泚，松韻何蕭瑟。", "酌酒飲游客，謂言此可述。", "周生誠不誣，所紀窮纖悉。", "惜哉非吾土，無由寄蓬蓽。", "平生丘壑心，與道共湮鬰。", "難進而易退，終當守儒術。"]'),
('0aafa398-1403-4949-a255-f84227752cfa','景臣同年郟兄作亭於公居之池上予登而名之曰夢草且賦詩以志焉','祖無擇','宋','宋诗','song-poetry','','[]','新構俯漣漪，名標謝客詩。',72,'全唐诗/poet.song.20000.json','["新構俯漣漪，名標謝客詩。", "窗明溪雨過，檻靜竹風吹。", "賀厦應容燕，巢蓮亦許龜。", "何人倦漂泊，此地好追隨。", "兀兀乘籃輿，厭厭倒接䍦。", "秋芳正堪賞，樽酒莫過時。"]'),
('94a831d5-ce2e-48a3-9bf6-347bbbf34618','題仰山二十韻','祖無擇','宋','宋诗','song-poetry','','[]','維南斗牛下，萬仞聳崔嵬。',240,'全唐诗/poet.song.20000.json','["維南斗牛下，萬仞聳崔嵬。", "日上光先占，江盤勢却回。", "一方蒙雨露，幾處對樓臺。", "不逐秦鞭去，曾經禹載來。", "雲生峯慘澹，冰泮谷喧豗。", "險外煙嵐變，深中洞府開。", "巖花春灼爍，溪鳥暖毰毸。", "飛瀑含清籟，乖龍走疾雷。", "平川蕭廟閟，半腹鄧壇摧。", "精藴瑶瑰寶，靈鐘杞梓材。", "僧軒宜薜荔，樵徑怯莓苔。", "旁睨龍州橘，前瞻庾嶺梅。", "仙經饒地肺，賦筆讓天台。", "神物多靈貺，農田少旱災。", "隠君須獨行，吟咏亦難才。", "何客能依止，伊予語敢哉。", "一麾成繫滯，四友阻遊陪。", "未脫紅塵累，徒嗟白髮催。", "夢頻生枕席，賞每倒尊罍。", "預恐瓜時代，圖歸作醉媒。"]'),
('57f468d3-91c0-4b3d-b00b-ce9ca2755a4f','途次金陵逢同年沈五判官','祖無擇','宋','宋诗','song-poetry','','[]','數載天涯別，年來不定居。',72,'全唐诗/poet.song.20000.json','["數載天涯別，年來不定居。", "扁舟忽相值，孤抱信何如。", "公幹猶多病，孝先仍嫩書。", "人生從坎壈，客意且躊躇。", "淡薄市橋酒，鮮肥江岸魚。", "可來同飲食，勿笑此蕭疎。"]'),
('a949d64e-967a-4e20-8d4a-4874216bae69','和御製賞花釣魚','祖無擇','宋','宋诗','song-poetry','','[]','禁籞春深御幄開，鳴鞘曉出五雲來。',64,'全唐诗/poet.song.20000.json','["禁籞春深御幄開，鳴鞘曉出五雲來。", "花含瑞色三危露，酒湛晴光萬壽杯。", "香餌得魚波滉漾，仙音儀鳳日徘徊。", "微臣叨竊逢辰幸，持橐甘泉此從陪。"]'),
('85992917-d810-49f5-8c5d-2e8022533560','九日陪舊參政蔡侍郎宴潁州西湖','祖無擇','宋','宋诗','song-poetry','','["\u897f\u6e56"]','秋晚西湖勝槩多，臺軒來此駐鳴珂。',64,'全唐诗/poet.song.20000.json','["秋晚西湖勝槩多，臺軒來此駐鳴珂。", "沙鷗散去驚絲竹，煙柳低垂間綺羅。", "亂擲金錢和露菊，狂摇鈿扇倚風荷。", "下僚幸接曹尊末，率爾翻成擊箸歌。"]'),
('c38445f8-c94a-45e0-aac4-e98072920733','讀王元之後集題于卷末','祖無擇','宋','宋诗','song-poetry','','[]','提筆幾回書誥命，剖符長是守方州。',64,'全唐诗/poet.song.20000.json','["提筆幾回書誥命，剖符長是守方州。", "未能抗表分司去，終老爲郎謫宦休。", "歌舞嬾呼寒食節，醉吟孤坐月波樓。", "文章獨步成何事，空有離騷寄隠憂。"]'),
('2e422218-e0bb-461f-9129-9a27e6c65c18','寄獻闕下一二知己','祖無擇','宋','宋诗','song-poetry','','[]','公道當朝絕比倫，因憑暖筆變孤根。',64,'全唐诗/poet.song.20000.json','["公道當朝絕比倫，因憑暖筆變孤根。", "纔衝霰雪游梁苑，便逐風雷化禹門。", "南郡已甘拋絳帳，東州何幸佐朱旛。", "心懷象魏身江海，兩地悠悠欲斷魂。"]'),
('20b8fd7b-9165-498c-9b16-8bb8569b8626','歷城郡治凝波亭','祖無擇','宋','宋诗','song-poetry','','[]','耽耽層構俯清漣，山色波光曉共鮮。',64,'全唐诗/poet.song.20000.json','["耽耽層構俯清漣，山色波光曉共鮮。", "形勝增雄齊十二，風流素盛客三千。", "鋪舒柳影眠鷗渚，欺厭蓮香載妓船。", "公退每來須度日，塵纓未濯媿潺湲。"]'),
('1f3620a0-02ed-4474-936b-3b54543cd2d0','留題泰山孫復先生新居','祖無擇','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','築室新成日觀前，亂雲重疊稱高眠。',64,'全唐诗/poet.song.20000.json','["築室新成日觀前，亂雲重疊稱高眠。", "人逢捫蝨驚旁若，衆望乘駒詠賁然。", "名理靜談誰捉麈，古書閒校自磨鉛。", "行聞天子東巡狩，羽葆親臨此禮賢。"]'),
('5ac51ccf-983f-40ff-aabc-8ae6dec76fd7','試筆','祖無擇','宋','宋诗','song-poetry','','[]','濟南通守欲幾年，最課無成媿古賢。',64,'全唐诗/poet.song.20000.json','["濟南通守欲幾年，最課無成媿古賢。", "却爲簿書拋筆硯，每思樵釣負林泉。", "浮名自信雖徒爾，薄俸相拘且勉旃。", "已共妻孥約生計，會須搔首賦歸田。"]'),
('da5bfeb5-86f7-4bc1-a422-f8889edfd541','監丞蕭君見貽嘉句仍惠芳醪强率鄙詞輒繼高韻聊資逌爾深媿斐然','祖無擇','宋','宋诗','song-poetry','','[]','遲日和風婉娩春，感時情思浩無津。',64,'全唐诗/poet.song.20000.json','["遲日和風婉娩春，感時情思浩無津。", "煩君遠寄中山酒，顧我方爲洛社人。", "濡筆便思題素扇，當尊難借吐芳茵。", "已欽才妙兼懷惠，相過文場願捧輪。"]'),
('f359b658-b125-4c12-9e33-c0c2c3ff8b02','寄泰山孫復','祖無擇','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','先生心與白雲閑，五十秋風髩不斑。',64,'全唐诗/poet.song.20000.json','["先生心與白雲閑，五十秋風髩不斑。", "自有清名滿天下，更無塵跡到人間。", "朱鉛樂外非攸好，貪懦聞風合厚顔。", "不待高吟見招隠，見收餘俸買青山。"]'),
('fac35e89-41c0-44ff-adaf-e5705d9754b7','蕭五監丞新作堂成名曰知雄且賦彫章題之屋壁勉率蕪惡以繼高韻','祖無擇','宋','宋诗','song-poetry','','[]','況堂佳號塵游外，題壁新吟藻思春。',64,'全唐诗/poet.song.20000.json','["況堂佳號塵游外，題壁新吟藻思春。", "朴素自持師老氏，清醒常戒鑒靈均。", "窮通一致由知命，恬智相須合入神。", "因覽君詩我顔厚，不能假日樂天真。"]'),
('609ed9d0-a172-4552-8c32-d4e129521a29','贈牛仲容','祖無擇','宋','宋诗','song-poetry','','[]','吾君旰食念邊陲，天下英雄待聘時。',64,'全唐诗/poet.song.20000.json','["吾君旰食念邊陲，天下英雄待聘時。", "仁義未行真處士，功名不立豈男兒。", "卧龍誰識南陽隠，失馬何勞北叟悲。", "莫向林泉賦長往，秋風吹子鬢毛衰。"]'),
('61053889-39b2-42d8-9b7c-44b0f7cc239d','張寺丞鳴玉亭書事','祖無擇','宋','宋诗','song-poetry','','[]','爲憐瀟洒近城闉，來往何曾問主人。',64,'全唐诗/poet.song.20000.json','["爲憐瀟洒近城闉，來往何曾問主人。", "列岫曉昏雲郁郁，流泉秋淨石粼粼。", "陸機詩就伏招隠，班固文成正答賓。", "愁見西峯日將暮，却驅羸馬入埃塵。"]'),
('cc2edd1e-6cd6-47a1-9f89-364037a994c6','庚辰清明州衙不送新火','祖無擇','宋','宋诗','song-poetry','','[]','禁烟故事存遺俗，改火平時有舊章。',64,'全唐诗/poet.song.20000.json','["禁烟故事存遺俗，改火平時有舊章。", "縱道齊民皆按堵，堪驚烜氏昧修方。", "晨炊已絕供賓饌，春酒何來獨酌觴。", "不似前年爲客日，富鄰猶許借餘光。"]'),
('35c35f2a-1cb9-4d05-b153-bd9d8eb0f416','赴任南康將經九江游二林先寄交代關屯田','祖無擇','宋','宋诗','song-poetry','','[]','平生山水有心期，今得軍麾慰所思。',64,'全唐诗/poet.song.20000.json','["平生山水有心期，今得軍麾慰所思。", "我欲因行訪蓮社，君應未訝過瓜時。", "若逢勝槩終朝住，兼領閑僧到處隨。", "莫遣迎新吏人至，雲間泉畔不相宜。"]'),
('c57732b0-98d4-4790-921c-9d51c9218473','送交代關屯田赴闕','祖無擇','宋','宋诗','song-poetry','','[]','謝公雅尚廉侯政，兼得如君不可加。',64,'全唐诗/poet.song.20000.json','["謝公雅尚廉侯政，兼得如君不可加。", "自有袴襦歌道路，長驅旌斾訪煙霞。", "林僧解誦松窗句，廳吏能封竹檻花。", "今日北轅堪健羨，清風留與後人誇。"]'),
('38e2243a-7f2c-421c-9e63-d59c316e435a','琵琶亭','祖無擇','宋','宋诗','song-poetry','','[]','晚泊湓江半客舟，琵琶亭下動閑愁。',64,'全唐诗/poet.song.20000.json','["晚泊湓江半客舟，琵琶亭下動閑愁。", "霓裳綠腰杳何許，楓葉荻花空自秋。", "賈傅有才悲鵩鳥，楚騷終古怨靈修。", "莫言司馬青衫濕，今日和人亦涕流。"]'),
('e32c8c6d-32fd-4c73-bfc8-848ccd2ccb24','南康春日','祖無擇','宋','宋诗','song-poetry','','[]','慙媿東風破臘來，一尊清聖爲君開。',64,'全唐诗/poet.song.20000.json','["慙媿東風破臘來，一尊清聖爲君開。", "無方可使朱顔駐，有客相逢白眼迴。", "老大漸能知世態，疎慵那復計身媒。", "遥憐伊洛冰應泮，芳草還荒舊釣臺。"]'),
('a29a5500-973d-4bed-b725-5704fa20669c','簡寂觀','祖無擇','宋','宋诗','song-poetry','','[]','順風曾出帝王尊，身後高名與觀存。',64,'全唐诗/poet.song.20000.json','["順風曾出帝王尊，身後高名與觀存。", "石室深居廣成子，布囊薄葬楊王孫。", "流塵冪冪凝丹竈，清吹徐徐觸絳旛。", "牢落空山門晝掩，羽人亦說絕囂煩。"]'),
('4a52a3c0-c2ea-498a-bfdf-fabd803411d3','右軍墨池','祖無擇','宋','宋诗','song-poetry','','[]','羌廬峯下歸宗寺，曾是當年內史居。',64,'全唐诗/poet.song.20000.json','["羌廬峯下歸宗寺，曾是當年內史居。", "繭紙世傳遺蹟後，墨池人記作書初。", "秋毫幾老崇山兔，舊法空觀得水魚。", "珍重僧家能好事，朱欄碧甃壯庭除。"]'),
('7818da12-2b0f-4196-9d7b-352704d08437','清明日與二三賓客賞花陳判官爲推勘他州事不預是會以詩抵予因次其韻酬之','祖無擇','宋','宋诗','song-poetry','','[]','寒食春光正好誇，小筵應免負芳華。',64,'全唐诗/poet.song.20000.json','["寒食春光正好誇，小筵應免負芳華。", "清談且喜交揮麈，賭酒何須要畫蛇。", "潑火雨餘微綠潤，落花風急亂紅斜。", "幕中有客應惆悵，今日全輸太守家。"]'),
('301726a7-0f07-40f1-afcd-62f21414db8c','秋日天平驛書事','祖無擇','宋','宋诗','song-poetry','','[]','孤館無人慰寂寥，感時情抱楚旌摇。',64,'全唐诗/poet.song.20000.json','["孤館無人慰寂寥，感時情抱楚旌摇。", "縱橫著物秋聲起，早晚連空殺氣消。", "衰鬢已同潘騎省，壯心猶羨霍嫖姚。", "誓江義勇吾家事，不得提戈靜虜妖。"]'),
('786632fd-b455-4260-a48e-7ef337ffb46a','濟上夜泊寄杜秘教','祖無擇','宋','宋诗','song-poetry','','[]','十幅蒲帆一竹篙，隨流逐浪我心勞。',64,'全唐诗/poet.song.20000.json','["十幅蒲帆一竹篙，隨流逐浪我心勞。", "幾程煙水秋光遠，半夜星河天氣高。", "正想黄陂何淼淼，可憐禹瀆更滔滔。", "猶欣明發諧相見，願奉清言散鬰陶。"]'),
('bf85732d-c1f2-4212-98e1-49910e5de271','經劍池','祖無擇','宋','宋诗','song-poetry','','[]','巧冶何年百煉金，刜鐘芒刃此湮沉。',64,'全唐诗/poet.song.20000.json','["巧冶何年百煉金，刜鐘芒刃此湮沉。", "氣衝牛斗雖難掩，鑒遇張雷始見尋。", "恍惚莫窮神物遠，波瀾空在曲池深。", "鉛刀也强思磨試，悵望西山與華陰。"]'),
('824518a3-3bf3-4d3c-a345-c1fc8483a691','送春長句呈李泰伯','祖無擇','宋','宋诗','song-poetry','','[]','盡日臨風把酒巵，宜春臺上送春歸。',64,'全唐诗/poet.song.20000.json','["盡日臨風把酒巵，宜春臺上送春歸。", "已看綠樹陰陰靜，猶有殘花帖帖飛。", "歲月任從隨手過，功名未必與心違。", "我緣客宦無常處，後會如今亦恐稀。"]'),
('fb9bd39f-1356-4c9f-becd-e110940b96ef','送潘華陽','祖無擇','宋','宋诗','song-poetry','','[]','河陽苗裔有英翹，年少聲名動帝朝。',64,'全唐诗/poet.song.20000.json','["河陽苗裔有英翹，年少聲名動帝朝。", "月桂我欣同賜第，澗松人借此沈僚。", "金牛開道秦川險，笮馬來賓漢使遥。", "想以刀州遇知己，便從平地上烟霄。"]'),
('a44e1ddb-0236-46ea-ba32-bf88205496ee','微子廟','祖無擇','宋','宋诗','song-poetry','','[]','億兆夷人困獨夫，惟君先見得良圖。',64,'全唐诗/poet.song.20000.json','["億兆夷人困獨夫，惟君先見得良圖。", "爲仁始欲扶商祚，去國終能啟宋都。", "鈇鑕豈甘因諫死，髠鉗仍免作官奴。", "千年廟食應無愧，知退知亡即師徒。"]'),
('e6fae52f-7586-4e2b-b693-ad3114745741','寺有四絕一曰靈巖予以赴官獲此稅鞅因賦拙句用誌其行','祖無擇','宋','宋诗','song-poetry','','[]','常想靈蹤得到難，因回征轡此盤桓。',64,'全唐诗/poet.song.20000.json','["常想靈蹤得到難，因回征轡此盤桓。", "松風逗磬僧齋冷，石水環堂客夢寒。", "聖作自同堯典布，古碑猶是魏朝刊。", "最憐山色當樓好，欲去重來一凭闌。"]'),
('8846129c-b602-40a4-99e9-7ab38f9a2d27','贈商水連尉同年','祖無擇','宋','宋诗','song-poetry','','[]','場屋相知最有情，去年同試使同榮。',64,'全唐诗/poet.song.20000.json','["場屋相知最有情，去年同試使同榮。", "神仙史籍輸梅福，典冊文章滯馬卿。", "泣玉淚收休積恨，擲金詞在藹新聲。", "公卿好致歸臺閣，莫遣徒勞浩嘆生。"]'),
('a3fdf6ea-adef-41bf-92ae-37a2c0c777d1','次韻和酬張兟秀才見寄','祖無擇','宋','宋诗','song-poetry','','[]','傾蓋相知分不同，遠憑郵置枉緘封。',64,'全唐诗/poet.song.20000.json','["傾蓋相知分不同，遠憑郵置枉緘封。", "題評祗益煩更品，刻畫何曾補陋容。", "綵服侍行君得意，朱轓假守我勞悰。", "論文未遂西齋約，早晚重親太華鋒。"]'),
('70ebb1ac-caa6-4715-9bea-30ff6a3c24e3','明水鎮水陸禪院','祖無擇','宋','宋诗','song-poetry','','[]','誰卜精藍若畫屏，四邊山色與泉聲。',64,'全唐诗/poet.song.20000.json','["誰卜精藍若畫屏，四邊山色與泉聲。", "野僧慣見心應樂，俗客偷來骨亦清。", "晚吹乍回香篆破，曉雲纔散蠟燈明。", "吏人莫怪徘徊久，自得閑情減宦情。"]'),
('25a8da89-9151-45b4-92ff-5f66175f8277','龍圖范給事以禫服向除修治塋域就山築室因爾書懷俾無擇繼和謹次用其韻','祖無擇','宋','宋诗','song-poetry','','[]','采采陔蘭負養親，幾思定省泣晨昏。',64,'全唐诗/poet.song.20000.json','["采采陔蘭負養親，幾思定省泣晨昏。", "三年已畢先王制，畫日將承聖主恩。", "名遂自同周柱史，諫違誰記魯臧孫。", "考槃在澗雖云樂，祗恐泥書到遠村。"]'),
('2cfcedc7-9e2a-44bb-82d9-714c8dca4bd0','田四秘丞通判鎮戎軍','祖無擇','宋','宋诗','song-poetry','','[]','身紆茜綬朝章貴，手把芝函帝命新。',64,'全唐诗/poet.song.20000.json','["身紆茜綬朝章貴，手把芝函帝命新。", "方朔上書曾自薦，祁奚外舉果知人。", "運籌暫逐征西將，持橐看歸拱北辰。", "我亦潛心禦戎策，羨君抗斾擁朱輪。"]'),
('5782a820-382a-478c-8cbf-21de639f70ce','官況','祖無擇','宋','宋诗','song-poetry','','[]','物態無端固盡諳，自爲俗吏欠清談。',64,'全唐诗/poet.song.20000.json','["物態無端固盡諳，自爲俗吏欠清談。", "豈憂官況全蕭索，祗畏人言足二三。", "玉勒已辜尋曉陌，錦鱗猶憶釣秋潭。", "公餘自遂疎慵性，從道嵇康七不堪。"]'),
('04d27ad0-a1fd-49ee-acef-81ba17851dd2','哭鄆州孔給事  其一','祖無擇','宋','宋诗','song-poetry','','[]','出入多年侍紫宸，封章頻上觸龍鱗。',64,'全唐诗/poet.song.20000.json','["出入多年侍紫宸，封章頻上觸龍鱗。", "杼投幾見疑慈母，檻折終聞記直臣。", "闕里忽驚歌曳杖，洛陽那復見埋輪。", "師門一慟盈襟淚，痛爲明時惜正人。"]'),
('37575f92-5c28-4fd2-993c-086b753371aa','哭鄆州孔給事  其二','祖無擇','宋','宋诗','song-poetry','','[]','聖孫家世嗣衣纓，夫子當朝有令名。',64,'全唐诗/poet.song.20000.json','["聖孫家世嗣衣纓，夫子當朝有令名。", "許國志堅存亮直，致君心切贊隆平。", "明庭抗疏忠言在，列郡班條惠化行。", "不享永年兼大用，終天遺恨負蒼生。"]'),
('feca300a-dd7f-4cea-8fd1-112933983809','夏州叛','祖無擇','宋','宋诗','song-poetry','','[]','羌虜奸誅軫聖憂，出師十萬擁貔貅。',64,'全唐诗/poet.song.20000.json','["羌虜奸誅軫聖憂，出師十萬擁貔貅。", "朝廷命將詩書府，廊廟論兵帷幄籌。", "舜后舞干期振旅，漢臣投筆待封侯。", "宣王六月存周雅，願繼徽聲頌國猷。"]'),
('38fd0b8f-2956-4ffa-a637-03892def91ee','寄澶州孫司理','祖無擇','宋','宋诗','song-poetry','','[]','明道二年同夏課，四人兩舉盡登科。',64,'全唐诗/poet.song.20000.json','["明道二年同夏課，四人兩舉盡登科。", "孤寒惟子辛勤甚，虛薄伊余忝竊多。", "宦路驅馳今各自，名場出處舊相過。", "感今懷舊無憀頼，不覺臨風發浩歌。"]'),
('58cc99ae-24f0-47b5-b848-e8ab746a29b0','送孟湘虞部赴闕','祖無擇','宋','宋诗','song-poetry','','[]','科名拾芥職三虞，落落雄才與衆殊。',64,'全唐诗/poet.song.20000.json','["科名拾芥職三虞，落落雄才與衆殊。", "爲政人驚今遂霸，論兵自比古孫吳。", "倚廬已見因心著，結綬還陪辨色趨。", "不似馮唐空白首，漢皇今正渴嘉謨。"]'),
('effbee5d-09de-4029-9e83-e3658f4b4262','送劉進士游邊','祖無擇','宋','宋诗','song-poetry','','[]','朔風動地雪花明，去去從知指戍城。',64,'全唐诗/poet.song.20000.json','["朔風動地雪花明，去去從知指戍城。", "場藿未縻千里驥，食魚翻嗜五侯鯖。", "征途望斷河冰合，旅館吟殘海月生。", "且共淹留話離索，一尊濁酒爲君傾。"]'),
('b05a62d0-9c69-4b29-9397-b71508f55639','同年楊兄作尉僰道兼領勾稽之作賦七言四韻詩以送之','祖無擇','宋','宋诗','song-poetry','','[]','縣城荒僻民居少，吏事全稀似隠淪。',64,'全唐诗/poet.song.20000.json','["縣城荒僻民居少，吏事全稀似隠淪。", "且喜桑郊接鄉樹，莫嗟藍綬染京塵。", "鸞姿豈合淹仇覽，仙骨應難滯子真。", "好在公餘頻寄問，我方江上學垂綸。"]'),
('f42824eb-5d8c-4481-8552-197b4e13deee','宋嘉言雅善飛白一日書八字貺予因成長句謝之','祖無擇','宋','宋诗','song-poetry','','[]','輕如浮霧重如雲，學到精微妙入神。',64,'全唐诗/poet.song.20000.json','["輕如浮霧重如雲，學到精微妙入神。", "奇迹昔年傳堊帚，高名他日壓烏巾。", "誇呈朋友防求副，留教兒孫恐失真。", "天子清閒好揮翰，似君須合侍嚴宸。"]'),
('f4e06aa9-3678-4f3f-8ed4-9145a4858cf0','送韓尉員外','祖無擇','宋','宋诗','song-poetry','','[]','幾年獻賦向公車，四十方爲冉冉趨。',64,'全唐诗/poet.song.20000.json','["幾年獻賦向公車，四十方爲冉冉趨。", "昔競寸陰終蹭蹬，今貪斗粟尚踟躕。", "潘郎毛鬢看將白，陶令田園說已蕪。", "官滿還歸省門下，預應搔首重長吁。"]'),
('edd4706a-3f1d-4dfd-adeb-21d619aa71d4','題野野園','祖無擇','宋','宋诗','song-poetry','','[]','曉日東郊扣隠扉，曈曈初日弄朱旗。',64,'全唐诗/poet.song.20000.json','["曉日東郊扣隠扉，曈曈初日弄朱旗。", "黄稍風舞先生柳，紫頰霜殷大谷梨。", "粉艷清歌穿邃閣，碧溪寒韻落幽池。", "我來載酒山翁醉，且喜秋香菊滿籬。"]'),
('295d0a7f-d625-4e77-a81e-f6ac26567063','誚王安石乞分司西京避讒而去因以述懷','祖無擇','宋','宋诗','song-poetry','','[]','割斷攀緣宰相權，憂危爭似我身全。',64,'全唐诗/poet.song.20000.json','["割斷攀緣宰相權，憂危爭似我身全。", "試觀竿上拋生體，且擬波中戲釣船。", "名利不求還獨樂，是非莫辨祗高眠。", "何當對景幽堂坐，更得閑吟度百年。"]'),
('83958bed-76dc-46de-9290-82ee3ad9f3bc','題三教圓通堂','祖無擇','宋','宋诗','song-poetry','','[]','師本佛之徒，潛心老與儒。',48,'全唐诗/poet.song.20000.json','["師本佛之徒，潛心老與儒。", "一堂何所像，三教此焉俱。", "香火長相續，丹青久不渝。", "高賢旌好事，二記聳龜趺。"]'),
('04c51f97-4a3e-4690-9a26-7df8fce8ef33','馬上讀韓吏部集','祖無擇','宋','宋诗','song-poetry','','[]','驅羸勌遠征，尺箠亦慵擎。',48,'全唐诗/poet.song.20000.json','["驅羸勌遠征，尺箠亦慵擎。", "却得開編看，仍教縱轡行。", "儒推文暢行，詩許孟郊鳴。", "盡日躭遺味，渾如挹大羹。"]'),
('3e364233-7dbb-4028-972c-84c423203b07','至齊五月兩院獄空喜而成咏','祖無擇','宋','宋诗','song-poetry','','[]','厭預鈴齋議，欣聞獄犴空。',48,'全唐诗/poet.song.20000.json','["厭預鈴齋議，欣聞獄犴空。", "三章用舊制，五月紹遺風。", "止繫垂衣治，非干別駕功。", "惟期四海內，刑厝與周同。"]'),
('9258fe71-8ca0-4db0-a530-afa6e3d24103','眡役于清偶書四韻寄示幕中賓客','祖無擇','宋','宋诗','song-poetry','','[]','經旬一水湄，風土化緇衣。',48,'全唐诗/poet.song.20000.json','["經旬一水湄，風土化緇衣。", "豈敢嗟于役，何當賦式微。", "雲山晴特秀，花木暖相輝。", "期子同携手，春游事勿違。"]'),
('9b83d29f-c083-46e3-84ca-52d8e9d6219a','齋中即書南事','祖無擇','宋','宋诗','song-poetry','','[]','軍壘無多事，朝晡且放衙。',48,'全唐诗/poet.song.20000.json','["軍壘無多事，朝晡且放衙。", "吏人如野鹿，公署似僧家。", "京信因求藥，賓懽爲鬭茶。", "忘懷塵俗外，枕籍祗南華。"]'),
('632acb26-0559-42e5-ab9b-9703f26b4621','羌先生廟','祖無擇','宋','宋诗','song-poetry','','[]','先生高世跡，舊隠白雲深。',48,'全唐诗/poet.song.20000.json','["先生高世跡，舊隠白雲深。", "結宇知何代，遺祠直至今。", "地分壇杏影，門接社蓮陰。", "我亦希風者，終明託玉岑。"]'),
('a7bef299-406c-4f16-ba67-a42fcac13b25','贈廬山崇勝珂長老','祖無擇','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','珂也僧中秀，曹溪得祖衣。',48,'全唐诗/poet.song.20000.json','["珂也僧中秀，曹溪得祖衣。", "雲泉聊適性，缾錫遂忘歸。", "九月秋風老，千山暮雨霏。", "我來陪靜話，相對兩無機。"]'),
('8f7a898b-7f4b-414e-9e79-c310fadb89b1','送承澤上人歸寧富沙','祖無擇','宋','宋诗','song-poetry','','[]','五老峯前見，過從一歲餘。',48,'全唐诗/poet.song.20000.json','["五老峯前見，過從一歲餘。", "還將隨客棹，歸去侍親輿。", "乞食江雲際，牽吟臘雪初。", "祗應清夜夢，時復到荒廬。"]'),
('8796a943-fd47-4f7b-b519-bce83fe2fbdd','酬江西運使齊工部見寄','祖無擇','宋','宋诗','song-poetry','','[]','龍坂彌年別，長茲仰道風。',48,'全唐诗/poet.song.20000.json','["龍坂彌年別，長茲仰道風。", "夢曾瞻使節，喜忽得詩筒。", "詞藻春林秀，恩私地鎮崇。", "因將示知者，傳誦滿江東。"]'),
('b3f204f4-1040-456b-9366-28e98ac9093f','游韶石','祖無擇','宋','宋诗','song-poetry','','[]','純音何寂寞，秀色自崔嵬。',48,'全唐诗/poet.song.20000.json','["純音何寂寞，秀色自崔嵬。", "巖草遺簫在，溪禽學鳳來。", "余希探禹穴，人似畏軒臺。", "登眺秋風裏，煩襟盡日開。"]'),
('7b808ff3-f5e3-433b-b59b-3a6cf63d760a','吏隠宜春郡詩十首  其一','祖無擇','宋','宋诗','song-poetry','','[]','吏隠宜春郡，年豐獄訟稀。',48,'全唐诗/poet.song.20000.json','["吏隠宜春郡，年豐獄訟稀。", "餘糧委南畝，茂草滿圜扉。", "天意憐艱食，民心恥畫衣。", "萬家行樂處，車馬有光輝。"]'),
('e883c882-fc1f-4785-8a0b-d23ca7886e9f','吏隠宜春郡詩十首  其二','祖無擇','宋','宋诗','song-poetry','','[]','吏隠宜春郡，溪山若畫圖。',48,'全唐诗/poet.song.20000.json','["吏隠宜春郡，溪山若畫圖。", "纖鱗時自躍，幽鳥靜相呼。", "曉浪噴寒雨，晴嵐鎖綠蕪。", "漁樵本吾事，搔首重踟躕。"]'),
('d869c7dc-b504-4069-99a2-ccbbb38e4172','吏隠宜春郡詩十首  其三','祖無擇','宋','宋诗','song-poetry','','[]','吏隠宜春郡，追惟二相賢。',48,'全唐诗/poet.song.20000.json','["吏隠宜春郡，追惟二相賢。", "節明天寶日，業茂會昌年。", "友善曾何累，朋誣亦自煎。", "不才非不幸，異代若差肩。"]'),
('efce0585-c882-4109-878f-d883ebe6cd6d','吏隠宜春郡詩十首  其四','祖無擇','宋','宋诗','song-poetry','','[]','吏隠宜春郡，閑思應舉時。',48,'全唐诗/poet.song.20000.json','["吏隠宜春郡，閑思應舉時。", "端居苦貧賤，徒步入京師。", "誤寵乘軒鶴，鈞憂入廟犧。", "功名在何許，雙鬢已垂絲。"]'),
('8cc40ec6-bbad-4014-aa9c-703b2207fb29','吏隠宜春郡詩十首  其五','祖無擇','宋','宋诗','song-poetry','','[]','吏隠宜春郡，鄉園去路賒。',48,'全唐诗/poet.song.20000.json','["吏隠宜春郡，鄉園去路賒。", "間關成客宦，荏苒度年華。", "出水魚吞餌，辭山鳳在笯。", "誰言千里隔，夜夜夢吾家。"]'),
('22bfa4dc-2046-4e59-82ac-0aa8896a9a78','吏隠宜春郡詩十首  其六','祖無擇','宋','宋诗','song-poetry','','[]','吏隠宜春郡，同僚得俊髦。',48,'全唐诗/poet.song.20000.json','["吏隠宜春郡，同僚得俊髦。", "純音等疏越，餘刃劇豪曹。", "器識青雲遠，歌詞白雪高。", "遂令遷客意，不復賦離騷。"]'),
('d93a4e4a-b559-4ed3-925c-24b867165f4e','吏隠宜春郡詩十首  其七','祖無擇','宋','宋诗','song-poetry','','[]','吏隠宜春郡，山城少客過。',48,'全唐诗/poet.song.20000.json','["吏隠宜春郡，山城少客過。", "靜中窺物理，閑外養天和。", "春暖尋花塢，宵凉翫月波。", "將迎者誰子，勞逸兩如何。"]'),
('ae39a55d-616f-4120-8e63-8e59aa1d3f66','吏隠宜春郡詩十首  其八','祖無擇','宋','宋诗','song-poetry','','[]','吏隠宜春郡，放懷詩酒間。',48,'全唐诗/poet.song.20000.json','["吏隠宜春郡，放懷詩酒間。", "未能慙下俚，幾欲效中山。", "杜甫籓籬窄，劉伶幕帟慳。", "高吟與沈醉，榮辱詎相關。"]'),
('c0df8c12-9f16-4abd-9198-ecb8e3cec9cf','吏隠宜春郡詩十首  其九','祖無擇','宋','宋诗','song-poetry','','[]','吏隠宜春郡，窮能嬾更占。',48,'全唐诗/poet.song.20000.json','["吏隠宜春郡，窮能嬾更占。", "矜名遭巧譖，晦跡喜深潛。", "昔慕狂爲聖，今師智養恬。", "優游無一事，不覺歲時淹。"]'),
('fb91dc38-1b5c-4297-820b-4d394a21ab75','吏隠宜春郡詩十首  其一○','祖無擇','宋','宋诗','song-poetry','','[]','吏隠宜春郡，素飱誠有餘。',48,'全唐诗/poet.song.20000.json','["吏隠宜春郡，素飱誠有餘。", "政聲慙遂霸，文藻謝嚴徐。", "使節分銅虎，仙廬秘石渠。", "君恩殊未報，不敢賦歸歟。"]'),
('4e536e91-65b1-40ee-8cd3-e3fb54e58e9d','題紀信廟','祖無擇','宋','宋诗','song-poetry','','[]','漢祖臨危日，將軍獨奪功。',48,'全唐诗/poet.song.20000.json','["漢祖臨危日，將軍獨奪功。", "一身雖是詐，萬古盡言忠。", "樹老風聲澀，天寒景色空。", "我來觀廟貌，無語對村翁。"]'),
('d39da965-09b0-49c7-8bd7-6b13c49d2f78','昇州保寧寺鳳皇亭','祖無擇','宋','宋诗','song-poetry','','[]','鳳臺雖舊址，亭榭斬新開。',48,'全唐诗/poet.song.20000.json','["鳳臺雖舊址，亭榭斬新開。", "荆棘榛蕪去，江山氣象來。", "明君虞氏化，賢守次公才。", "遲爾離丹穴，飛飛止此臺。"]'),
('cee7a724-0596-4180-bac9-bdd5130b8e58','留題女郎臺','祖無擇','宋','宋诗','song-poetry','','[]','女郎臺上寺，寺影蘸湖光。',48,'全唐诗/poet.song.20000.json','["女郎臺上寺，寺影蘸湖光。", "夜梵星辰近，晨齋鳥雀忙。", "烟滋楊柳綠，風逞芰荷香。", "欲下還慵去，憑闌到夕陽。"]'),
('e498800a-5d2f-487a-bcee-a8b012c4ad9d','春郊即事','祖無擇','宋','宋诗','song-poetry','','[]','東方驅曉騎，南畝勸春耕。',48,'全唐诗/poet.song.20000.json','["東方驅曉騎，南畝勸春耕。", "試與牧童語，因知林鳥名。", "雨前茶正小，社後酒猶清。", "可笑豚蹄祝，篝車望豈輕。"]'),
('e6050bd2-e0d3-4901-be34-886ef173a637','送李承知京兆司錄','祖無擇','宋','宋诗','song-poetry','','[]','纔從知己薦，又應辟書行。',48,'全唐诗/poet.song.20000.json','["纔從知己薦，又應辟書行。", "廷尉官聯重，軍謀職任清。", "華嚴東野秀，紫閣晚峯橫。", "盡是供吟處，歸應新築成。"]'),
('544e33b1-13b5-4ec6-a5b0-37af1193560d','送宋寺丞通判邛州','祖無擇','宋','宋诗','song-poetry','','[]','半刺侯藩重，臨邛驛路賒。',48,'全唐诗/poet.song.20000.json','["半刺侯藩重，臨邛驛路賒。", "將經灞陵樹，先看洛陽花。", "土物張騫竹，民封卓氏家。", "爲君傷遠目，日日斷褒斜。"]'),
('e4e081c2-89b5-448f-a370-f65a5e70c1aa','秋日感懷','祖無擇','宋','宋诗','song-poetry','','[]','多病多愁客，新秋百感生。',48,'全唐诗/poet.song.20000.json','["多病多愁客，新秋百感生。", "異鄉違土性，孤宦見人情。", "案厭留燈讀，田思带雨耕。", "不堪臨曉鏡，潘鬢二毛成。"]'),
('c36da99f-a72d-46d1-95b0-afc7f0fef673','寄潁州兄','祖無擇','宋','宋诗','song-poetry','','[]','川陸一千里，炎凉六十旬。',48,'全唐诗/poet.song.20000.json','["川陸一千里，炎凉六十旬。", "意通書信少，思入夢魂頻。", "身外宦情薄，眼前人事新。", "祝兄無見念，憂道不憂貧。"]'),
('2008ee32-9d2d-4245-8c76-5e8c7bcaa639','舟次張澤阻風','祖無擇','宋','宋诗','song-poetry','','[]','舟楫雖佳興，風波即畏途。',48,'全唐诗/poet.song.20000.json','["舟楫雖佳興，風波即畏途。", "我心何所懼，世路此無殊。", "銜尾千艘泊，爭頭萬怪趨。", "飃然不終日，揮手謝淳洿。"]'),
('7a4c6379-012d-4c6b-b34b-9647e4a44d45','寄題漢州西湖兼簡知郡馬屯田','祖無擇','宋','宋诗','song-poetry','','["\u897f\u6e56"]','房相留遺愛，清風湖水長。',48,'全唐诗/poet.song.20000.json','["房相留遺愛，清風湖水長。", "人思浴池鳳，誰識濟川航。", "白雪徽音遠，洪鈞道化光。", "還聞繼高躅，新有召公棠。"]'),
('d8009d7d-afb0-4b1c-9180-e737c628b737','寄千乘劉殿丞求字人編','祖無擇','宋','宋诗','song-poetry','','[]','千乘劉夫子，高名繼謫仙。',48,'全唐诗/poet.song.20000.json','["千乘劉夫子，高名繼謫仙。", "從居庇身邑，已著字人編。", "才入鐘嶸品，文期鄭氏箋。", "何當求副本，長願播匏弦。"]'),
('3e7afbb9-12de-4bc7-b31f-3033e7c394c4','寄信安判官張秘校','祖無擇','宋','宋诗','song-poetry','','[]','蓮幕從軍客，蓬仙典校人。',48,'全唐诗/poet.song.20000.json','["蓮幕從軍客，蓬仙典校人。", "才章過鮑謝，交契敵雷陳。", "婉婉謀畫暇，翩翩書問頻。", "徒知感高義，猶阻奉清塵。"]'),
('769fe872-d2dc-4a3f-b880-24a651b4b841','泗水','祖無擇','宋','宋诗','song-poetry','','[]','紀地復涵虛，清疑顥氣俱。',48,'全唐诗/poet.song.20000.json','["紀地復涵虛，清疑顥氣俱。", "東家遺教遠，夏后建功殊。", "冷色平吞魯，長波迥勝吳。", "如斯無少息，體道悟真儒。"]'),
('649e5bfa-08b7-4ee5-ba3e-58f0579aab1c','沈康赴江西掾','祖無擇','宋','宋诗','song-poetry','','[]','高譽冠時英，人皆倒屣迎。',48,'全唐诗/poet.song.20000.json','["高譽冠時英，人皆倒屣迎。", "決科材尚屈，掌獄職仍輕。", "滕閣吟登健，吳山醉望清。", "公餘如訪古，一爲問豐城。"]'),
('e630fa58-19fd-4776-bfd5-bc413e26ebe0','張唐民下第東歸','祖無擇','宋','宋诗','song-poetry','','[]','學古功非淺，干時命尚迍。',48,'全唐诗/poet.song.20000.json','["學古功非淺，干時命尚迍。", "拾青辜壯志，垂白念慈親。", "歸路天同遠，生涯世自貧。", "吾知君道大，馳逐老風塵。"]'),
('385da584-e6ea-4b1b-beef-700346a0203c','送人作尉臨潼','祖無擇','宋','宋诗','song-poetry','','[]','年少文能老，新曾射策來。',48,'全唐诗/poet.song.20000.json','["年少文能老，新曾射策來。", "從橫傳古學，慷慨濟時才。", "黄綬官徒爾，青雲志在哉。", "他年歸會課，遲子出塵埃。"]'),
('62134c1d-b7ec-47f5-b97b-a8e0cf2a971d','書懷寄呈萊州張學士','祖無擇','宋','宋诗','song-poetry','','[]','從作東齊吏，經年寡往來。',49,'全唐诗/poet.song.20000.json','["從作東齊吏，經年寡往來。", "朱泉顔隨日減，青眼爲山開。", "學政慙能政，論材信不材。", "何人慰孤寂，知己在蓬萊。"]'),
('d7b08b78-70f4-41ce-b16a-f4181d32915f','萬太博知惠州','祖無擇','宋','宋诗','song-poetry','','[]','惠州君未到，聽我送君吟。',48,'全唐诗/poet.song.20000.json','["惠州君未到，聽我送君吟。", "去路九韶石，鄰封八桂林。", "下車秋色老，望闕海雲深。", "善政多餘暇，無忘惠好音。"]'),
('8b28d407-76d2-4d54-ab97-652132d1bfbd','送新州陳式虞部','祖無擇','宋','宋诗','song-poetry','','[]','大庾嶺南郡，新興事若何。',48,'全唐诗/poet.song.20000.json','["大庾嶺南郡，新興事若何。", "還珠合浦近，辟惡密香多。", "主聖天如覆，時平海不波。", "更逢賢太守，應有袴襦歌。"]'),
('5781f7d2-c7ce-45dc-9693-480cad8e5869','送蓮房與馬屯田','祖無擇','宋','宋诗','song-poetry','','[]','問遺不必貴，要之資闕如。',48,'全唐诗/poet.song.20000.json','["問遺不必貴，要之資闕如。", "蓮房三百枚，采掇亦云初。", "持以侑尊酒，甘香即有餘。", "野老獻芹意，今予其有諸。"]'),
('7ad0667b-1506-445e-b539-ad2049a3fabe','題安成劉伯玉日新亭','祖無擇','宋','宋诗','song-poetry','','[]','積善家餘慶，日新亭可云。',48,'全唐诗/poet.song.20000.json','["積善家餘慶，日新亭可云。", "詩書盈几有，道藝喜時聞。", "兒姪既登學，晨昏在克勤。", "欲知榮地力，此便是青雲。"]'),
('92d1be90-a69c-4cd2-b6fd-142344d6e4ab','寄成都詩人謝希濤','祖無擇','宋','宋诗','song-poetry','','[]','常聞游蜀客，來說謝希濤。',48,'全唐诗/poet.song.20000.json','["常聞游蜀客，來說謝希濤。", "氣稟江山秀，名因翰墨高。", "新詩來自遠，密意念空勞。", "拙句聊相贈，應煩報錯刀。"]'),
('5229766d-f15b-4d8b-94cf-857fa1e1c3c5','秋曉寓自','祖無擇','宋','宋诗','song-poetry','','[]','梧桐冷墜秦宮井，沆瀣光浮漢苑槃。',32,'全唐诗/poet.song.20000.json','["梧桐冷墜秦宮井，沆瀣光浮漢苑槃。", "倚杵遠天垂六幕，照梁初日上三竿。"]'),
('57e62351-79be-4cb7-9fda-3f35deb3d5d1','鴛鴦','祖無擇','宋','宋诗','song-poetry','','[]','水宿雲飛無定期，雄雌兩兩鎮相隨。',32,'全唐诗/poet.song.20000.json','["水宿雲飛無定期，雄雌兩兩鎮相隨。", "到頭不會天何意，却使人生有別離。"]'),
('65a829e0-f3b1-479d-bff1-53f59ddb043b','後池新柳','祖無擇','宋','宋诗','song-poetry','','[]','客來莫怪寡心情，俗吏喧嘩不喜聽。',32,'全唐诗/poet.song.20000.json','["客來莫怪寡心情，俗吏喧嘩不喜聽。", "多感後池楊柳眼，一回相對一回青。"]'),
('33f3e994-07c8-4f96-9ba7-d77d80e707de','歷城春日對酒','祖無擇','宋','宋诗','song-poetry','','[]','數尺游絲拂面來，數枝紅杏向人開。',32,'全唐诗/poet.song.20000.json','["數尺游絲拂面來，數枝紅杏向人開。", "眼前信美非吾土，且勸春風酒一杯。"]'),
('fb2c87f3-dc5a-49ab-99ac-e929374cd9b9','戲別申申堂','祖無擇','宋','宋诗','song-poetry','','[]','翠柳和煙籠碧沼，紅芳如火照諸鄰。',32,'全唐诗/poet.song.20000.json','["翠柳和煙籠碧沼，紅芳如火照諸鄰。", "主公欲去寧無戀，倚翠隈紅屬後人。"]'),
('9865cb5e-0306-4f92-b383-0070ce9fef9a','汴水即事','祖無擇','宋','宋诗','song-poetry','','[]','波狂如箭雨如絲，汎汎扁舟瞥鳥飛。',32,'全唐诗/poet.song.20000.json','["波狂如箭雨如絲，汎汎扁舟瞥鳥飛。", "睡起謳鴉乍鳴櫓，却思村舍聽鄰機。"]'),
('f23c0268-0705-481e-8e96-7f20a44b70d8','澄清閣在','祖無擇','宋','宋诗','song-poetry','','[]','范滂雅志在澄清，今日廉車命閣名。',32,'全唐诗/poet.song.20000.json','["范滂雅志在澄清，今日廉車命閣名。", "華榜高標雖具美，奈何長是困蒼生。"]'),
('02036f76-8e64-4b9b-bb71-a8f9c37b2371','贈江州李虛一司戶','祖無擇','宋','宋诗','song-poetry','','[]','官况蕭條三語掾，地居卑濕九江城。',32,'全唐诗/poet.song.20000.json','["官况蕭條三語掾，地居卑濕九江城。", "曾聞午夜開宣室，早晚君王召賈生。"]'),
('239b13f2-1c24-4412-8d61-976d97ee4e8b','劉仙石  其一','祖無擇','宋','宋诗','song-poetry','','[]','神仙不死石長存，萬古千秋表洞門。',32,'全唐诗/poet.song.20000.json','["神仙不死石長存，萬古千秋表洞門。", "人欲求真好修煉，莫徒將杖叩苔痕。"]'),
('70aad349-d795-42bc-8912-cc302ea2a3d5','劉仙石  其二','祖無擇','宋','宋诗','song-poetry','','[]','支機莫問君平肆，取履誰收黄石祠。',32,'全唐诗/poet.song.20000.json','["支機莫問君平肆，取履誰收黄石祠。", "深洞自開人不見，何須惆悵憶當時。"]'),
('cf3b5f96-0dd8-448a-92b7-bbf234209afa','交代屯田遠惠書問紙尾批示若就江州至軍兼可腹背游覽廬阜因成拙句且答佳意','祖無擇','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山在境好行春，猶恨奇峰半屬鄰。',32,'全唐诗/poet.song.20000.json','["廬山在境好行春，猶恨奇峰半屬鄰。", "腹背徧游煩示諭，即當先謁樂天真。"]'),
('b03432ab-5245-49d0-8038-4d88df14b73d','將至南康道中','祖無擇','宋','宋诗','song-poetry','','[]','湓江輟棹整驂騑，松路楊鞭入翟微。',32,'全唐诗/poet.song.20000.json','["湓江輟棹整驂騑，松路楊鞭入翟微。", "好是近郊人候望，紛紛羽服與田衣。"]'),
('b62510ec-1897-4a3b-ab07-2f8bdbbdee7b','招二三僚友游廬阜','祖無擇','宋','宋诗','song-poetry','','[]','雨餘廬阜連天碧，公退鈴齋盡日閑。',32,'全唐诗/poet.song.20000.json','["雨餘廬阜連天碧，公退鈴齋盡日閑。", "爲報二三佳客道，速須蠟屐共登山。"]'),
('33db7bdf-270d-4d48-86c9-d307f2928742','遊栖賢','祖無擇','宋','宋诗','song-poetry','','[]','偷得沈迷簿領身，暫來林下訪幽人。',32,'全唐诗/poet.song.20000.json','["偷得沈迷簿領身，暫來林下訪幽人。", "雲泉滿眼慵歸去，便擬拋官學隠淪。"]'),
('2200baa7-a797-45d8-8cf7-9e2ad3f4fe0c','歌者李蘇蘇','祖無擇','宋','宋诗','song-poetry','','[]','歌妙纍纍若貫珠，歷城惟祗數蘇蘇。',32,'全唐诗/poet.song.20000.json','["歌妙纍纍若貫珠，歷城惟祗數蘇蘇。", "何當更唱陽春曲，爲爾今宵倒玉壺。"]'),
('a47f5baa-ff03-4098-8e81-c21f7981016f','過渦河','祖無擇','宋','宋诗','song-poetry','','[]','揚鞭策羸馬，橋上一徘徊。',24,'全唐诗/poet.song.20000.json','["揚鞭策羸馬，橋上一徘徊。", "欲擬臨渦賦，慙無八斗才。"]'),
('7369a897-2c57-4784-aa73-1c03762c588c','馬古口占','祖無擇','宋','宋诗','song-poetry','','[]','前年躡屩念歸與，今日乘軒類使乎。',32,'全唐诗/poet.song.20000.json','["前年躡屩念歸與，今日乘軒類使乎。", "千里班春憂寄重，自慙翻屬箇非夫。"]'),
('88a6c5d4-7617-411e-bcb9-c9c15f56cdad','登泰山簡周行','祖無擇','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','日日塵中眼不開，暫登蒼翠喜游陪。',32,'全唐诗/poet.song.20000.json','["日日塵中眼不開，暫登蒼翠喜游陪。", "莫辭辛苦經難險，大有人生不到來。"]'),
('19175a6b-0a8c-4d06-a871-ef8f2cd740e0','又游靈巖','祖無擇','宋','宋诗','song-poetry','','[]','紅塵滿爲三回到，青嶂迎人萬疊開。',32,'全唐诗/poet.song.20000.json','["紅塵滿爲三回到，青嶂迎人萬疊開。", "却被野僧相顧笑，區區還是舊時來。"]'),
('56036002-3f0d-4642-a292-fe1187eb114c','次韻酬陳判官見貽','祖無擇','宋','宋诗','song-poetry','','[]','一篇爲惠枉瑶封，疑得仙文自蕊宮。',32,'全唐诗/poet.song.20000.json','["一篇爲惠枉瑶封，疑得仙文自蕊宮。", "始信夫君才力大，居然天地入形籠。"]'),
('43e5d9e1-cf2f-4244-9abb-3c96991ae92c','周成職方笑臺','祖無擇','宋','宋诗','song-poetry','','[]','賈生太息唐衢哭，感事傷時可奈何。',32,'全唐诗/poet.song.20000.json','["賈生太息唐衢哭，感事傷時可奈何。", "爭似君當堯舜日，臺頭大笑樂天和。"]'),
('a018b520-d0f8-4168-877b-ef65343193e3','感事','祖無擇','宋','宋诗','song-poetry','','[]','東家木鐸德音遠，西竺金人像教來。',32,'全唐诗/poet.song.20000.json','["東家木鐸德音遠，西竺金人像教來。", "禮樂不興王道絕，吾民何日遂康哉。"]'),
('b397356f-d7d4-4821-b5ce-32a2553483e3','題蔡州壺仙觀','祖無擇','宋','宋诗','song-poetry','','[]','鸎老花殘過禁烟，杖藜閒步到壺仙。',32,'全唐诗/poet.song.20000.json','["鸎老花殘過禁烟，杖藜閒步到壺仙。", "仙家本是無塵地，別有風光一洞天。"]'),
('03be06bf-4d70-4676-af47-df5cec531255','聚爲九老自詠','祖無擇','宋','宋诗','song-poetry','','[]','科名高厭玉階前，歷任公卿四十年。',32,'全唐诗/poet.song.20000.json','["科名高厭玉階前，歷任公卿四十年。", "休道老夫無事業，兩扶紅日上青天。"]'),
('deee0c12-eba9-4a1f-a939-888b77ffbb83','題蔡州東湖','祖無擇','宋','宋诗','song-poetry','','[]','夕陽水底霞鋪錦，清夜波心月湧金。',32,'全唐诗/poet.song.20000.json','["夕陽水底霞鋪錦，清夜波心月湧金。", "此是東湖最佳處，無人來伴水仙吟。"]'),
('5aea3969-20aa-491c-a4f1-db547bb1ac05','詠繭兒','祖無擇','宋','宋诗','song-poetry','','[]','千絲萬縷自經營，本爲藏身却誤身。',32,'全唐诗/poet.song.20000.json','["千絲萬縷自經營，本爲藏身却誤身。", "待得巧成歸鼎鑊，不知輕煖屬他人。"]'),
('722e76a3-9ecb-4696-91d9-a1628429e05e','次韻和','祖無擇','宋','宋诗','song-poetry','','[]','前日西行別翰林，爲我開尊飲之酒。',144,'全唐诗/poet.song.20000.json','["前日西行別翰林，爲我開尊飲之酒。", "高冠滿坐皆賢豪，談笑喧呼時各有。", "自慙流落疏游陪，十載江湖成浪走。", "主人名重聞四夷，典冊高文推大手。", "發揮六藝無遺精，考黜百家如拉朽。", "顧我昏冥聞道晚，代謝春秋四十九。", "當年擊節傚金注，此日强顔同木偶。", "事功未省成尺寸，廩祿惟思校升斗。", "會須歸去老東陂，鼓腹含飴逐堯叟。"]'),
('005c2419-5c71-4beb-8616-334800bdd3a8','題袁州東湖盧肇石','祖無擇','宋','宋诗','song-poetry','','[]','袁山之陽秀水側，草覆遺基誰氏宅。',320,'全唐诗/poet.song.20000.json','["袁山之陽秀水側，草覆遺基誰氏宅。", "皆云子發其姓盧，往往文章名籍籍。", "宅中舊物何所存，惟有嶙峋一區石。", "闊纔三尺高倍尋，久卧塵沙羣瓦礫。", "余心好異因獨往，下馬環觀聊拂拭。", "地表可見十二三，已足怪駭動魂魄。", "呼工運鍤壍其旁，挽以長絙百夫力。", "雜然鼓譟登大車，恍爾如蒙巨靈擘。", "選置東湖最佳處，四面澄波映天碧。", "倚空突兀無與鄰，頓覺亭臺增氣色。", "彎環幽竇莫敢撢，恐有乖龍飛霹靂。", "余嘗南游到陽朔，衆峰矗矗春筍植。", "捫蘿踏蘚窮之遍，若此奇卓曾未識。", "郡人奔走來如雲，故老驚視復唧唧。", "乃言此石遇真賞，屈指于今年二百。", "沈埋曠代誰爾珍，一日光價逾荆璧。", "嗟余束髮大夫後，區區志尚惟孤直。", "十年再謫非不窮，猶慕堅純無改易。", "如何故老不我愚，感物再三形嘆息。", "石不能言人有言，忽使他時重湮阨。"]'),
('14407826-8350-4d3e-b78c-f6c435c36a54','和題東湖','祖無擇','宋','宋诗','song-poetry','','[]','晴烟羃冪澹湖光，勢勝居然占一方。',64,'全唐诗/poet.song.20000.json','["晴烟羃冪澹湖光，勢勝居然占一方。", "拂水萬絲楊柳弱，倚風千蓋芰荷香。", "縱遊閑泛蘭舟穩，半醉狂眠石席凉。", "公退每來須度日，却疑身出利名鄉。"]'),
('aa8070eb-0506-4f0d-86e3-90a3fcb6e27e','又和題宜春臺','祖無擇','宋','宋诗','song-poetry','','[]','異鄉何處散幽懷，頼得城中百尺臺。',64,'全唐诗/poet.song.20000.json','["異鄉何處散幽懷，頼得城中百尺臺。", "還向天涯經歲住，那知春色爲唯來。", "雪消江上看梅發，風暖衡陽有雁回。", "强擬登高聊賦咏，再三媿乏楚人才。"]'),
('3df40970-1789-4194-89f7-0d9349d4dc1e','題尚書余襄公西園','祖無擇','宋','宋诗','song-poetry','','[]','臺閣清風正凜然，歸休車騎曲江邊。',64,'全唐诗/poet.song.20000.json','["臺閣清風正凜然，歸休車騎曲江邊。", "及親已具三牲養，負郭新添二頃田。", "萊子長年榮綵服，衛公雅意樂平泉。", "官閑道在心無悶，惟惜光陰事簡編。"]'),
('278d75b9-b260-480f-9341-f64e75c79c88','題余尚書山居要術','祖無擇','宋','宋诗','song-poetry','','[]','張衡已作歸田賦，汜勝仍修種樹書。',32,'全唐诗/poet.song.20000.json','["張衡已作歸田賦，汜勝仍修種樹書。", "願借山居精要術，欲將嵩洛葺吾廬。"]'),
('db9ade68-8b09-4eaa-bb14-f844922aa619','袁州慶豐堂十閑詠  其一','祖無擇','宋','宋诗','song-poetry','','[]','吏散鈴齋掩，閑眠到日斜。',24,'全唐诗/poet.song.20000.json','["吏散鈴齋掩，閑眠到日斜。", "無端是春夢，容易繞京華。"]'),
('55950d84-6881-41de-b637-48d4c2b92e3f','袁州慶豐堂十閑詠  其二','祖無擇','宋','宋诗','song-poetry','','[]','鄭聲良可厭，閑抱七絲琴。',24,'全唐诗/poet.song.20000.json','["鄭聲良可厭，閑抱七絲琴。", "欲識調絃意，理人先理心。"]'),
('4e6acf35-8682-4600-91a8-665ad21fcd63','袁州慶豐堂十閑詠  其三','祖無擇','宋','宋诗','song-poetry','','[]','年長身多病，閑鈔已試方。',24,'全唐诗/poet.song.20000.json','["年長身多病，閑鈔已試方。", "未甘先犬馬，畢命報恩光。"]'),
('53969d33-df90-437c-8f87-6bbf67fbe06f','袁州慶豐堂十閑詠  其四','祖無擇','宋','宋诗','song-poetry','','[]','青山日相對，閑看白雲生。',24,'全唐诗/poet.song.20000.json','["青山日相對，閑看白雲生。", "誰謂無心出，中含濟物情。"]'),
('b5565a69-87d6-4382-b703-734a4116628d','袁州慶豐堂十閑詠  其五','祖無擇','宋','宋诗','song-poetry','','[]','曉桉三杯後，閑烹北苑茶。',24,'全唐诗/poet.song.20000.json','["曉桉三杯後，閑烹北苑茶。", "色香俱絕品，雪泛滿甌花。"]'),
('340e0525-5208-45be-87ae-4ff887faf72f','袁州慶豐堂十閑詠  其六','祖無擇','宋','宋诗','song-poetry','','[]','扁舟賓客少，閑作道家裝。',24,'全唐诗/poet.song.20000.json','["扁舟賓客少，閑作道家裝。", "跡靜心還靜，逍遥覺日長。"]'),
('712a0435-11e9-4f4e-9048-415faf2abffe','袁州慶豐堂十閑詠  其七','祖無擇','宋','宋诗','song-poetry','','[]','雨霽輕埃息，閑吟面曲池。',24,'全唐诗/poet.song.20000.json','["雨霽輕埃息，閑吟面曲池。", "遊鱗時對擲，雙破碧漣漪。"]'),
('182613bf-98a9-48b8-b6e3-f2c614221abc','袁州慶豐堂十閑詠  其八','祖無擇','宋','宋诗','song-poetry','','[]','朝來因試筆，閑答故交書。',24,'全唐诗/poet.song.20000.json','["朝來因試筆，閑答故交書。", "莫怪音塵絕，吾心與世疎。"]'),
('2a72e6e8-aea5-4b41-9c21-4b99361b9c17','袁州慶豐堂十閑詠  其九','祖無擇','宋','宋诗','song-poetry','','[]','漸老無功業，閑思惜壯年。',24,'全唐诗/poet.song.20000.json','["漸老無功業，閑思惜壯年。", "桑榆如有得，猶可勒燕然。"]'),
('88fad482-5def-46cd-b844-06a1761e4d15','袁州慶豐堂十閑詠  其一○','祖無擇','宋','宋诗','song-poetry','','[]','晴軒足清趣，閑與鶴開籠。',24,'全唐诗/poet.song.20000.json','["晴軒足清趣，閑與鶴開籠。", "寄語北山侶，無驚蕙帳空。"]'),
('6462fdcc-3408-4c17-9592-b56752c4be89','和閻運使以詩見奬吏隠宜春郡詩','祖無擇','宋','宋诗','song-poetry','','[]','狂吟何足話風騷，和寡甘降郢唱高。',64,'全唐诗/poet.song.20000.json','["狂吟何足話風騷，和寡甘降郢唱高。", "敢望與言同子夏，競推多可似出濤。", "九成豈後虞韶美，一字終虛魯史褒。", "自笑潢汙不盈尺，猶將學海去滔滔。"]'),
('275f1513-6f28-4361-9044-d98c467c2cf7','和','祖無擇','宋','宋诗','song-poetry','','[]','九十日春今日盡，送春何況我偏知。',32,'全唐诗/poet.song.20000.json','["九十日春今日盡，送春何況我偏知。", "後期應在經殘臘，重探梅開雪裏枝。"]'),
('13b8ce4a-ba93-4a76-99b4-1cfae239910d','和','祖無擇','宋','宋诗','song-poetry','','[]','憶時相逢甲午年，與君同賦送春篇。',64,'全唐诗/poet.song.20000.json','["憶時相逢甲午年，與君同賦送春篇。", "等閑又見春風老，更捧新吟一惘然。", "萬樹紅芳落漸稀，浮榮能得幾多時。", "孤根未識陽和力，春去春來兩不知。"]'),
('7c088915-18b7-48ff-91a8-62b670369b4a','九日登袁州宜春臺','祖無擇','宋','宋诗','song-poetry','','[]','落帽佳辰又到來，黄花爛熳爲誰開。',64,'全唐诗/poet.song.20000.json','["落帽佳辰又到來，黄花爛熳爲誰開。", "已經多歲衰容改，更被無情急景催。", "取次盃盤須盡醉，隨宜歌管任頻陪。", "却漸未報君恩厚，空向山城養不才。"]'),
('8522731d-2e91-471e-a16d-0dc4011daa2f','詠震山巖彭徵君釣臺','祖無擇','宋','宋诗','song-poetry','','[]','閑作山城吏隠居，敬君真逸寓漁磯。',32,'全唐诗/poet.song.20000.json','["閑作山城吏隠居，敬君真逸寓漁磯。", "臺前巖畔清風在，尚想烟波映芰衣。"]'),
('041def69-548b-4afa-bc47-4bcc48bd1b88','石傘峯書堂','祖無擇','宋','宋诗','song-poetry','','[]','伊人高步接夔龍，舊隠荒凉石傘峯。',64,'全唐诗/poet.song.20000.json','["伊人高步接夔龍，舊隠荒凉石傘峯。", "莘野躬耕聞往事，傅巖代築見遺蹤。", "草茅豈合掩崇業，竹帛終能紀茂庸。", "朝暮油雲膚寸合，何妨霖雨徧三農。"]'),
('e8610465-e227-42ad-aa7c-05cd03ba7f1c','慈嚴院','祖無擇','宋','宋诗','song-poetry','','[]','恩德傳名久，慈嚴賜號新。',96,'全唐诗/poet.song.20000.json','["恩德傳名久，慈嚴賜號新。", "樓臺□半□，風水憶長春。", "客有披襟者，時無洗耳人。", "清音發鐘磬，翠色混松筠。", "住合登仙籍，來宜出俗塵。", "經年嗟倥傯，半日喜逡巡。", "席上詩情逸，樽中酒味醇。", "怱怱又歸去，自愧使君身。"]'),
('b4eb56f5-2337-4743-b8d5-a2c467f7a95f','題招提院靜照堂','祖無擇','宋','宋诗','song-poetry','','[]','院靜遠囂塵，虛堂締構新。',48,'全唐诗/poet.song.20000.json','["院靜遠囂塵，虛堂締構新。", "幾招台嶺客，共話沃州春。", "想像山中樂，優游物外身。", "公卿詩滿壁，雅正日相親。"]'),
('1384d7bd-e1c0-4c90-9335-51989b4888f3','曹六四歌同遊靈巖因寄尊府判院','祖無擇','宋','宋诗','song-poetry','','[]','石湖浮動靈巖月，天靜碧雲低白煙。',32,'全唐诗/poet.song.20000.json','["石湖浮動靈巖月，天靜碧雲低白煙。", "此夜山川宜斷取，爲予携到若翁前。"]'),
('f4acf387-c87d-48d8-b0e1-760a50a6f9da','自詠二首  其一','祖無擇','宋','宋诗','song-poetry','','[]','松下門開入翠微，草香花氣襲春衣。',32,'全唐诗/poet.song.20000.json','["松下門開入翠微，草香花氣襲春衣。", "山中深僻無人到，自有閒雲共鶴飛。"]'),
('a92f7e6e-5fca-428b-9b36-0a721b6a5f0c','自詠二首  其二','祖無擇','宋','宋诗','song-poetry','','[]','形勝山前感物華，却乘清興過僧家。',64,'全唐诗/poet.song.20000.json','["形勝山前感物華，却乘清興過僧家。", "樓臺消廢無人問，今古傳聞只自嗟。", "雲擁斷崖埋石笋，泉沖涼雨落金沙。", "憑君識得尋幽趣，只管高譚至日斜。"]'),
('2abb4e59-abf2-4d22-b06d-5227102b0f2e','記萬載風俗三絕  其一','祖無擇','宋','宋诗','song-poetry','','[]','居民覆其屋，大半施白瓦。',24,'全唐诗/poet.song.20000.json','["居民覆其屋，大半施白瓦。", "山際兩三家，如經新雪下。"]'),
('3acbe253-7ee4-43ec-bee5-4e8691fa2dde','記萬載風俗三絕  其二','祖無擇','宋','宋诗','song-poetry','','[]','官酤米爲麴，釀出成紅酒。',24,'全唐诗/poet.song.20000.json','["官酤米爲麴，釀出成紅酒。", "里社醉豐年，便是宣城酎。"]'),
('dd2029ee-33c7-4058-8d70-c1b2884d8bce','記萬載風俗三絕  其三','祖無擇','宋','宋诗','song-poetry','','[]','田中多峭石，蒼玉亂欹斜。',24,'全唐诗/poet.song.20000.json','["田中多峭石，蒼玉亂欹斜。", "怪似湘中見，封域近長沙。"]'),
('bb5453c3-4fb1-4b4f-8d3d-a7474a414e94','鬰林觀三言詩刻','祖無擇','宋','宋诗','song-poetry','','[]','犯驚濤，航溟渤。',80,'全唐诗/poet.song.20000.json','["犯驚濤，航溟渤。", "披宿莽，屐崛岉。", "愒槃石，解簪韍。", "挹飛泉，醒心骨。", "揮高論，謝俗物。", "思古人，忽終日。", "足飲酣，清思逸。", "即絕壁，試奇筆。", "千萬言，蒼鮮沒。", "後有人，爲吾拂。"]'),
('15e31dea-ccad-40e0-b69d-b3954df29aaf','和祖無擇題袁州東湖盧肇石','任大中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','宜陽刺史才，祖擇之維傑。',288,'全唐诗/poet.song.20000.json','["宜陽刺史才，祖擇之維傑。", "大旱雨一方，盡使焦枯活。", "公退趣尚深，水石探其絕。", "長江北岸林，唐有盧子發。", "曾居此林下，高把簪組脫。", "歲遠成荒墟，佳名詎泯沒。", "有石數尺長，猶是舊時物。", "況辱泥塗久，實有堅重節。", "擇之渡水見，力爲心慘切。", "萬夫一呼聚，撓動雷聲揭。", "地險若驅來，巖谷俱震裂。", "幽輔郡東河，脫得太華骨。", "白玉漏纖紋，雨頻爲澡刷。", "草蔓漸盤遶，柳綠密揮拂。", "潤恐欲迸泉，怪亦有奧穴。", "安知無蟄龍，時見微雲出。", "幾因牽夜吟，簾曉捲殘月。", "氣暗逼人寒，蒙籠未若別。", "烟重風掃開，獨立勢突兀。", "蘇武見單于，傲睨腰不折。", "人皆畫將歸，予筆恨麤拙。", "擇之豈不賢，天涯避讒舌。", "對此憂足忘，我觀未甚悅。", "不得見媧皇，願天無破缺。"]'),
('3361d223-6d5b-4e23-b96f-80a619984ab4','從清逸老人遊西山夜宿翠巖聯句','任大中','宋','宋诗','song-poetry','','[]','蒼龍夭矯西北來，鑿破明珠成碧岫。',65,'全唐诗/poet.song.20000.json','["蒼龍夭矯西北來，鑿破明珠成碧岫。", "何人駕空起樓閣，地靈不敢藏餘秀。", "鎮窗雲重衣巾潤，梳木風清肌骨透。", "任客來一夜與僧談，氣覺浩然充宇宙。"]'),
('93067d43-dc5c-4df6-b5e1-056c43ea71be','絕句','任大中','宋','宋诗','song-poetry','','[]','莫管流年一擲梭，花前對酒且高歌。',32,'全唐诗/poet.song.20000.json','["莫管流年一擲梭，花前對酒且高歌。", "命中若有終須有，到底無時不奈何。"]'),
('0250e374-4bce-43b9-99ec-072185d18451','送永倅周茂叔還濂溪','任大中','宋','宋诗','song-poetry','','[]','君去何人最淚流，老翁身獨宿南州。',32,'全唐诗/poet.song.20000.json','["君去何人最淚流，老翁身獨宿南州。", "隨君不及秋來雁，直到瀟湘水盡頭。"]'),
('ba94d35e-3e8d-4106-84c0-ec49e5b33651','和祖無擇袁州東湖盧肇石','蕭元宗','宋','宋诗','song-poetry','','[]','石是人非世所傳，宜陽城郭古山川。',64,'全唐诗/poet.song.20000.json','["石是人非世所傳，宜陽城郭古山川。", "和光瓦礫曾無累，委質泥沙積有年。", "地僻久爲神物護，時來方遇使君賢。", "介然作鎮東湖上，德政何當向此鎸。"]'),
('47d7769d-f8d0-4e18-a8e8-92a728d49c48','謝擇之學士惠示吏隠宜春郡十詩因成五十六言奉答','閻珣','宋','宋诗','song-poetry','','[]','達觀終知世事勞，利名都是一鴻毛。',64,'全唐诗/poet.song.20000.json','["達觀終知世事勞，利名都是一鴻毛。", "登瀛自有仙遊樂，緩带何妨吏隠高。", "深意庇民躋富壽，正辭華國聳英髦。", "摶風九萬期鵬翼，且傲松軒弄彩毫。"]'),
('7060e7e0-1442-4654-b838-be6149a572ea','和祖無擇九日登袁州宜春臺','宋攄','宋','宋诗','song-poetry','','[]','登高佳節喜重來，會客依隨五馬開。',64,'全唐诗/poet.song.20000.json','["登高佳節喜重來，會客依隨五馬開。", "帽落秋風隨意適，杯迎露菊趁時催。", "東籬幸有主人席，絳帳那逢上客陪。", "欲報君恩話歸去，不妨尊酒論文才。"]'),
('f86f01ca-f007-446b-bdef-c1387b410809','和祖無擇九日登袁州宜春臺','羅誘','宋','宋诗','song-poetry','','[]','九日經年一再來，不妨吏隠遣懷開。',64,'全唐诗/poet.song.20000.json','["九日經年一再來，不妨吏隠遣懷開。", "時豐訟少欣多暇，秋晚花黄儘任催。", "幸遇登高賢燕樂，喜容落帽客追陪。", "預愁詔入三公去，芹泮誰思樂育才。"]'),
('7f89e0de-21e1-47b1-87d2-a587985fdef5','鄴公菴歌','釋雲知','宋','宋诗','song-poetry','','[]','呼猿澗西藏石筍，丹桂蒼松達鷲嶺。',144,'全唐诗/poet.song.20000.json','["呼猿澗西藏石筍，丹桂蒼松達鷲嶺。", "幾年陳迹絕纖埃，一旦佳名同清景。", "山家時喜來五馬，相携款曲空巖下。", "遂許誅茅結小菴，異日功成伴瀟灑。", "菴成可以資靜觀，目前直見江湖寬。", "鄴公政簡每頻到，試茶笑傲浮雲端。", "物外似忘軒冕貴，此中深得林泉意。", "野人陪著病維摩，游息自同方丈地。", "芳猷從此流千載，且得而今光勝概。"]'),
('46194b60-3995-4337-93d5-9585c74c3e5b','晏起','王說','宋','宋诗','song-poetry','','[]','入夏酣眠醒較遲，幽人事事佔便宜。',32,'全唐诗/poet.song.20000.json','["入夏酣眠醒較遲，幽人事事佔便宜。", "閑來培灌經綸種，念起澄清賢師基。"]'),
('094490d6-f4f5-4aac-a379-92f132013683','西園辨蘭亭和韻','李大臨','宋','宋诗','song-poetry','','[]','沙石香叢葉葉青，却因聲誤得蟬名。',64,'全唐诗/poet.song.20000.json','["沙石香叢葉葉青，却因聲誤得蟬名。", "騷人佩處唯荆渚，識者知來徧蜀城。", "消得作亭滋九畹，便當入室異羣英。", "非逢至鑒分明說，汩沒人間過此生。"]'),
('2ab2e319-db2f-4ff6-8dce-14b61a587b47','送張職方出守高安','李大臨','宋','宋诗','song-poetry','','[]','白首爲郎舍，清朝剖使符。',24,'全唐诗/poet.song.20000.json','["白首爲郎舍，清朝剖使符。", "一麾榮父子，千里接江湖。"]'),
('f8e75b1b-b1f2-497d-b731-72f2c2cb97e5','題招提院靜照堂','李大臨','宋','宋诗','song-poetry','','[]','地勝堂新構，僧閑晝杜門。',48,'全唐诗/poet.song.20000.json','["地勝堂新構，僧閑晝杜門。", "山林誰樂靜，城市亦非喧。", "客到空彈指，風來不動幡。", "祗應常宴坐，對鏡一無言。"]'),
('78c22359-a883-49cc-8495-5a89c50e4567','謁濂溪周虞部','李大臨','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','簾前翠靄逼廬山，門掩寒流盡日閑。',32,'全唐诗/poet.song.20000.json','["簾前翠靄逼廬山，門掩寒流盡日閑。", "我亦忘機澹榮利，喜君高躅到松關。"]'),
('17cea1db-9c19-455c-9699-cb376e721451','句','龔鼎臣','宋','宋诗','song-poetry','','[]','家經武夷住，事與會稽隣。',12,'全唐诗/poet.song.20000.json','["家經武夷住，事與會稽隣。"]'),
('4af016bf-636c-4a64-89ad-4eab0df46abc','同林逋宿中峰次韻','徐復','宋','宋诗','song-poetry','','[]','盥櫛從朝嬾，論交慰昔賢。',48,'全唐诗/poet.song.20000.json','["盥櫛從朝嬾，論交慰昔賢。", "寒花隠亂草，老木插飛煙。", "聽雨夜牀冷，彈琴秋葉前。", "臨高問往事，歷歷是何年。"]'),
('61615ed8-b1ff-4da4-9f99-b724b2765683','耆英會詩  其一','楚建中','宋','宋诗','song-poetry','','[]','自顧頹齡七十餘，久慚頑鈍費洪鑪。',32,'全唐诗/poet.song.20000.json','["自顧頹齡七十餘，久慚頑鈍費洪鑪。", "歸逢大老耆年會，衰朽形骸愧畫圖。"]'),
('740a47c1-01db-407d-aeb1-3cb84b058e6f','耆英會詩  其二','楚建中','宋','宋诗','song-poetry','','[]','二相謨猷爛史編，諸公才業過前賢。',32,'全唐诗/poet.song.20000.json','["二相謨猷爛史編，諸公才業過前賢。", "好圖儀像傳來世，何事頑疎亦比肩。"]'),
('890d988b-e5fa-46c3-bb64-4be8a9bfa695','次吳江驛','馬彝','宋','宋诗','song-poetry','','[]','蘭舟東下泊吳江，暫寄郵亭看渺茫。',64,'全唐诗/poet.song.20000.json','["蘭舟東下泊吳江，暫寄郵亭看渺茫。", "魯望舊蹤追感歎，季鷹前事入思量。", "當軒雨過峯巒秀，隔岸風來橘柚香。", "散髮未能歸未遂，鱸魚時節負秋光。"]'),
('88f10214-25f2-4a90-ab4e-d40902b2a8aa','題濮公仙洞','柳伯達','宋','宋诗','song-poetry','','[]','昔人何人占弋山，波光嵐翠照淮灣。',64,'全唐诗/poet.song.20000.json','["昔人何人占弋山，波光嵐翠照淮灣。", "佩蘭隠者今何在，煉石仙人去不還。", "綠水渡頭空自急，白雲嶺上至今閑。", "高峰張令祠邊望，古息荒城半草間。"]'),
('06b8495d-3ee5-4af5-ad15-c40c396334c4','題峽山寺','郭昌','宋','宋诗','song-poetry','','[]','猿豈爲妖恪自迷，世間那有倘來妻。',32,'全唐诗/poet.song.20000.json','["猿豈爲妖恪自迷，世間那有倘來妻。", "裂衣心痛從前悔，恪不如猿反噬臍。"]'),
('4e123cdf-3058-4cc1-883e-66387e4e177d','留題靈巖','何約','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','天下名藍稱四絕，靈巖雄與岱山連。',32,'全唐诗/poet.song.20000.json','["天下名藍稱四絕，靈巖雄與岱山連。", "古淵堂上憑欄處，似在樓巖太華邊。"]'),
('ee6553a1-b213-435d-954b-6b01358e9d93','臨安石','元居中','宋','宋诗','song-poetry','','[]','人久衆所憎，物久衆所惜。',24,'全唐诗/poet.song.20000.json','["人久衆所憎，物久衆所惜。", "爲負磊落姿，不隨寒暑易。"]'),
('609b9d7d-8833-45aa-bcad-baa36ddae8cf','風水洞','元居中','宋','宋诗','song-poetry','','[]','二洞標奇石，連巖葺字新。',96,'全唐诗/poet.song.20000.json','["二洞標奇石，連巖葺字新。", "凉生清桂曉，暖漲碧桃春。", "閑擁東方騎，來尋北隴人。", "破雲拖蠟屐，琢句寫霜筠。", "譚劇頻飛屑，歌長益落塵。", "爲探瓊巘勝，不記玉觴巡。", "下客慚長穎，高筵飲德醇。", "追隨到峯頂，疑化九霄身。"]'),
('7e2696e0-9c80-4217-9f53-81deb95080e7','上祖無擇','元居中','宋','宋诗','song-poetry','','[]','洞蔽深雲遠俗塵，山中曾未識朱輪。',32,'全唐诗/poet.song.20000.json','["洞蔽深雲遠俗塵，山中曾未識朱輪。", "自從白傅來游後，三百年間又一人。"]'),
('c59142cb-161f-4bef-881d-7258787b7e01','琅邪山清風亭','張澤','宋','宋诗','song-poetry','','[]','滁陽承乏多閒暇，時入山中訪道安。',32,'全唐诗/poet.song.20000.json','["滁陽承乏多閒暇，時入山中訪道安。", "何處披襟却煩暑，清風亭上久盤還。"]'),
('269d345c-6130-4525-ba6e-ce8eebae010a','別信州席上作','楊察','宋','宋诗','song-poetry','','[]','十二天辰數，今宵席客盈。',48,'全唐诗/poet.song.20000.json','["十二天辰數，今宵席客盈。", "位如星占野，人若月分卿。", "極醉巫峰倒，聊吟嶰琯清。", "他年爲舜牧，協力濟蒼生。"]'),
('3556f6fb-e14e-4d1f-9d19-aefd589761b0','再入臺作','馬遵','宋','宋诗','song-poetry','','[]','連蹇多年心欲灰，厭爲俗吏走塵埃。',64,'全唐诗/poet.song.20000.json','["連蹇多年心欲灰，厭爲俗吏走塵埃。", "豈知黄紙新書下，還送青氊舊物來。", "武騎强爲終不意，河南難問愧無才。", "一麾早晚江湖去，相與持螯共酒盃。"]'),
('dff5bbe8-60fb-4c62-88b0-649020163c05','次韻經略吳及石門洞','劉牧','宋','宋诗','song-poetry','','[]','諫紙空箱後，高牙拂斷霓。',120,'全唐诗/poet.song.20000.json','["諫紙空箱後，高牙拂斷霓。", "還符翠洲夢，來見石門題。", "架竹生新徑，誅茅得舊蹊。", "陰崖走別洞，陽嶺带回溪。", "吟桂人非隠，逢花客自迷。", "虛中存納受，絕壁阻攀躋。", "地遠饒征戍，君來息鼓鼙。", "吏閑眠麂鹿，民樂戲鳧鷖。", "勝事時相遇，芳樽手屢携。", "清風與詩句，留與昔賢齊。"]'),
('c5e55b25-274f-4f44-b3dc-0249d09605a7','和歐陽永叔送龍學赴陝府酌飲贈別','吳奎','宋','宋诗','song-poetry','','[]','陝郡太守來告別，翰林主人爲置酒。',144,'全唐诗/poet.song.20000.json','["陝郡太守來告別，翰林主人爲置酒。", "急喚尋常詩酒伴，要誇此會爲難有。", "席間騁辯何快哉，恰似縱丸臨坂走。", "詼諧往往笑絕倒，同異時時瞋掉手。", "共憐奇偉出塵冥，却欲昏愚浪枯朽。", "從來豪舉必兼包，擊節齊侯容九九。", "我實鄙鈍不曉事，賢公采取寧非偶。", "擇之文行衆所珍，昔日乘槎犯牛斗。", "年將老矣又分符，莫遣安排用莊叟。"]'),
('db0550fa-630f-45c1-90b0-7c38b6742f68','泛五雲谿遊照湖歸','吳奎','宋','宋诗','song-poetry','','[]','樵風漾歸舟，飄然一葉輕。',96,'全唐诗/poet.song.20000.json','["樵風漾歸舟，飄然一葉輕。", "曲岸忽超逸，遠山回抱明。", "幽禽淡容與，荷芰相低傾。", "野田足收穫，邨叟時逢迎。", "驩言無物役，得我游覽情。", "日脚暮雲起，湖面蓼煙生。", "秋光湛空碧，彷彿見重城。", "候吏津亭外，稍聞笳鼓聲。"]'),
('42b6f457-1e70-46c6-9a4b-44a965b117b8','遊雲門寺留題靈運上人房','吳奎','宋','宋诗','song-poetry','','[]','雲門入雲深，樹密山轉幽。',120,'全唐诗/poet.song.20000.json','["雲門入雲深，樹密山轉幽。", "谿亭脩竹裏，激激玉泉流。", "仁智所遐想，古今爲勝遊。", "我乘休沐至，窮覽殊難周。", "金碧樓殿午，寒香松桂秋。", "清風動高興，飄越不可收。", "禪師索題詩，捉筆事冥搜。", "欲速馳思遠，頃刻歷九州。", "象外有真物，惝怳難爲求。", "徒形陳熟言，羞澀爲爾留。"]'),
('acaaa904-ec0f-4f48-8fb0-c2b3f3db09bf','泛照湖遊天章','吳奎','宋','宋诗','song-poetry','','[]','秦望奇峰北，天章野寺東。',120,'全唐诗/poet.song.20000.json','["秦望奇峰北，天章野寺東。", "石橋跨驚瀨，雲屋麗層穹。", "片段磨礲密，高低結構雄。", "盤基深鑿岸，飛勢聳凌空。", "迥却熙蒸日，虛含自遠風。", "谿山形勝聚，川陸往來通。", "竹影摇軒外，松聲逼坐中。", "孤煙惹樵叟，輕浪濺漁翁。", "氣象清無比，登臨杳莫窮。", "直須圖畫看，安得入神工。"]'),
('3be72534-3ef6-49da-9052-120d64bc8481','泛照湖遊天章','吳奎','宋','宋诗','song-poetry','','[]','愁霖不肯已，陰結彌二旬。',288,'全唐诗/poet.song.20000.json','["愁霖不肯已，陰結彌二旬。", "吾遊欲及時，秉燭出城門。", "泛泛一舫航，密坐環親賓。", "爽氣忽侵袂，重雲稍逡巡。", "俄頃萬里晴，鬼魅伏清晨。", "日光溜水態，照灼無涯垠。", "輕煙緬以沒，微風飈然振。", "菰蒲動幽響，撥刺驚潛鱗。", "浮沈戲鷗鷺，蕩漾開萍蘋。", "榜人發櫂歌，漁翁理罾緡。", "激越自成態，瀟灑何其真。", "清輝不可狀，野思徒紛紜。", "弭棹山之阿，行行問吾民。", "莓苔粘側逕，馬足絕纖塵。", "青谿曲折度，茅屋經過頻。", "川涂斗開闊，夷路夾松筠。", "右轉聳雲構，廣除礱翠珉。", "佛殿爍金碧，標牓自玉宸。", "脩廊盤磴道，等級華堂新。", "最後敞高閣，扃藏帝室珍。", "冥心一薰拂，璨璨羅星辰。", "大哉三聖筆，天縱妙入神。", "名家數幾百，較古誰爲鄰。", "山頭見塔影，樹杪排嶙峋。"]'),
('18b0e680-7e81-4369-8833-831c33ae5221','句','吳奎','宋','宋诗','song-poetry','','[]','奚車一牛駕，朝馬兩人騎。',12,'全唐诗/poet.song.20000.json','["奚車一牛駕，朝馬兩人騎。"]'),
('996b1277-8842-4811-a383-dca834cb47b3','耆英會詩','王謹言','宋','宋诗','song-poetry','','[]','相印貂冠粲六符，華顛高會侍臣俱。',64,'全唐诗/poet.song.20000.json','["相印貂冠粲六符，華顛高會侍臣俱。", "不將官職誇鄉里，唯尚年齡入畫圖。", "履道清歡追故事，竚瞻陰德見訏謨。", "叨陪几杖真榮觀，珪璧叢中問珷玞。"]'),
('0f2870e8-4f80-47ab-973e-6bc0cf4f7c66','山房  其一','毛維瞻','宋','宋诗','song-poetry','','[]','東晉仙人借舊山，定應天意許公閑。',32,'全唐诗/poet.song.20000.json','["東晉仙人借舊山，定應天意許公閑。", "郡人欲問使君處，笑指峰巒紫翠間。"]'),
('23d825d7-1c67-40c2-86b5-306d7d331a4f','山房  其二','毛維瞻','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','樓上青山繞四垂，畫橋百步引失扉。',32,'全唐诗/poet.song.20000.json','["樓上青山繞四垂，畫橋百步引失扉。", "落成當與公同上，一看長江白練微。"]'),
('8ffcb448-6662-4f25-acf0-312dd3686111','白雲莊','毛維瞻','宋','宋诗','song-poetry','','[]','歸去携家住白雲，雲中猿鶴許同羣。',64,'全唐诗/poet.song.20000.json','["歸去携家住白雲，雲中猿鶴許同羣。", "陶公酒後詩偏好，疏傅金餘客屢醺。", "芒屩潛行逐漁釣，壺將時出勞耕耘。", "即看人世應微笑，未熟黄粱晝夢紛。"]'),
('891fee36-c9f4-434e-af50-fa45c7c287f3','詩一首','毛維瞻','宋','宋诗','song-poetry','','[]','峭拔神仙宅，來尋煙水重。',72,'全唐诗/poet.song.20000.json','["峭拔神仙宅，來尋煙水重。", "深應盤九地，高不讓羣峰。", "瞻對奇勝畫，捫緣直豈容。", "幾是蓮葉下，終古鮮紋封。", "往事雲難問，無言路有蹤。", "橋山杳何處，侍從此攀龍。"]'),
('61075103-f9df-48c5-bd4b-a5ead8a39843','觀棋大吟','邵雍','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','人有精游藝，予嘗觀弈棋。',288,'全唐诗/poet.song.20000.json','["人有精游藝，予嘗觀弈棋。", "筭餘知造化，著外見幾微。", "好勝心無已，爭先意不低。", "當人盡賓主，對面如蠻夷。", "財利激于衷，喜怒見于頄。", "生殺在于手，與奪指于頤。", "戾不殊冰炭，和不侔塤箎。", "義不及朋友，情不通夫妻。", "珠玉出懷袖，龍蛇走肝脾。", "金湯起樽俎，劔戟交幈幃。", "白晝役鬼神，平地蟠蛟螭。", "空江響雷雹，陸海誅鯨鯢。", "寒暑同舒慘，昏明共蔽虧。", "山河燦於地，星斗會璇璣。", "因覩輸贏勢，翻驚寵辱蹊。", "高卑易裁制，返覆難拘羈。", "心迹既一判，利害不兩提。", "卷舒當要會，取捨在須斯。", "智者傷于詐，信者失于椎。", "真僞之相雜，名實之都隳。", "得者失之本，福爲禍之梯。", "乾坤支作訟，離坎變成睽。", "弧矢相凌犯，言辭共詆欺。", "何嘗無勝負，未始絕興衰。"]'),
('db89a2be-2fe1-4e5a-9427-10c6ab924af2','過溫寄鞏縣宰吳秘丞','邵雍','宋','宋诗','song-poetry','','[]','風軟玉溪騰醉騎，花繁石窟漾歌舟。',32,'全唐诗/poet.song.20000.json','["風軟玉溪騰醉騎，花繁石窟漾歌舟。", "相望咫尺仙凡隔，不得同陪三月遊。"]'),
('ccf9aa3b-d8a0-4eed-b582-3ab2d3d5dc18','新居成呈劉君玉殿院','邵雍','宋','宋诗','song-poetry','','[]','履道坊南竹徑脩，綠楊陰裏水分流。',64,'全唐诗/poet.song.20000.json','["履道坊南竹徑脩，綠楊陰裏水分流。", "衆賢買得澄心景，獨我居爲養志秋。", "若比陳門成已僣，苟陪顔巷亦堪憂。", "無端風雨雖狂暴，不信能凌沈隠侯。"]'),
('e10e3e51-d9a3-4ed9-82d7-aed8bd975263','寄謝三城太守韓子華舍人','邵雍','宋','宋诗','song-poetry','','[]','洛陽自爲都，二千有餘年。',288,'全唐诗/poet.song.20000.json','["洛陽自爲都，二千有餘年。", "舉步圖籍中，開目今古間。", "西北岌宮殿，東南傾山川。", "照人伊洛清，迎門嵩少寒。", "水竹最佳處，履道之南偏。", "下有幽人室，一徑通柴關。", "蓬蒿隠其居，藜藿品其飡。", "上親下妻子，厚薄隨其緣。", "人雖不堪憂，己亦不改安。", "閱史悟興亡，探經得根源。", "有客謂予曰，子獨不通權。", "清朝能用才，聖主正求賢。", "道德與仁義，不徒爲空言。", "功業貴及時，何不求美官。", "上食天子祿，下拯蒼生殘。", "通衢張大第，負郭廣良田。", "朱門爛金紫，青樓繁管絃。", "外廐列肥駿，後庭羅纖妍。", "入則坐虛堂，出則乘華軒。", "冠劍何燁燁，氣體自舒閑。", "高談天下事，廣坐生晴煙。", "人莫敢仰視，屏息候其顔。", "此所謂男子，志可得而觀。", "又何必自苦，形容若枯鱣。"]'),
('cc30724f-2034-4727-a0a1-0b9e7377f893','依韻和張元伯職方歲除','邵雍','宋','宋诗','song-poetry','','[]','及正四十六，老去恥無才。',48,'全唐诗/poet.song.20000.json','["及正四十六，老去恥無才。", "殘臘方迴律，新春又起灰。", "非唯忘利祿，況復外形骸。", "白髮已過半，光陰任自催。"]'),
('265f8727-e202-4785-b61a-b0c5221a86aa','謝鄭守王密學惠酒','邵雍','宋','宋诗','song-poetry','','[]','堂堂大府來新酒，密密小園開好花。',32,'全唐诗/poet.song.20000.json','["堂堂大府來新酒，密密小園開好花。", "此日飲之紅樹下，還驚不稱野人家。"]'),
('abbe2973-0b9a-4812-9e77-3bfeb1656327','小園逢春','邵雍','宋','宋诗','song-poetry','','[]','小隠園中百本花，各隨紅紫發新芽。',32,'全唐诗/poet.song.20000.json','["小隠園中百本花，各隨紅紫發新芽。", "東君見借陽和力，不減公侯富貴家。"]'),
('b7a2acfc-f386-4a64-a09d-7cd3d9ece6a6','和張二少卿丈白菊','邵雍','宋','宋诗','song-poetry','','[]','清淡曉凝霜，宜乎殿顥商。',48,'全唐诗/poet.song.20000.json','["清淡曉凝霜，宜乎殿顥商。", "自知能潔白，誰念獨芬芳。", "豈爲瓊無艷，還驚雪有香。", "素英浮玉液，一色混瑶觴。"]'),
('12e11871-9ef7-4ae2-8c61-96fe69646db4','生男吟','邵雍','宋','宋诗','song-poetry','','[]','我本行年四十五，生男方始爲人父。',64,'全唐诗/poet.song.20000.json','["我本行年四十五，生男方始爲人父。", "鞠育教誨誠在我，壽夭賢愚繫於汝。", "我若壽命七十歲，眼前見汝二十五。", "我欲願汝成大賢，未知天意肯從否。"]'),
('eaed0f01-7779-4f59-84fd-cc2856bc511a','閑吟四首  其一','邵雍','宋','宋诗','song-poetry','','[]','平生如仕官，隨分在風波。',48,'全唐诗/poet.song.20000.json','["平生如仕官，隨分在風波。", "所損無紀極，所得能幾何。", "既乖經世慮，尚可全天和。", "罇中有酒時，且飲復且歌。"]'),
('33137d16-f455-4fe2-a7ef-438877eda414','閑吟四首  其二','邵雍','宋','宋诗','song-poetry','','[]','予年四十七，已甫知命路。',48,'全唐诗/poet.song.20000.json','["予年四十七，已甫知命路。", "豈意天不絕，生男始爲父。", "且免散琴書，敢望大門戶。", "萬事盡如此，何用過憂懼。"]'),
('b302621a-50a7-4c80-966b-411a8a219bc0','閑吟四首  其三','邵雍','宋','宋诗','song-poetry','','[]','居洛八九載，投心唯二三。',48,'全唐诗/poet.song.20000.json','["居洛八九載，投心唯二三。", "相逢各白首，共坐多清談。", "人事已默定，世情曾久諳。", "酒行勿相逼，徐得奉醺酣。"]'),
('f2b12f77-c6f7-4bbf-b729-aeb93369cc0f','閑吟四首  其四','邵雍','宋','宋诗','song-poetry','','[]','欲有一瓢樂，曾無二頃田。',48,'全唐诗/poet.song.20000.json','["欲有一瓢樂，曾無二頃田。", "丹誠未貫日，白髮已華顛。", "雲意寒尤淡，松心老益堅。", "年來踈懶甚，時憶舊林泉。"]'),
('9912f60e-0a1d-46c7-85e5-79dcc708d1d5','和張少卿丈再到洛陽','邵雍','宋','宋诗','song-poetry','','[]','當年曾任青春客，今日重來白雪翁。',32,'全唐诗/poet.song.20000.json','["當年曾任青春客，今日重來白雪翁。", "今日當年已一世，幾多興替在其中。"]'),
('3366c3d9-5830-4a28-8c8a-d696d901a828','高竹八首  其一','邵雍','宋','宋诗','song-poetry','','[]','高竹百餘挺，固知爲予生。',48,'全唐诗/poet.song.20000.json','["高竹百餘挺，固知爲予生。", "忽忽有所得，時時閑遶行。", "自信或未至，自知或未明。", "竊比于古人，不能無愧情。"]'),
('ca56bfce-bc8b-4276-81a0-84bdb186352f','高竹八首  其二','邵雍','宋','宋诗','song-poetry','','[]','高竹臨清溝，軒小亦且幽。',48,'全唐诗/poet.song.20000.json','["高竹臨清溝，軒小亦且幽。", "光陰雖屬夏，風露已驚秋。", "月色林間出，泉聲砌下流。", "誰知此夜情，邈矣不能收。"]'),
('7e741c51-a010-4255-87d5-2947cc867e6b','高竹八首  其三','邵雍','宋','宋诗','song-poetry','','[]','高竹已可愛，況在垂楊下。',48,'全唐诗/poet.song.20000.json','["高竹已可愛，況在垂楊下。", "幽人無軒冕，得此自可詫。", "枉尺既不能，括囊又何謝。", "賈生若知此，慟哭亦自罷。"]'),
('cb35a904-4a52-4780-9246-670421b46ac6','高竹八首  其四','邵雍','宋','宋诗','song-poetry','','[]','高竹碧相倚，自能發餘清。',48,'全唐诗/poet.song.20000.json','["高竹碧相倚，自能發餘清。", "時時微風來，萬葉同一聲。", "道污得夷理，物虛含遠情。", "階前閑步人，意思何清平。"]'),
('74d05389-f794-47a8-b7d2-209d32e1a01c','高竹八首  其五','邵雍','宋','宋诗','song-poetry','','[]','高竹如碧幢，翠柳苦低蓋。',48,'全唐诗/poet.song.20000.json','["高竹如碧幢，翠柳苦低蓋。", "幽人有軒榻，日夜與之對。", "宇靜覺神開，景閑喜真會。", "與其喪吾真，孰若從吾愛。"]'),
('faeb596a-a490-4e5e-8de4-96efead4e40a','高竹八首  其六','邵雍','宋','宋诗','song-poetry','','[]','高竹雜高梧，還驚秋節初。',48,'全唐诗/poet.song.20000.json','["高竹雜高梧，還驚秋節初。", "晚凉尤可喜，舊帙亦宜舒。", "池閣輕風裏，園林晚景餘。", "人生有此樂，何必較錙銖。"]'),
('d6b8061b-2aa5-4f0d-95c2-8f6cac6329c3','高竹八首  其七','邵雍','宋','宋诗','song-poetry','','[]','高竹數十尺，仍在高花上。',48,'全唐诗/poet.song.20000.json','["高竹數十尺，仍在高花上。", "柴門晝不開，青碧日相向。", "非止身休逸，是亦心夷曠。", "能知閑之樂，自可敵卿相。"]'),
('2d116e39-acca-4810-aba8-155c65844c11','高竹八首  其八','邵雍','宋','宋诗','song-poetry','','[]','高竹逾冬青，四月方易葉。',48,'全唐诗/poet.song.20000.json','["高竹逾冬青，四月方易葉。", "抽萌如止戈，解籜若脫甲。", "脩靜信可愛，遶行不知匝。", "嗟哉凡草木，徒自費鋤鍤。"]'),
('02bfff22-5e15-43ff-8c84-7a7c7ff2a121','秋日飲鄭州宋園示管城簿周正叔','邵雍','宋','宋诗','song-poetry','','[]','二都相去四百里，中有名園屬宋家。',64,'全唐诗/poet.song.20000.json','["二都相去四百里，中有名園屬宋家。", "古木參天羅劍戟，長藤垂地走龍蛇。", "我來遊日逢秋杪，君爲開筵對晚花。", "飲散竹軒微雨後，凌晨歸路起樓鴉。"]'),
('aa64392d-b530-4048-a1bd-e2d630e44978','重陽日再到共城百源故居','邵雍','宋','宋诗','song-poetry','','[]','故國逢佳節，登臨但可悲。',48,'全唐诗/poet.song.20000.json','["故國逢佳節，登臨但可悲。", "山川一夢外，風月十年期。", "白髮飄新鬢，黄花遶舊籬。", "鄉人應笑我，晝錦是男兒。"]'),
('e95d4fd0-1cc5-4899-843d-d01e1b1cf974','過陝','邵雍','宋','宋诗','song-poetry','','[]','吾祖道何光，二南分一方。',48,'全唐诗/poet.song.20000.json','["吾祖道何光，二南分一方。", "開周爲太保，封陝輔成王。", "歲月裝遼邈，山川造渺茫。", "世孫雖不肖，猶解憶甘棠。"]'),
('87ab2c2b-b176-495a-b3c7-da54af3ea629','題黄河','邵雍','宋','宋诗','song-poetry','','[]','誰言爲利多于害，我謂長渾未始清。',32,'全唐诗/poet.song.20000.json','["誰言爲利多于害，我謂長渾未始清。", "西至崑崙東至海，其間多少不平聲。"]'),
('b7d3e534-e7be-4924-892d-a784b08f4469','過潼關','邵雍','宋','宋诗','song-poetry','','[]','禁密因離亂，機閑爲太平。',48,'全唐诗/poet.song.20000.json','["禁密因離亂，機閑爲太平。", "山河雖設險，道德豈容爭。", "不究千一義，空傳百二名。", "遐方久無外，何復用雞鳴。"]'),
('9f1f5329-0db8-4ca0-b5dd-4aad8521f42d','題華山','邵雍','宋','宋诗','song-poetry','','["\u534e\u5c71"]','域中有五嶽，國家謹時祀。',48,'全唐诗/poet.song.20000.json','["域中有五嶽，國家謹時祀。", "華嶽居其一，作鎮雄西裔。", "唐號金天王，今封順聖帝。", "吁咈哉若神，僣竊同天地。"]'),
('f5b92255-b294-4a4a-948e-5f358b924942','宿華清宮','邵雍','宋','宋诗','song-poetry','','[]','天寶初六載，作宮于溫泉。',48,'全唐诗/poet.song.20000.json','["天寶初六載，作宮于溫泉。", "明皇與妃子，自此歲幸焉。", "紫閣清風裏，崇巒皓月前。", "柰何雙石甕，香溜尚涓涓。"]'),
('0b93b810-2722-4790-a8e8-5040a3d7f5bf','登朝元閣','邵雍','宋','宋诗','song-poetry','','[]','繡嶺岌層巒，岧嶤十九盤。',48,'全唐诗/poet.song.20000.json','["繡嶺岌層巒，岧嶤十九盤。", "微微經雨後，杳杳出雲端。", "往事金輿遠，遺蹤玉像殘。", "至今臨渭水，依舊見長安。"]'),
('7f1407df-dabd-40c2-9aef-03dbbf5612ab','長安道路作','邵雍','宋','宋诗','song-poetry','','[]','長安道上何沾巾，古時道行今時人。',64,'全唐诗/poet.song.20000.json','["長安道上何沾巾，古時道行今時人。", "不知寒暑與朝暮，車輪馬跡常轔轔。", "自是此土亦辛苦，雨作泥兮風爲塵。", "泥塵返復不知數，大雨大風無出門。"]'),
('a1d0e512-0a62-45e1-ab34-dfa52715301a','題留侯廟','邵雍','宋','宋诗','song-poetry','','[]','滅項興劉如覆手，絕秦昌漢若更棊。',64,'全唐诗/poet.song.20000.json','["滅項興劉如覆手，絕秦昌漢若更棊。", "卷舒天下坐籌日，鍛鍊心源辟穀時。", "黄石公傳皆是用，赤松子伴更何爲。", "如君才業求其比，今古相望不記誰。"]'),
('40711d1f-646a-4a7a-a70f-7dc6b7f89d9b','題淮陰侯廟十首  其一','邵雍','宋','宋诗','song-poetry','','[]','一身作亂宜從戮，三族全夷似少恩。',32,'全唐诗/poet.song.20000.json','["一身作亂宜從戮，三族全夷似少恩。", "漢道是時初雜霸，蕭何王佐殆非尊。"]'),
('b11cc8d4-6fee-4375-9c0e-98de8494934c','題淮陰侯廟十首  其二','邵雍','宋','宋诗','song-poetry','','[]','據立大功非不智，復貪王爵似專愚。',32,'全唐诗/poet.song.20000.json','["據立大功非不智，復貪王爵似專愚。", "造成四百年炎漢，纔得安寧反受誅。"]'),
('793dfdb4-e6f5-424a-aa73-f41b50f1c0d8','題淮陰侯廟十首  其三','邵雍','宋','宋诗','song-poetry','','[]','生身既得逢真主，立事何須作假王。',32,'全唐诗/poet.song.20000.json','["生身既得逢真主，立事何須作假王。", "誰謂禍階從此始，不宜迴首怨高皇。"]'),
('fc96f1e3-4814-49da-b282-27ce6982596d','題淮陰侯廟十首  其四','邵雍','宋','宋诗','song-poetry','','[]','一時韓信爲良犬，千古蕭何作霸臣。',32,'全唐诗/poet.song.20000.json','["一時韓信爲良犬，千古蕭何作霸臣。", "彼此并干名教罪，罪猶不逮謂斯人。"]'),
('fdd394c7-3e47-41d6-9114-d5b895a51fa4','題淮陰侯廟十首  其五','邵雍','宋','宋诗','song-poetry','','[]','韓信事劉元不叛，蕭何惑漢竟生疑。',32,'全唐诗/poet.song.20000.json','["韓信事劉元不叛，蕭何惑漢竟生疑。", "當初若聽蒯通語，高祖功名未可知。"]'),
('d691c752-7fd1-4103-8afa-c3165f2590e7','題淮陰侯廟十首  其六','邵雍','宋','宋诗','song-poetry','','[]','雖則有才兼有智，存亡是退處非真。',32,'全唐诗/poet.song.20000.json','["雖則有才兼有智，存亡是退處非真。", "五湖依舊煙波在，范蠡無人繼後塵。"]'),
('c889aedd-e510-48a8-af8f-c4bb60435b4d','題淮陰侯廟十首  其七','邵雍','宋','宋诗','song-poetry','','[]','若非韓信難除項，不得蕭何莫制韓。',32,'全唐诗/poet.song.20000.json','["若非韓信難除項，不得蕭何莫制韓。", "天下須知無一手，苟非高祖用蕭難。"]'),
('0111614a-6d52-4455-b122-2d433fa4c5df','題淮陰侯廟十首  其八','邵雍','宋','宋诗','song-poetry','','[]','漢家基定議功勳，異姓封王有五人。',32,'全唐诗/poet.song.20000.json','["漢家基定議功勳，異姓封王有五人。", "不似淮陰最雄傑，敢教根固又生秦。"]'),
('6ac487b6-a705-4c72-804d-ebeb56e46998','題淮陰侯廟十首  其九','邵雍','宋','宋诗','song-poetry','','[]','韓信恃功前慮寡，漢皇負德尚權安。',32,'全唐诗/poet.song.20000.json','["韓信恃功前慮寡，漢皇負德尚權安。", "幽囚必欲擒來斬，固要加諸甚不難。"]'),
('02706f4a-9270-4287-b53d-ee9a72884402','題淮陰侯廟十首  其一○','邵雍','宋','宋诗','song-poetry','','[]','若履暴榮須暴辱，既經多喜必多憂。',32,'全唐诗/poet.song.20000.json','["若履暴榮須暴辱，既經多喜必多憂。", "功成能讓封王印，世世長爲列土侯。"]'),
('dd67be7c-c78b-4bb5-8c66-55da479c07b6','鳳州郡樓上書所見','邵雍','宋','宋诗','song-poetry','','[]','楊柳垂青带，風動如飛蓋。',96,'全唐诗/poet.song.20000.json','["楊柳垂青带，風動如飛蓋。", "危樓思不窮，盡日閑相對。", "鳥去林自空，雲移山不礙。", "情隨雙燕還，意與孤鴻會。", "晚角時斷續，層崖遞明晦。", "殘陽掛踈紅，遠水生微瀨。", "塞目煙岑密，都城若天外。", "如何久客心，東望憑欄殺。"]'),
('f68c013a-7d3b-49e1-9ac1-061ae1a7b9eb','自鳳州還至秦川驛寄守倅薛姚二君','邵雍','宋','宋诗','song-poetry','','[]','歡聚九十日，迴首都如夢。',24,'全唐诗/poet.song.20000.json','["歡聚九十日，迴首都如夢。", "明月與清江，東軒又難共。"]'),
('56de772d-ec0b-4d5e-bac1-580baf6474f3','謝西臺張元伯雪中送詩','邵雍','宋','宋诗','song-poetry','','[]','洛城雪片大如手，爐中無火樽無酒。',32,'全唐诗/poet.song.20000.json','["洛城雪片大如手，爐中無火樽無酒。", "凌晨有人來打門，言送西臺詩一首。"]'),
('6f6e60e0-36dd-4503-a914-8ac1318c821d','送猗氏張主簿','邵雍','宋','宋诗','song-poetry','','[]','人間仕宦幾千里，堂上親闈別兩重。',32,'全唐诗/poet.song.20000.json','["人間仕宦幾千里，堂上親闈別兩重。", "須念鵬飛從此始，方今路險善求容。"]'),
('1b24db20-7464-4fee-9399-b4291f1b15ef','新正吟','邵雍','宋','宋诗','song-poetry','','[]','蘧瑗知非日，宣尼讀易年。',48,'全唐诗/poet.song.20000.json','["蘧瑗知非日，宣尼讀易年。", "人情止于是，天意豈徒然。", "立事情尤倦，思山興益堅。", "誰能同此志，相伴老伊川。"]'),
('ea51afd9-14f1-4668-96ee-753a2bcf3401','春遊五首  其一','邵雍','宋','宋诗','song-poetry','','[]','五嶺梅花迎臘開，三川正月賞寒梅。',64,'全唐诗/poet.song.20000.json','["五嶺梅花迎臘開，三川正月賞寒梅。", "相去萬里先一月，始知春色從南來。", "何人妙曲傳羌笛，盡日清香落酒盃。", "料得天涯未歸客，也應臨此重徘徊。"]'),
('db23947f-d024-45e0-b404-75b04d3188a8','春遊五首  其二','邵雍','宋','宋诗','song-poetry','','[]','洛城春色浩無涯，春色城東又復嘉。',64,'全唐诗/poet.song.20000.json','["洛城春色浩無涯，春色城東又復嘉。", "風力緩摇千樹柳，水光輕盪半川花。", "煙晴翡翠飛平岸，日暖鴛鴦下淺沙。", "不見君王西幸久，遊人但感鬢空華。"]'),
('9059b74f-49ac-4918-9c3e-52db8211b2ec','春遊五首  其三','邵雍','宋','宋诗','song-poetry','','[]','二月方當爛漫時，翠華未幸春無依。',64,'全唐诗/poet.song.20000.json','["二月方當爛漫時，翠華未幸春無依。", "綠楊陰裏尋芳遍，紅杏香中带醉歸。", "數片落花蝴蝶趁，一竿斜日流鸎啼。", "清樽有酒慈親樂，猶得階前戲綵衣。"]'),
('c1a17c10-b444-468f-a083-cdaff818bc0d','春遊五首  其四','邵雍','宋','宋诗','song-poetry','','[]','人間佳節唯寒食，天下名園重洛陽。',64,'全唐诗/poet.song.20000.json','["人間佳節唯寒食，天下名園重洛陽。", "金谷暖橫宮殿碧，銅駝睛合綺羅光。", "橋邊楊柳細垂地，花外鞦韆半出牆。", "白馬蹄輕草如剪，爛遊於此十年强。"]'),
('89659c22-7844-4059-9dba-331a69581558','春遊五首  其五','邵雍','宋','宋诗','song-poetry','','[]','三月牡丹方盛開，鼓聲多處是亭臺。',64,'全唐诗/poet.song.20000.json','["三月牡丹方盛開，鼓聲多處是亭臺。", "車中遊女自笑語，樓下看人閑往來。", "積翠波光摇帳幄，上陽花氣撲樽罍。", "西都風氣所宜者，草木空妖誰復哀。"]'),
('aaab625a-2114-423e-94e1-b623c9553384','竹庭睡起','邵雍','宋','宋诗','song-poetry','','[]','竹庭睡起閑隠几，悠悠夏日光景長。',64,'全唐诗/poet.song.20000.json','["竹庭睡起閑隠几，悠悠夏日光景長。", "鸎方引雛教嫩舌，杏正垂實裝輕黄。", "雨滴幽夢時斷續，風翻遠思還飛揚。", "小渠弄水綠陰密，迴首又且數日强。"]'),
('14af8ac1-90cf-4fd4-b0c4-179514444ed1','秋遊六首  其一','邵雍','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','七月芙蕖正爛開，東南園近日徘徊。',64,'全唐诗/poet.song.20000.json','["七月芙蕖正爛開，東南園近日徘徊。", "有時風向池心過，無限香從水面來。", "罨畫溪深方誤入，洞庭湖晚未成迴。", "坐來一霎蕭蕭雨，又送新凉到酒盃。"]'),
('7f49cfd6-1948-4df1-a364-c0ca1bbac2df','秋遊六首  其二','邵雍','宋','宋诗','song-poetry','','[]','先秋顥氣已潜生，洛邑方知節候平。',64,'全唐诗/poet.song.20000.json','["先秋顥氣已潜生，洛邑方知節候平。", "庭院乍凉入共喜，園林經雨氣尤清。", "迴舟伊水風微溜，緩轡天津月正明。", "自有臯夔分聖念，好將詩酒樂升平。"]'),
('ccc2ec01-c329-4895-96e9-9d89343b5994','秋遊六首  其三','邵雍','宋','宋诗','song-poetry','','[]','八月光陰未甚凄，松亭竹榭尤爲宜。',64,'全唐诗/poet.song.20000.json','["八月光陰未甚凄，松亭竹榭尤爲宜。", "况當晝夜初停處，正是炎凉得所時。", "明月入懷如有意，好風迎面似相知。", "閑人歌詠自怡悅，不管朝廷不採詩。"]'),
('ce999ee7-628d-4da9-b036-12a2d4d7d8f2','秋遊六首  其四','邵雍','宋','宋诗','song-poetry','','[]','家住南城水竹涯，乘秋行樂未嘗虧。',64,'全唐诗/poet.song.20000.json','["家住南城水竹涯，乘秋行樂未嘗虧。", "輕寒氣候我自愛，半醉光陰人莫知。", "信馬天街微雨後，憑欄僧閣晚晴時。", "十年美景追尋遍，好向風前摘白髭。"]'),
('3389050d-b581-4499-8a40-929e8065ffab','秋遊六首  其五','邵雍','宋','宋诗','song-poetry','','[]','九月風光雖已暮，中州景物未全衰。',64,'全唐诗/poet.song.20000.json','["九月風光雖已暮，中州景物未全衰。", "眼觀秋色千萬里，手把黄花三兩枝。", "美酒易消閑歲月，青銅休照老容儀。", "若言必使他人信，瀝盡丹誠誰肯知。"]'),
('4db4eaa1-a88d-427c-b07b-d4fcb2983f94','秋遊六首  其六','邵雍','宋','宋诗','song-poetry','','[]','霜天寥落思無窮，不奈樓高逼望中。',64,'全唐诗/poet.song.20000.json','["霜天寥落思無窮，不奈樓高逼望中。", "四面溪山徒滿目，九秋宮殿自危空。", "雲橫遠嶠千尋直，霞亂斜陽數縷紅。", "無限傷情言不到，共誰開口向西風。"]'),
('9929c8dc-7905-4b34-ae5b-cfba936d8caa','秋日即事','邵雍','宋','宋诗','song-poetry','','[]','鳥聲亂晝林，爲誰苦驅逼。',48,'全唐诗/poet.song.20000.json','["鳥聲亂晝林，爲誰苦驅逼。", "蟲聲亂夜庭，爲誰苦勞役。", "嗟哉彼何短，一槩無休息。", "借問此何長，兩能忘語默。"]'),
('ea113e36-3fef-4da9-9b63-44f4e04c6773','商山道中作','邵雍','宋','宋诗','song-poetry','','[]','十舍到商顔，雖遥不甚艱。',48,'全唐诗/poet.song.20000.json','["十舍到商顔，雖遥不甚艱。", "東西遡洛水，表裏看秦山。", "身在煙霞外，心存人子間。", "庭闈況非遠，自可指期還。"]'),
('43f89d1c-e310-41a8-8525-87497cea2d35','和商洛章子厚長官早梅  其一','邵雍','宋','宋诗','song-poetry','','[]','只應王母專輕巧，剪碎天邊亂白雲。',32,'全唐诗/poet.song.20000.json','["只應王母專輕巧，剪碎天邊亂白雲。", "無限清香與清艷，樽前飫享盡輸君。"]'),
('02b03e42-3cf1-4ac4-b77e-41394a882be3','和商洛章子厚長官早梅  其二','邵雍','宋','宋诗','song-poetry','','[]','梅覆春溪水遶山，梅花爛漫水潺湲。',32,'全唐诗/poet.song.20000.json','["梅覆春溪水遶山，梅花爛漫水潺湲。", "南秦地暖開仍早，比至春初已數番。"]'),
('b5b7da05-6841-4231-a185-e80e535513af','和商洛章子厚長官早梅  其三','邵雍','宋','宋诗','song-poetry','','[]','群芳萬品遞相催，若說高標獨有梅。',32,'全唐诗/poet.song.20000.json','["群芳萬品遞相催，若說高標獨有梅。", "會得東君無別意，爲憐清淡使先開。"]'),
('98df7887-a831-4389-a0aa-e6efa74d5c85','和商洛章子厚長官早梅  其四','邵雍','宋','宋诗','song-poetry','','[]','霜扶清格高高起，風駕寒香遠遠留。',32,'全唐诗/poet.song.20000.json','["霜扶清格高高起，風駕寒香遠遠留。", "太守多情客多感，金樽倒盡是良籌。"]'),
('17cd4223-fbe9-4313-bd4f-d6e474565d5e','商山旅中作','邵雍','宋','宋诗','song-poetry','','[]','殘火昏燈夜正沉，默思前事擁寒衾。',32,'全唐诗/poet.song.20000.json','["殘火昏燈夜正沉，默思前事擁寒衾。", "霜天皎月雖千里，不抵傷時一寸心。"]'),
('75fbdc17-f8b1-4228-890e-ea09ede0085e','和商守宋郎中早梅','邵雍','宋','宋诗','song-poetry','','[]','山南地似嶺南溫，臘月梅開已浹辰。',96,'全唐诗/poet.song.20000.json','["山南地似嶺南溫，臘月梅開已浹辰。", "恥與百花爭俗態，獨殊群艷占先春。", "角中飄去凄於骨，笛裏吹來妙入神。", "秀額粧殘黏素粉，畫梁歌暖起輕塵。", "宰君惜艷獻州牧，太守分香及野人。", "手把數枝重疊嗅，忍教芳酒不濡唇。"]'),
('b80390c6-a4d2-4207-bed1-25ec2f36e466','和人放懷','邵雍','宋','宋诗','song-poetry','','[]','爲人雖未有前知，富貴功名豈力爲。',64,'全唐诗/poet.song.20000.json','["爲人雖未有前知，富貴功名豈力爲。", "滌蕩襟懷須是酒，優游情思莫如詩。", "況當水竹雲山地，忍負風花雪月期。", "男子雄圖存用捨，不開眉笑待何時。"]'),
('f77a7fc5-e9d3-4127-a19f-fb7138d166e6','和商守登樓看雪','邵雍','宋','宋诗','song-poetry','','[]','西樓賞雪眼偏明，次第身疑在水晶。',64,'全唐诗/poet.song.20000.json','["西樓賞雪眼偏明，次第身疑在水晶。", "千片萬片巧粧地，半舞半飛斜犯楹。", "形如玉屑依還碎，體似楊花又更輕。", "誰謂天涯有羈客，一般對酒兩般情。"]'),
('ad352256-fb03-4de0-8f59-3b70b4b4074b','和商守西樓雪霽','邵雍','宋','宋诗','song-poetry','','[]','大雪初晴日半曛，高樓何惜上仍頻。',64,'全唐诗/poet.song.20000.json','["大雪初晴日半曛，高樓何惜上仍頻。", "數峰𡷾崒劍鋩立，一水縈紆冰樓新。", "崑嶺移歸都是玉，天河落後盡成銀。", "幽人自恨無佳句，景物從來不負人。"]'),
('0dc7eb9f-7b38-4b64-8413-9ba3ff7d02eb','和商守雪殘登樓','邵雍','宋','宋诗','song-poetry','','[]','殘雪已消冰已開，風光漸覺擁樓臺。',64,'全唐诗/poet.song.20000.json','["殘雪已消冰已開，風光漸覺擁樓臺。", "旅人未遂日邊去，春色又從天上來。", "況是樽中常有酒，豈堪嶺上却無梅。", "若非太守金蘭契，誰肯傾心重不才。"]'),
('585c4742-450a-42f8-9fc6-27a70f64ba22','和商守雪霽對月','邵雍','宋','宋诗','song-poetry','','[]','雪滿群山霜滿庭，光寒月碾一輪輕。',64,'全唐诗/poet.song.20000.json','["雪滿群山霜滿庭，光寒月碾一輪輕。", "羈懷殊少曏時樂，皓彩空多此夜明。", "竹近簾櫳饒碎影，風涵臺榭有餘清。", "恨無好句酬佳景，徒自凄凉夢不成。"]'),
('ef5749cf-d3c8-49d6-afe4-b8f4a9d6066f','和商守雪霽登樓','邵雍','宋','宋诗','song-poetry','','[]','百尺危樓小雪睛，晚來閑望逼人清。',64,'全唐诗/poet.song.20000.json','["百尺危樓小雪睛，晚來閑望逼人清。", "山橫暮靄高還下，水隔踈林淡復明。", "天際落霞千萬縷，風餘殘角兩三聲。", "此時此景真堪畫，只恐丹青筆未精。"]'),
('3d27e520-3902-4a51-9847-3da50ce78df7','旅中歲除','邵雍','宋','宋诗','song-poetry','','[]','比到明年無數刻，且令芳酒更斟回。',64,'全唐诗/poet.song.20000.json','["比到明年無數刻，且令芳酒更斟回。", "星杓建丑晦將盡，歲箭射人春又來。", "不用物情閑作梗，大都心緒已成灰。", "浮名更在浮雲外，瞬息光陰況便催。"]'),
('6d75eab0-3510-4acd-921f-1e44c12e779c','和商守新歲','邵雍','宋','宋诗','song-poetry','','[]','衰軀在旅逢新歲，因感平生鬢易凋。',64,'全唐诗/poet.song.20000.json','["衰軀在旅逢新歲，因感平生鬢易凋。", "飲罷襟懷還寂寞，歡餘情緒却無聊。", "望仙風月晴偏好，抹綠簾櫳夜正遥。", "對此塊然唯土木，降茲未始不魂銷。"]'),
('21368ddb-fd88-45a2-8117-dc84f148930f','追和王常侍登郡樓望山','邵雍','宋','宋诗','song-poetry','','[]','四賢當日此盤桓，千百年人尚厚顔。',64,'全唐诗/poet.song.20000.json','["四賢當日此盤桓，千百年人尚厚顔。", "天下有名難避世，胸中無物漫居山。", "事觀今古興亡後，道在君臣進退間。", "若藴奇才必奇用，不然須負一生閑。"]'),
('cb7e73a2-6e79-4154-a1db-36222d8f49af','題四皓廟四首  其一','邵雍','宋','宋诗','song-poetry','','[]','强秦失御血橫流，天下求君君不有。',32,'全唐诗/poet.song.20000.json','["强秦失御血橫流，天下求君君不有。", "正是英雄較逐時，未知鹿入何人手。"]'),
('e2d9f9fb-37e7-41e2-a507-866e2c640583','題四皓廟四首  其二','邵雍','宋','宋诗','song-poetry','','[]','灞上真人既已翔，四人相顧都無語。',32,'全唐诗/poet.song.20000.json','["灞上真人既已翔，四人相顧都無語。", "徐云天命自有歸，不若追蹤巢與許。"]'),
('886383e7-e73e-4135-9615-26d95904d18f','題四皓廟四首  其三','邵雍','宋','宋诗','song-poetry','','[]','漢皇傲物終難屈，太子卑辭方肯出。',32,'全唐诗/poet.song.20000.json','["漢皇傲物終難屈，太子卑辭方肯出。", "雖老猶能成大功，至今高義如星日。"]'),
('d04c8516-549e-4895-b12f-c43d59f49044','題四皓廟四首  其四','邵雍','宋','宋诗','song-poetry','','[]','田橫入海猶能得，商至長安百里强。',32,'全唐诗/poet.song.20000.json','["田橫入海猶能得，商至長安百里强。", "能使四人成美節，始知高祖是真王。"]'),
('31dedd8f-cfa4-417a-865e-843cf8f6c749','同安權縣林丞和余二首趁韵答之  其二','劉克莊','宋','宋诗','song-poetry','','[]','頗聞四境有絃聲，雉傍人飛犬不驚。',64,'全唐诗/poet.song.200000.json','["頗聞四境有絃聲，雉傍人飛犬不驚。", "在處棠陰應勿伐，等閑花判亦流行。", "掞庭子盍摛新藻，絕廩□□□落英。", "臺府諸公衡尺審，春風薦子有誰爭。"]'),
('872fa907-6f39-432e-a05a-ef25064908a8','擊壤圖','劉克莊','宋','宋诗','song-poetry','','[]','昔聞華胥與凈土，道釋寓言非目覩。',320,'全唐诗/poet.song.200000.json','["昔聞華胥與凈土，道釋寓言非目覩。", "此圖物色皆華人，太平氣象在裏許。", "競披野服裝束儉，旋瀉薄醪盆盎古。", "小姑丘嫂醜駭人，襁兒於背行傴僂。", "嶧桐泗磬未嘗試，手持蕢桴叩土鼓。", "當時四里安耕鑿，百姓焉知有官府。", "帝心猶不奈叢脞，欲以黄屋讓支父。", "烏乎放勳去已遠，朝野多事民愁苦。", "腐儒未暇論秦漢，齊榷魚鹽魯稅畝。", "舟鮫衡麓設譏禁，□若海神愁摘煮。", "計臣各操享上說，禍先及農次商賈。", "南鄰責米借斗斛，西舍誅帛空機杼。", "又聞更盼平□□，□□□□□官庾。", "何况防秋羽檄急，□□□□選材武。", "下鄉卒毒慘於蛇，坐衙官惡猛如虎。", "十家九亡村落靜，存者鬼質身繿縷。", "有時適野挑薺食，亦或逢場戴花舞。", "披圖茅屋晴窗下，偶然釋耒一摩拊。", "老農未知陶唐世，過予瞪視口譫語。", "暮年憔悴欲移鄉，借問此是何處所。"]'),
('9a4202c2-66cd-453e-94b4-887aec3d5752','乙卯歲除','劉克莊','宋','宋诗','song-poetry','','[]','井竈蕭條歲又殘，呼童掃地具杯盤。',64,'全唐诗/poet.song.200000.json','["井竈蕭條歲又殘，呼童掃地具杯盤。", "村舂堪笑生涯儉，家祭方知拜起難。", "衲壞蒙頭寒自若，燭燒見跋夜將闌。", "卧聞儺鼓鼕鼕過，不與諸孫作伴看。"]'),
('10be8894-ea22-4521-8a67-3629a15af5d7','丙辰元日','劉克莊','宋','宋诗','song-poetry','','[]','免騎朝馬趁南衙，五見空村換歲華。',64,'全唐诗/poet.song.200000.json','["免騎朝馬趁南衙，五見空村換歲華。", "旋遣厨人挑薺菜，虛勞座客頌椒花。", "不施鬰壘鈞編戶，雖飲屠蘇殿一家。", "二十宦游今七十，於身何損復何加。"]'),
('8484a34a-d2f6-4e99-baa9-22cd11365ef7','早去','劉克莊','宋','宋诗','song-poetry','','[]','早去天知無宦情，急攻人惎有虛名。',64,'全唐诗/poet.song.200000.json','["早去天知無宦情，急攻人惎有虛名。", "老而能學□□少，耄不加刑黜典輕。", "宿昔□□□未就，他時血碧尚難平。", "吾書豈必行今世，千□□□泣蒯生。"]'),
('2c103c70-1214-4763-b546-c751d2ad3656','門外  其一','劉克莊','宋','宋诗','song-poetry','','[]','門外沙鷗忽散羣，云何飛矢遠尋君。',64,'全唐诗/poet.song.200000.json','["門外沙鷗忽散羣，云何飛矢遠尋君。", "今身莫是前□幹，異世寧無後子雲。", "早歲多言生悔吝，暮年雙聵斷知聞。", "吾兒謹勿趨華藻，寧使班書議少文。"]'),
('c9c657be-f44f-4ee5-885e-81e610910f24','門外  其二','劉克莊','宋','宋诗','song-poetry','','[]','平生孤立懶隨群，未愛標名附五君。',64,'全唐诗/poet.song.200000.json','["平生孤立懶隨群，未愛標名附五君。", "投老病身甘碓□，無窮世事等輪雲。", "牛衣尚許尋初服，蠶室何堪續舊聞。", "玉座他年如記憶，安知不講禮融文。"]'),
('267d91da-edd7-40d9-bad8-b5b3891a1296','髮脫','劉克莊','宋','宋诗','song-poetry','','[]','髮脫紛紛不待爬，天將醜怪變妍華。',64,'全唐诗/poet.song.200000.json','["髮脫紛紛不待爬，天將醜怪變妍華。", "論爲城旦寧非怒，度作沙彌亦自佳。", "稚子笑翁簪柏葉，侍人諱老匣菱花。", "霜寒尤要泥丸暖，慙愧烏巾著意遮。"]'),
('e3d2d3fd-599a-4cae-8f69-eb5e0f01866b','憶昔','劉克莊','宋','宋诗','song-poetry','','[]','憶昔春郊共踏青，十人中已九凋零。',64,'全唐诗/poet.song.200000.json','["憶昔春郊共踏青，十人中已九凋零。", "溘先未遣隨朝露，殿後姑留作曙星。", "老眼蠅書猶可讀，微聾蟻閙不須聽。", "申公歲晚殊多事，白首番番詣漢廷。"]'),
('c0576e23-e949-4209-adca-b6873427992f','夜檢故書得孫季蕃詞有懷其人二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','貪聽譙更夜未眠，偶拈一卷向燈前。',64,'全唐诗/poet.song.200000.json','["貪聽譙更夜未眠，偶拈一卷向燈前。", "鳳簫按譜聲聲叶，鮫帕盛珠顆顆圓。", "洛叟曾規秦學士，蜀公晚喜柳屯田。", "江湖冷落詞人少，難起花翁傍酒邊。"]'),
('c5eb33f5-7a7a-41be-a480-f6c8585b4f28','夜檢故書得孫季蕃詞有懷其人二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','中年豪宕以詞行，醉墨淋漓一座傾。',64,'全唐诗/poet.song.200000.json','["中年豪宕以詞行，醉墨淋漓一座傾。", "昔競捧牋求少藴，今誰瀝酒吊耆卿。", "戴花起舞生無悶，薦菊爲肴死亦清。", "愁絕水仙祠畔路，萋萋原草幾枯榮。"]'),
('48df0268-ee4e-4d58-b679-31229ec4e22e','門前榕樹','劉克莊','宋','宋诗','song-poetry','','[]','木壽尤推櫟與樗，觀榕可信漆園書。',64,'全唐诗/poet.song.200000.json','["木壽尤推櫟與樗，觀榕可信漆園書。", "絕無翡翠來巢此，曾有蚍蜉欲撼渠。", "五鳳修成安用汝，萬牛力挽竟何如。", "山頭旦旦尋斤斧，擁腫全生計未疎。"]'),
('ca107e81-19c5-4be2-80e5-fae496040d5f','不寐二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','□□憑書作睡媒，夜窗危坐亂書堆。',64,'全唐诗/poet.song.200000.json','["□□憑書作睡媒，夜窗危坐亂書堆。", "甫從安樂窩移去，又向華胥國遣回。", "轉枕易如炊斗黍，據梧聽徹奏□□。", "□□□□東方白，仍取殘編更闔開。"]'),
('52402302-4f0d-42f2-998b-fc2ce6c5a39d','不寐二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','□□□□聽漏籌，簷聲得得伴春愁。',64,'全唐诗/poet.song.200000.json','["□□□□聽漏籌，簷聲得得伴春愁。", "殘燈似喚人開□，□□□□妾護篝。", "昔者鶴曾爲道士，俄而蜨又化莊周。", "要知夢覺皆虛幻，且撥寒爐起坐休。"]'),
('0557a56a-aa8e-4007-9f80-fa08a133dc5b','答赴補同人','劉克莊','宋','宋诗','song-poetry','','[]','莫厭春泥沒膝深，公卿皆拔自詞林。',64,'全唐诗/poet.song.200000.json','["莫厭春泥沒膝深，公卿皆拔自詞林。", "鵠袍肯在諸生列，蟲篆原非壯士心。", "山下久無吾屐齒，葦間忽聽子挐音。", "年來懶與人諛墓，欲贈劉叉未有金。"]'),
('9d5afab0-3d2c-4f59-8400-a908d43b425f','答上饒江濤','劉克莊','宋','宋诗','song-poetry','','[]','趙傁萬篇韓半之，江湖尤重兩賢詩。',32,'全唐诗/poet.song.200000.json','["趙傁萬篇韓半之，江湖尤重兩賢詩。", "不須負笈行千里，回首東家自有師。"]'),
('5a143ec7-949b-4c58-abcc-ce346dc0ec9b','挽徐吏部二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','仰鑽無篚實，平進少梯媒。',48,'全唐诗/poet.song.200000.json','["仰鑽無篚實，平進少梯媒。", "一鶴竟歸去，萬牛難挽回。", "空馳驛使召，不見省郎來。", "欲挂原頭劍，徐君安在哉。"]'),
('be1e6330-f459-4e2a-8cb4-35db14fcdf5d','挽徐吏部二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','昔過高陽里，宮牆許一窺。',48,'全唐诗/poet.song.200000.json','["昔過高陽里，宮牆許一窺。", "有樓藏冊子，無院處歌姬。", "羅雀閉窮巷，殺雞留晚炊。", "欲携船鯽往，道遠歎吾衰。"]'),
