('a81705cd-6fec-4bd1-bd19-2b890e6905e4','送黄□赴補','劉克莊','宋','宋诗','song-poetry','','[]','澤宮選新俊，鼓篋者雲從。',48,'全唐诗/poet.song.200000.json','["澤宮選新俊，鼓篋者雲從。", "此士堪穿札，同人學避鋒。", "朝家方教胄，天子必臨雍。", "去去飛潜異，雲山隔幾重。"]'),
('516adc2e-8cab-4057-8859-fc76f5087e66','北耗','劉克莊','宋','宋诗','song-poetry','','[]','京師渠敢洩邊機，北耗傳訛果是非。',64,'全唐诗/poet.song.200000.json','["京師渠敢洩邊機，北耗傳訛果是非。", "不見紅旗加露布，頗傳黄屋尚宵衣。", "南風不競師將老，春水方生虜必歸。", "何日靈臺真偃伯，更無一點戰塵飛。"]'),
('1eefbc70-821d-47d8-b93f-60df0e630b29','送趙司理歸永嘉','劉克莊','宋','宋诗','song-poetry','','[]','終歲閉柴荆，於君面尚生。',48,'全唐诗/poet.song.200000.json','["終歲閉柴荆，於君面尚生。", "客談花判健，民道李官清。", "方喜片言折，忽因微罪行。", "呂侯今秉鉞，羔雁必來迎。"]'),
('2db2216f-4bac-40b0-a16c-e932928ca6b7','送林寬夫父子','劉克莊','宋','宋诗','song-poetry','','[]','家學有淵源，傳之於艾軒。',48,'全唐诗/poet.song.200000.json','["家學有淵源，傳之於艾軒。", "三珠生老蚌，百鳥避雛鵷。", "同進誰爭賀，諸生定閉蕃。", "吾窮無可贐，握手贈君言。"]'),
('daf9d0eb-fcee-4fb6-a520-75519e803bc5','蜀捷','劉克莊','宋','宋诗','song-poetry','','[]','吠南初謂予堪侮，折北俄聞彼不支。',64,'全唐诗/poet.song.200000.json','["吠南初謂予堪侮，折北俄聞彼不支。", "撻覽果殲强弩下，鬼章有入檻車時。", "鍾繇捷表前無古，班固銘詩繼者誰。", "白髮腐儒心膽薄，一春林下浪攢眉。"]'),
('a2220565-779b-471d-8dcc-88abf513f76a','題周從龍養生圖','劉克莊','宋','宋诗','song-poetry','','[]','二圖心悟非師傳，子若通之可以仙。',32,'全唐诗/poet.song.200000.json','["二圖心悟非師傳，子若通之可以仙。", "欲向丹房供灑掃，老人爐竈壞多年。"]'),
('1d67dfc6-9882-486a-861a-e0027237c903','挽劉母王宜人二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','上壽今何憾，殷憂昔備嘗。',48,'全唐诗/poet.song.200000.json','["上壽今何憾，殷憂昔備嘗。", "分燈照鄰女，畫荻訓賢郎。", "石窌將開邑，隴阡自表岡。", "吾衰彤管廢，短些不成章。"]'),
('75343f24-533c-4a4a-9b00-a0bdb6cc08d1','挽劉母王宜人二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','原上車千兩，傾城出送終。',48,'全唐诗/poet.song.200000.json','["原上車千兩，傾城出送終。", "孟鄰懷舊好，防墓愴新封。", "鶴弔孤峯頂，牛鳴半驛中。", "會携芻一束，自往唁林宗。"]'),
('a4220980-fbd3-4009-b90f-4f4ba7d0516e','挽陳判官','劉克莊','宋','宋诗','song-poetry','','[]','□□□兵少，匹馬命如絲。',48,'全唐诗/poet.song.200000.json','["□□□兵少，匹馬命如絲。", "寶玦化爲燼，錦囊存者詩。", "無丹駐光景，有雪上鬚眉。", "坐閲君三世，如之何勿思。"]'),
('32ae1c8e-846d-422a-a2a4-12252d8cb041','送林推官','劉克莊','宋','宋诗','song-poetry','','[]','仕泉一郡共稱賢，今仕於漳想亦然。',64,'全唐诗/poet.song.200000.json','["仕泉一郡共稱賢，今仕於漳想亦然。", "非有珠犀堪自獻，若無梔蠟可爲妍。", "惡貪泉水平生潔，缺相輪尖早晚圓。", "若是尚書問村叟，衰殘恰似挂冠年。"]'),
('a4c373dd-0d1f-40c9-ac54-c1da119670e1','長溪陳夢雷携表弟趙君玉書相訪','劉克莊','宋','宋诗','song-poetry','','[]','□□外弟寄雙魚，細讀銀鈎卷復舒。',64,'全唐诗/poet.song.200000.json','["□□外弟寄雙魚，細讀銀鈎卷復舒。", "愧我挂冠方草奏，誤君載盾過茆廬。", "罷祠久絕支離粟，失勢誰看閑雜書。", "老畏春寒縮如鱉，坐妨沽酒摘園蔬。"]'),
('37148cc8-ed8f-43c7-8f2d-7f11cc8686a7','寄湯伯紀秘書','劉克莊','宋','宋诗','song-poetry','','[]','挽留天語極諄諄，願爲明時遠牧民。',64,'全唐诗/poet.song.200000.json','["挽留天語極諄諄，願爲明時遠牧民。", "倏去居然令國削，至清渾不怕州貧。", "斷無苞匪聊崇儉，纔用蒲鞭亦害仁。", "莫比尋常騎竹馬，使君元結一流人。"]'),
('6ebc65d3-6838-48f1-a929-55cb7ae58b9b','六言二首答陳天驥長短句  其一','劉克莊','宋','宋诗','song-poetry','','[]','天孫機上刀尺，雪兒口裏宮商。',28,'全唐诗/poet.song.200000.json','["天孫機上刀尺，雪兒口裏宮商。", "愧我元非郢客，恨君不識秦郎。"]'),
('370f997a-8a4f-40cb-b507-422b28e393e8','六言二首答陳天驥長短句  其二','劉克莊','宋','宋诗','song-poetry','','[]','書裙曾累逐客，墜釵能謗酔翁。',28,'全唐诗/poet.song.200000.json','["書裙曾累逐客，墜釵能謗酔翁。", "寧作經學博士，勿爲曲子相公。"]'),
('c101e9ee-b65a-45d8-9dcd-371f53c8c089','寄湯季庸侍郎','劉克莊','宋','宋诗','song-poetry','','[]','粵從紫氣度函關，更十年中幾賜環。',64,'全唐诗/poet.song.200000.json','["粵從紫氣度函關，更十年中幾賜環。", "一葉身輕歸去勇，六丁力盡挽來難。", "高情常寄紛華外，晚節全觀出處間。", "別後有書無寄處，聊憑小阮問平安。"]'),
('4922bc6f-4198-429b-a308-57b24b836782','送廣東憲','劉克莊','宋','宋诗','song-poetry','','[]','疏屢循牆詔屢催，繡衣安得更徘徊。',64,'全唐诗/poet.song.200000.json','["疏屢循牆詔屢催，繡衣安得更徘徊。", "直從象窟埋輪去，曾向龍墀折檻來。", "度嶺尊堯心未已，登臺叫舜首頻回。", "遥知行橐無南物，驛使歸時且寄梅。"]'),
('491d9cee-542e-4ad6-aa88-9d2b83a05df8','次韵趙克勤吏部六首  其一','劉克莊','宋','宋诗','song-poetry','','[]','甫里薄田汾曲廬，兒曹堪墾亦堪居。',32,'全唐诗/poet.song.200000.json','["甫里薄田汾曲廬，兒曹堪墾亦堪居。", "惟應水竹并風月，尚屬先生未屬渠。"]'),
('fd28fc58-2655-4cbc-8205-d7e276d053cd','次韵趙克勤吏部六首  其二','劉克莊','宋','宋诗','song-poetry','','[]','苔徑荒蕪薇架斜，樹頭吹盡不留些。',32,'全唐诗/poet.song.200000.json','["苔徑荒蕪薇架斜，樹頭吹盡不留些。", "奴欺主病慵鋤草，魔笑翁衰免散花。"]'),
('75a6a060-9e70-4c9c-8f46-d293d2b5f0e6','次韵趙克勤吏部六首  其三','劉克莊','宋','宋诗','song-poetry','','[]','有小林泉傍隠廬，無閒賓客訪村居。',32,'全唐诗/poet.song.200000.json','["有小林泉傍隠廬，無閒賓客訪村居。", "辛勤闢地添支徑，曲折通溪入淺渠。"]'),
('bbc3de41-1985-4d91-b32a-7ef1653bcc77','次韵趙克勤吏部六首  其四','劉克莊','宋','宋诗','song-poetry','','[]','籬邊雪畔影橫斜，應訝何郎太瘦些。',32,'全唐诗/poet.song.200000.json','["籬邊雪畔影橫斜，應訝何郎太瘦些。", "未可被渠瞞老眼，玉堂茅舍一般花。"]'),
('ba04eb72-d46d-41f1-9d0e-4f234128b0a7','次韵趙克勤吏部六首  其五','劉克莊','宋','宋诗','song-poetry','','[]','憶昔承明共直廬，而今寂寞賦閒居。',32,'全唐诗/poet.song.200000.json','["憶昔承明共直廬，而今寂寞賦閒居。", "戴花社裏聊容我，起草臺邊可欠渠。"]'),
('64ef9e4f-a2bc-4cdc-b582-bf751e01d23b','次韵趙克勤吏部六首  其六','劉克莊','宋','宋诗','song-poetry','','[]','兩鬢星星暮景斜，清狂減似向來些。',32,'全唐诗/poet.song.200000.json','["兩鬢星星暮景斜，清狂減似向來些。", "短供未至瓶無粟，妖夢皆因筆有花。"]'),
('b2a76bb3-fe57-4439-9244-56e10b2f452c','齒落','劉克莊','宋','宋诗','song-poetry','','[]','愈悲第二牙辭去，况我今虧第一牙。',64,'全唐诗/poet.song.200000.json','["愈悲第二牙辭去，况我今虧第一牙。", "嚼比牛飼衰畢現，豁如狗竇醜難遮。", "讌陳麟脯真虛設，庖進魚䐹不必嗟。", "歲晚魯公惟食粥，斷無仙骨飯胡麻。"]'),
('404b74a2-ea23-4624-97b9-573e21994038','四月八日三絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','徵在生夫子，摩耶育釋迦。',24,'全唐诗/poet.song.200000.json','["徵在生夫子，摩耶育釋迦。", "人人衣逢掖，箇箇著袈裟。"]'),
('314e38ea-6842-436a-9d07-ebc7dba757ef','四月八日三絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','九龍吐香水，茲事已千秋。',24,'全唐诗/poet.song.200000.json','["九龍吐香水，茲事已千秋。", "道是本無垢，年年浴未休。"]'),
('11da9dad-3371-4513-823c-2c63f52352f7','四月八日三絕  其三','劉克莊','宋','宋诗','song-poetry','','[]','生曾辭寶位，死却要金棺。',24,'全唐诗/poet.song.200000.json','["生曾辭寶位，死却要金棺。", "達士發冷笑，癡人被熱瞞。"]'),
('6d6c6e7e-cca8-441a-b526-dcaf0282b787','繩技','劉克莊','宋','宋诗','song-poetry','','[]','公卿黠似雙環女，權位危於百尺竿。',64,'全唐诗/poet.song.200000.json','["公卿黠似雙環女，權位危於百尺竿。", "身在半天貪進步，脚離實地駭傍觀。", "愈悲登華高難下，載却尋橦險不安。", "誰與貴人銘座右，等閑記取退朝看。"]'),
('e76d6000-1ee6-4f7f-a62f-8308420ac47b','荔枝二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','去年一顆難鑽核，今歲千林盡著花。',32,'全唐诗/poet.song.200000.json','["去年一顆難鑽核，今歲千林盡著花。", "老子有方能辟穀，純將絳雪代丹砂。"]'),
('6584318c-7c99-4b2e-996a-170ce6bc01dd','荔枝二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','寂寂南州少物華，有園池處只梅茶。',32,'全唐诗/poet.song.200000.json','["寂寂南州少物華，有園池處只梅茶。", "荔枝花發差平等，不問貧家富貴家。"]'),
('aa702a34-c67f-4d7a-a96f-ce22e670eb38','蒙恩復畀明道祠寄呈趙克勤吏部三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','曾對青藜漢閣中，天風吹散各西東。',32,'全唐诗/poet.song.200000.json','["曾對青藜漢閣中，天風吹散各西東。", "白頭重得爲僚友，同爲君王轄竹宮。"]'),
('6826e196-fe70-4166-9a2b-5ee4ded6bad8','蒙恩復畀明道祠寄呈趙克勤吏部三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','柱史荒壇僅有名，可能香火似承平。',32,'全唐诗/poet.song.200000.json','["柱史荒壇僅有名，可能香火似承平。", "却愁舊制難遥領，直要先生出按行。"]'),
('3ce822ab-1b43-4b7d-bc62-895f99928ed8','蒙恩復畀明道祠寄呈趙克勤吏部三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','雲臺玉局舊曾諳，回首茅山亦再監。',32,'全唐诗/poet.song.200000.json','["雲臺玉局舊曾諳，回首茅山亦再監。", "惟有亳祠尤久任，白頭三度入冰銜。"]'),
('37f7cfca-0844-4498-9a02-c0e9e2ea227e','陳亨叔司理見遺長牋小詩還贄','劉克莊','宋','宋诗','song-poetry','','[]','貧近山家作此行，潘輿來只費三程。',64,'全唐诗/poet.song.200000.json','["貧近山家作此行，潘輿來只費三程。", "責兒反鮓嫌疑謹，使婦供鮭奉養清。", "吾不入城避瓜李，子因謀野過柴荆。", "紫薇老病君房去，自課樵歌代遠情。"]'),
('4b0c03c0-9f0d-4e24-b1f0-5501b3d50b5e','久雨二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','倏暖俄寒氣候偏，未梅一月雨連綿。',64,'全唐诗/poet.song.200000.json','["倏暖俄寒氣候偏，未梅一月雨連綿。", "移床自笑無乾處，鍊石渠能補漏天。", "風卷杜陵幾重屋，江通甫里百弓田。", "誰言野老無憂責，據枕終宵不得眠。"]'),
('92b91185-241f-41f0-b917-b1264bde92f4','久雨二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','登高四望積雲深，失了金烏底處尋。',64,'全唐诗/poet.song.200000.json','["登高四望積雲深，失了金烏底處尋。", "未可漚麻需潦退，臨當曬麥輒天陰。", "寶開元畫憂嵐濕，惜善和書怕蠹侵。", "只道閑人無繫累，豈知亦有事關心。"]'),
('2df50ec3-74f0-4fa0-80b0-f18b48154180','挽趙虛齋二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','俱列儒臣侍細氈，各爲逐客問歸船。',64,'全唐诗/poet.song.200000.json','["俱列儒臣侍細氈，各爲逐客問歸船。", "親賢有詔徵劉向，疎遠無人贖史遷。", "當日金臺諸客散，暮年鐵壁幾人全。", "傷心滴露研朱筆，抱在螢窗雪案邊。"]'),
('29bb97ac-6420-4010-a718-c5a3f4223367','挽趙虛齋二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','前歲山人來訪逮，墓田丙舍報余知。',64,'全唐诗/poet.song.200000.json','["前歲山人來訪逮，墓田丙舍報余知。", "法書尚寶元章帖，拙筆深慙有道碑。", "重作大招難盡意，共談太極永無期。", "可憐老病忘昏晝，但記西窗剪燭時。"]'),
('c342e934-6164-4edd-8dbf-58a06b373bd5','艾人六言二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','不惟寶劍衝斗，亦自高冠切雲。',28,'全唐诗/poet.song.200000.json','["不惟寶劍衝斗，亦自高冠切雲。", "令祖豈非艾子，先師莫是茅君。"]'),
('2715dfee-8694-494f-913e-accd499d188d','艾人六言二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','欹枕三彭暫去，燒船五鬼俱還。',28,'全唐诗/poet.song.200000.json','["欹枕三彭暫去，燒船五鬼俱還。", "我欲膝行倒屣，君無髮上衝冠。"]'),
('3321f8aa-c146-4ad0-b25b-688960f0f70e','病起','劉克莊','宋','宋诗','song-poetry','','[]','病起龍鍾怯負犁，劣能扶杖視蔬畦。',64,'全唐诗/poet.song.200000.json','["病起龍鍾怯負犁，劣能扶杖視蔬畦。", "罷休自笑同芻狗，老去君當恕木雞。", "孤鶴驚飛沙苑箭，群烏嗔借上林棲。", "終須覓箇安巢處，萬疊青山繚碧溪。"]'),
('07015bba-cabe-4e67-bed1-f9ab97601c08','警齋吳侍郎再和余送行及居厚弟詩各次韻  其一','劉克莊','宋','宋诗','song-poetry','','[]','朝陽鳳咮更誰同，回首啾啾笑候蟲。',64,'全唐诗/poet.song.200000.json','["朝陽鳳咮更誰同，回首啾啾笑候蟲。", "洛下二龍閑馬呂，建中兩豸數鄒龔。", "呼來伯雅聊排悶，叱去奴星莫送窮。", "華髮未交衰颯甚，敢鳴破釜答編鍾。"]'),
('42bd7350-c118-4154-be48-736bdb3018cd','警齋吳侍郎再和余送行及居厚弟詩各次韻  其二','劉克莊','宋','宋诗','song-poetry','','[]','朝騎寶馬聽雞聲，夕問歸舟灶婢驚。',64,'全唐诗/poet.song.200000.json','["朝騎寶馬聽雞聲，夕問歸舟灶婢驚。", "手扳抽還無責任，諫書訖了少施行。", "有時短褐過鄰舍，不記巍冠待邇英。", "善類合離關世運，非人頰舌所能爭。"]'),
('5e6af4ed-d9b4-459a-aa7a-99a512c35499','警齋吳侍郎再和余送行及居厚弟詩各次韻  其三','劉克莊','宋','宋诗','song-poetry','','[]','曾聽仙韶宴玉津，豈知金彈忽危身。',64,'全唐诗/poet.song.200000.json','["曾聽仙韶宴玉津，豈知金彈忽危身。", "誰爲高樹鳳凰語，無奈雕籠鸚鵡嗔。", "拙射元非落鵰手，村眉難比掃蛾人。", "新裁白紵衣如雪，一點休教染洛塵。"]'),
('517eb537-bb9d-4cb3-a819-d03e4e972d46','警齋吳侍郎再和余送行及居厚弟詩各次韻  其四','劉克莊','宋','宋诗','song-poetry','','[]','少小携書借隙光，宵眠常晏起常忙。',64,'全唐诗/poet.song.200000.json','["少小携書借隙光，宵眠常晏起常忙。", "莫嫌茅舍曝朝日，猶勝板橋行曉霜。", "藜杖久疎前閣老，桃花不記舊臺郎。", "自慚道學工夫淺，晚却逃儒入老莊。"]'),
('8ad7876d-26a3-4eb5-a07c-1099eacb87b5','梅花一首','劉克莊','宋','宋诗','song-poetry','','[]','造化生尤物，居然冠衆芳。',48,'全唐诗/poet.song.200000.json','["造化生尤物，居然冠衆芳。", "東家傅粉白，西域返魂香。", "真可壻芍藥，未妨妃海棠。", "平生恨歐九，極口說姚黄。"]'),
('28c43934-14a9-4fc4-a00b-cf15231b4ec5','蚍蜉一首','劉克莊','宋','宋诗','song-poetry','','[]','梅月炎官尚斂威，紛紛此物傍綀衣。',64,'全唐诗/poet.song.200000.json','["梅月炎官尚斂威，紛紛此物傍綀衣。", "撲燈似怕光芒掩，撼樹都忘力量微。", "因愛積陰憎景日，逆知將雨洩天機。", "未應蟻子渾無援，時至皆能插羽飛。"]'),
('0201f84a-add9-4db7-8bdf-b1693d2f7916','攬鏡六言三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','背傴水牛泅磵，髮白冰蠶吐絲。',28,'全唐诗/poet.song.200000.json','["背傴水牛泅磵，髮白冰蠶吐絲。", "貌醜似猴行者，詩瘦於鶴何師。"]'),
('502880d4-b952-41f8-b409-4233708c2209','攬鏡六言三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','天上映藜已懶，霧中看花不真。',28,'全唐诗/poet.song.200000.json','["天上映藜已懶，霧中看花不真。", "顧我七十餘老，見公三兩分人。"]'),
('2700e89b-0584-420e-b0c6-bcf425921b4c','攬鏡六言三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','蚊睫僾然不見，蠅頭老矣停披。',28,'全唐诗/poet.song.200000.json','["蚊睫僾然不見，蠅頭老矣停披。", "盲左邱明作傳，瞎張太祝工詩。"]'),
('96ef8c06-5e41-439c-9538-6abf850b6547','送林元質侍郎赴宣城二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','江鄉民力已凋疲，妙選名臣往拊綏。',64,'全唐诗/poet.song.200000.json','["江鄉民力已凋疲，妙選名臣往拊綏。", "此去天家增保障，向來帝子擁旌麾。", "蕭生補郡寧忘諫，謝守看山定有詩。", "相國若詢周柱史，爲言健似出關時。"]'),
('edcf34a5-8445-4fb6-b5f3-a901626de85a','送林元質侍郎赴宣城二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','玉階接武侍凝旒，歲晚同尋洛社遊。',64,'全唐诗/poet.song.200000.json','["玉階接武侍凝旒，歲晚同尋洛社遊。", "騎竹小兒迎輒去，戴花老監挽難留。", "班春行李那容緩，亭午前茅盍少休。", "造物殷勤愛公處，傍無妙麗護衣篝。"]'),
('50999e8b-1cf8-4d61-aa53-e09196966131','抄近藁六言二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','和調失黏詩句，按摸出格文章。',28,'全唐诗/poet.song.200000.json','["和調失黏詩句，按摸出格文章。", "儘可追陪党進，不消更覓君房。"]'),
('c810f9ef-a10f-4ac2-b462-e73c3b34cf4d','抄近藁六言二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','東鄰莫效西子，南窗何減北扉。',28,'全唐诗/poet.song.200000.json','["東鄰莫效西子，南窗何減北扉。", "一螢道我來往，焉用宮蓮送歸。"]'),
('f461a80f-2b97-4ce4-93ca-e1ede0a188e4','代舉人主司問答六言二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','破題得李程賦，結語取錢起詩。',28,'全唐诗/poet.song.200000.json','["破題得李程賦，結語取錢起詩。", "遂令眊矂舉子，不滿冬烘主司。"]'),
('72ce6271-7223-4ab9-a340-e0c8291df375','代舉人主司問答六言二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','夢裏誰無綵筆，暗中別有朱衣。',28,'全唐诗/poet.song.200000.json','["夢裏誰無綵筆，暗中別有朱衣。", "蘇二得援失薦，歐九黜幾取煇。"]'),
('fd5c9f6b-a62d-4905-82c7-69bb30d892e2','採荔子十絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','策杖凌晨出，携筐薄暮歸。',24,'全唐诗/poet.song.200000.json','["策杖凌晨出，携筐薄暮歸。", "未知故山荔，何似首陽薇。"]'),
('f47dcfb2-2e38-4b94-8121-8e02f9816814','採荔子十絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','一鶴爲前導，奚煩絳節哉。',24,'全唐诗/poet.song.200000.json','["一鶴爲前導，奚煩絳節哉。", "樵蘇私借問，何處地仙來。"]'),
('6def5746-ddcb-40a0-98d8-3e4fb6c16ec1','採荔子十絕  其三','劉克莊','宋','宋诗','song-poetry','','[]','開國何其忝，箋天未必俞。',24,'全唐诗/poet.song.200000.json','["開國何其忝，箋天未必俞。", "繳還三百戶，換賜一千株。"]'),
('411aa4e4-4887-4089-bca9-1bab00cd7457','採荔子十絕  其四','劉克莊','宋','宋诗','song-poetry','','[]','日日煩湯使，年年費火攻。',24,'全唐诗/poet.song.200000.json','["日日煩湯使，年年費火攻。", "暮齡知艾附，不及荔枝功。"]'),
('3b6e1420-93f9-4367-9b81-203a536a4a87','採荔子十絕  其五','劉克莊','宋','宋诗','song-poetry','','[]','解使冰腸煖，能令玉色腴。',24,'全唐诗/poet.song.200000.json','["解使冰腸煖，能令玉色腴。", "誰能補丹訣，素女絳羅襦。"]'),
('8b886788-cdbe-4479-87c2-147898a59361','採荔子十絕  其六','劉克莊','宋','宋诗','song-poetry','','[]','童子偷無怪，先生老尚饞。',24,'全唐诗/poet.song.200000.json','["童子偷無怪，先生老尚饞。", "采時留絕頂，猿鳥要分甘。"]'),
('f65df970-01a7-4e50-9204-99a4677777a7','採荔子十絕  其七','劉克莊','宋','宋诗','song-poetry','','[]','帝享老臞仙，丹苞實醴泉。',24,'全唐诗/poet.song.200000.json','["帝享老臞仙，丹苞實醴泉。", "猶嫌無供帳，賜以錦漫天。"]'),
('a7f2ddef-e0e4-46f8-b7b3-818d8408c528','採荔子十絕  其八','劉克莊','宋','宋诗','song-poetry','','[]','包柚書云爾，分桃傳有之。',24,'全唐诗/poet.song.200000.json','["包柚書云爾，分桃傳有之。", "憐渠生處遠，玉食偶然遺。"]'),
('3b52ff29-f800-467f-9d8b-335cbe912ba5','採荔子十絕  其九','劉克莊','宋','宋诗','song-poetry','','[]','懷橘悲何及，芸瓜老不任。',24,'全唐诗/poet.song.200000.json','["懷橘悲何及，芸瓜老不任。", "摘來先廟祭，灑淚向松陰。"]'),
('0895a1db-69f5-489c-8bf1-e26a5c491835','採荔子十絕  其一○','劉克莊','宋','宋诗','song-poetry','','[]','傳得上林種，曾於艮嶽栽。',24,'全唐诗/poet.song.200000.json','["傳得上林種，曾於艮嶽栽。", "吾君無嗜好，不貢一株來。"]'),
('d970b384-2425-4671-90fb-13c6333a1147','贈日者朱俊甫二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','老子瞢騰大化中，支干一字不能通。',32,'全唐诗/poet.song.200000.json','["老子瞢騰大化中，支干一字不能通。", "請君留取談天口，去訪橫渠與了翁。"]'),
('0f803a5b-0287-4bb5-bcc8-0a474bea65c7','贈日者朱俊甫二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','謝公閉墅懶圍棋，董相還家且下帷。',32,'全唐诗/poet.song.200000.json','["謝公閉墅懶圍棋，董相還家且下帷。", "見說金甌殊未定，問君魁柄屬之誰。"]'),
('0240ff65-52a5-404f-a6c8-77dfcdfca228','贈羅攝官','劉克莊','宋','宋诗','song-poetry','','[]','一夢端爲文字祥，華宗復出小君章。',64,'全唐诗/poet.song.200000.json','["一夢端爲文字祥，華宗復出小君章。", "無家來去如潮水，有鬼揶揄向路傍。", "肯顧雀羅殊鄭重，欲爲雞黍愧荒凉。", "燕昭歿後金臺少，僮瘦馿饑驛堠長。"]'),
('e8eecc22-8d61-4641-a92e-60dac3c96564','哀仲妹','劉克莊','宋','宋诗','song-poetry','','[]','壼範班班在里閭，始知列女傳非虛。',64,'全唐诗/poet.song.200000.json','["壼範班班在里閭，始知列女傳非虛。", "室無遺桂空花妄，溪有新塋宰樹疎。", "弟憶雪中聯汝句，兄行雷岸寄家書。", "自憐戴白龍鍾叟，猶向原頭駕素車。"]'),
('1eb5c3b2-9393-4166-bedf-fbd56365eee2','挽方親來伯','劉克莊','宋','宋诗','song-poetry','','[]','弆藏古物或千年，漢晉隋唐在目前。',64,'全唐诗/poet.song.200000.json','["弆藏古物或千年，漢晉隋唐在目前。", "死有一孫堪付託，生惟四友共周旋。", "寶扶風簋如原甫，臨永興書逼米顛。", "占盡人間最清事，吾碑百世後方傳。"]'),
('df4b4415-9f1b-441c-a6a5-da6c9290d32a','答楊浩','劉克莊','宋','宋诗','song-poetry','','[]','往前曾愛銘文囑，老病安知擬議差。',64,'全唐诗/poet.song.200000.json','["往前曾愛銘文囑，老病安知擬議差。", "柏下人埋將宿草，管城子禿已無花。", "自慙吾匪三長史，誰誤君尋五作家。", "今代李邕領袖手，往來碑版不須嗟。"]'),
('de60cd8f-548d-4d24-85f9-b6b1e3e88a99','九日遊華嚴寺二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','堂閉厨荒蘚壁頹，重尋陳迹故堪哀。',64,'全唐诗/poet.song.200000.json','["堂閉厨荒蘚壁頹，重尋陳迹故堪哀。", "殘僧遠避遊山屐，饑雀空窺施食臺。", "鬢換絕無黑絲出，樽空不見白衣來。", "千林摇落秋容老，未有黄花一朵開。"]'),
('c6e5a318-0eba-45f9-9298-a76235d4a700','九日遊華嚴寺二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','古塔東偏景最奇，年深何處認苔基。',64,'全唐诗/poet.song.200000.json','["古塔東偏景最奇，年深何處認苔基。", "碧紗籠毀雷轟壁，黄纈林疎葉脫枝。", "鶻沒暮雲天杳杳，鶴歸舊里冢纍纍。", "牛山淚與龍山帽，雨洗風吹在者誰。"]'),
('e5200614-0f48-4200-9ff7-316f8b00904d','答建士謝旿二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','贄余一兩卷，覽罷恍然驚。',48,'全唐诗/poet.song.200000.json','["贄余一兩卷，覽罷恍然驚。", "老子猶堅壁，偏師忽劫營。", "今人輕雅道，造物靳詩名。", "自笑空空者，將何贈爾行。"]'),
('80981cf3-0b20-4e83-86fe-f73c7ac2cc1b','答建士謝旿二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','偶有幽人訪，柴門始一開。',48,'全唐诗/poet.song.200000.json','["偶有幽人訪，柴門始一開。", "大顛留偈去，小謝袖詩來。", "襆被嫌三宿，挑燈讀百回。", "惟應雙屐齒，歷歷在莓苔。"]'),
('39951a0e-5de3-4b6e-872b-9ca0b94fa5e7','挽安溪黄丞','劉克莊','宋','宋诗','song-poetry','','[]','未得毛錐力，空將鐵硯磨。',48,'全唐诗/poet.song.200000.json','["未得毛錐力，空將鐵硯磨。", "暗投主司老，私淑里人多。", "三韭何妨飽，雙松不待哦。", "鄉鄰惜耆舊，爲輟相舂歌。"]'),
('9b73b8d9-0628-493f-9919-f32f6171ae12','題趙主簿省試議併以將行','劉克莊','宋','宋诗','song-poetry','','[]','世儒通易少，公子信人豪。',48,'全唐诗/poet.song.200000.json','["世儒通易少，公子信人豪。", "幾載韋編絕，三篇紙價高。", "素心鄙溫飽，餘事及風騷。", "臺閫招徠廣，勾朱不足勞。"]'),
('c0cd539b-8e58-4607-a78d-3020fff8339d','記夢','劉克莊','宋','宋诗','song-poetry','','[]','昔夢趨旃厦，巍冠預講論。',48,'全唐诗/poet.song.200000.json','["昔夢趨旃厦，巍冠預講論。", "孤忠鄙張禹，薄命類虞翻。", "稍覺芻言戇，徐瞻玉色溫。", "放臣絕朝謁，無路可酬恩。"]'),
('121841b8-69cb-41ea-910c-54e43bb8fb5b','書事二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','空空都沒一行書，行行徒矜九尺軀。',64,'全唐诗/poet.song.200000.json','["空空都沒一行書，行行徒矜九尺軀。", "面上带妖真可恥，脚中有鬼不容扶。", "末年鐵拐傳仙訣，他日金錐抉冢珠。", "泉下定爲明允笑，果能看破半山無。"]'),
('44dca617-e6d0-47ea-8e9b-68b299b4b971','書事二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','利刃斬風空惡毒，疾聲吠雪似獃顛。',64,'全唐诗/poet.song.200000.json','["利刃斬風空惡毒，疾聲吠雪似獃顛。", "嗟余芻狗木雞爾，視汝螟蛉蜾蠃然。", "墓上將軍堪嚇鬼，龕中大士且安禪。", "不須懺禮如來足，佛與波旬共結緣。"]'),
('09121bea-58c9-41f4-a7a5-c2f20ffc06c4','餞潘使君二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','送去迎來兩轂朱，如侯治行極稀疎。',64,'全唐诗/poet.song.200000.json','["送去迎來兩轂朱，如侯治行極稀疎。", "清惟薄採閩山荔，仁不曾苞丙穴魚。", "遺愛驗於還印後，歸裝貧似下車初。", "漢廷尚有公卿闕，頗怪龔黄欠璽書。"]'),
('20ccbea4-cb2f-4b99-ad58-719d52b0240d','餞潘使君二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','一念拳拳帝所臨，士民皆諒使君心。',64,'全唐诗/poet.song.200000.json','["一念拳拳帝所臨，士民皆諒使君心。", "隨車雨每孚精禱，下瀨船多出俸金。", "兩載公真茹蘗苦，百年人尚愛棠陰。", "從今緊閉袁安戶，庭雪平腰徑草深。"]'),
('9593a551-13e8-4ba4-9fef-204bcee3d9f5','哭吳卿明輔二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','水心文印雖傳嫡，青出於藍自一家。',64,'全唐诗/poet.song.200000.json','["水心文印雖傳嫡，青出於藍自一家。", "尚意祥麟來泰畤，安知怪鵩集長沙。", "忤因宮妾頭無髮，去爲將軍手污靴。", "他日史官如立傳，先書氣節後詞華。"]'),
('c71e171a-eb00-4ccb-8369-e3c7615a095a','哭吳卿明輔二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','吳兢史法蔡邕碑，每嘆斯文尚在茲。',64,'全唐诗/poet.song.200000.json','["吳兢史法蔡邕碑，每嘆斯文尚在茲。", "老奪故交堪痛惜，晚徵集序未遑爲。", "單傳骨髓惟吾子，空嘔心肝向阿誰。", "道遠束芻携不去，覆翻遺墨豈勝悲。"]'),
('aa3b8e81-d901-4ce3-828e-6becc691f30e','挽方惠倅','劉克莊','宋','宋诗','song-poetry','','[]','家譜推賢裔，鄉評號吉人。',48,'全唐诗/poet.song.200000.json','["家譜推賢裔，鄉評號吉人。", "佩銀成短夢，冠玉漫長身。", "朱軫鸞膠斷，青林鶴表新。", "空令柱下史，反惜幕中賓。"]'),
('3a8a126b-8e20-426e-aada-85bf8c2fb3d8','挽葉謙夫尚書二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','履聲騰上逼星辰，俄駕朱轓去牧民。',64,'全唐诗/poet.song.200000.json','["履聲騰上逼星辰，俄駕朱轓去牧民。", "不作金張門下客，亦非牛李黨中人。", "公寧抽版還丞相，誰更移書責諫臣。", "爪距紛紛誇鷙搏，安知魯野有祥麟。"]'),
('e23e41f5-d058-4e25-a914-f5167b055889','挽葉謙夫尚書二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','道山昔謬領羣仙，同舍推公最妙年。',64,'全唐诗/poet.song.200000.json','["道山昔謬領羣仙，同舍推公最妙年。", "方立班心九霄上，忽騎箕尾列星邊。", "奏篇誰肯收遺藁，主祭妻爲選象賢。", "百嶂千峰環縣郭，未知何處是新阡。"]'),
('36cd2526-7e15-4cff-8609-f509fc0aaf9f','冬夜讀几案間雜書得六言二十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','叔夜真龍鳳矣，嗣宗猶螟蠃然。',28,'全唐诗/poet.song.200000.json','["叔夜真龍鳳矣，嗣宗猶螟蠃然。", "一以廣陵散死，一以勸進表全。"]'),
('3ee6e446-3808-4f6f-adab-42272a4c72d3','冬夜讀几案間雜書得六言二十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','盤龍恨庾長史，太宰哀李崖州。',28,'全唐诗/poet.song.200000.json','["盤龍恨庾長史，太宰哀李崖州。", "達人能和大怨，壯士不報細讎。"]'),
