('eab09bc8-05e1-4697-8089-85e6d1385aeb','冬夜讀几案間雜書得六言二十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','橫議遊俠四出，清流標榜自賢。',28,'全唐诗/poet.song.200000.json','["橫議遊俠四出，清流標榜自賢。", "血染瓜田方止，尸投濁河可憐。"]'),
('b84b4ed5-fd34-4edb-95ec-0ebc92176cdc','冬夜讀几案間雜書得六言二十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','箋疏蟲魚小物，抉挑草木微情。',28,'全唐诗/poet.song.200000.json','["箋疏蟲魚小物，抉挑草木微情。", "兔葵累劉夢得，燕泥辜薛道衡。"]'),
('553b6c0e-9aba-45fa-8857-7ac22979b322','冬夜讀几案間雜書得六言二十首  其一一','劉克莊','宋','宋诗','song-poetry','','[]','□□本非家法，偶語安知朝儀。',28,'全唐诗/poet.song.200000.json','["□□本非家法，偶語安知朝儀。", "宮中遂有秘戲，殿上竟問小遺。"]'),
('75e61102-bfe5-4d36-b405-a49102c2d6ee','冬夜讀几案間雜書得六言二十首  其一二','劉克莊','宋','宋诗','song-poetry','','[]','宋玉口多微詞，曼倩言不純師。',28,'全唐诗/poet.song.200000.json','["宋玉口多微詞，曼倩言不純師。", "陳賦諷薦枕女，抗義斬賣珠兒。"]'),
('7cdf5382-912e-4d38-9b78-37d4ed42895f','冬夜讀几案間雜書得六言二十首  其一三','劉克莊','宋','宋诗','song-poetry','','[]','鸚鵡洲猶自若，銅雀臺安在哉。',28,'全唐诗/poet.song.200000.json','["鸚鵡洲猶自若，銅雀臺安在哉。", "老瞞真大不道，狂生恃小有才。"]'),
('6b8d87ad-89ff-4fe6-9607-c9fb8732cb14','冬夜讀几案間雜書得六言二十首  其一四','劉克莊','宋','宋诗','song-poetry','','[]','巢居吸景休糧，壁觀入定放光。',28,'全唐诗/poet.song.200000.json','["巢居吸景休糧，壁觀入定放光。", "三萬里隔弱水，六千劫坐道場。"]'),
('69517844-7735-47db-b62d-842393d439d5','冬夜讀几案間雜書得六言二十首  其一五','劉克莊','宋','宋诗','song-poetry','','[]','六郎子晉後身，董君漢廷近親。',28,'全唐诗/poet.song.200000.json','["六郎子晉後身，董君漢廷近親。", "大羅天女男妾，館陶公主肥人。"]'),
('20d99c1d-f0f6-4d82-9c11-50f01ce456ad','冬夜讀几案間雜書得六言二十首  其一六','劉克莊','宋','宋诗','song-poetry','','[]','進來金丹攙喫，放下玉笛偷吹。',28,'全唐诗/poet.song.200000.json','["進來金丹攙喫，放下玉笛偷吹。", "先丁寧雪衣女，勿漏泄錦綳兒。"]'),
('4b9fe179-121b-4e44-9226-efe3c07634dc','冬夜讀几案間雜書得六言二十首  其一七','劉克莊','宋','宋诗','song-poetry','','[]','李妹玉曜膚色，梅娘淡粧素衣。',28,'全唐诗/poet.song.200000.json','["李妹玉曜膚色，梅娘淡粧素衣。", "大主嗔老奴愛，三郎怕肥婢知。"]'),
('816e86cb-23cb-4f5e-8fe5-9946c2e6fe08','冬夜讀几案間雜書得六言二十首  其一八','劉克莊','宋','宋诗','song-poetry','','[]','裙是千葉榴染，鬢似折枝杏簪。',28,'全唐诗/poet.song.200000.json','["裙是千葉榴染，鬢似折枝杏簪。", "空問天孫乞巧，其奈君王愛憨。"]'),
('96bc2f60-a72f-4bf1-bef6-a66387aff3a6','冬夜讀几案間雜書得六言二十首  其一九','劉克莊','宋','宋诗','song-poetry','','[]','寧置寒冰隘巷，勿長婦人深宮。',28,'全唐诗/poet.song.200000.json','["寧置寒冰隘巷，勿長婦人深宮。", "兒□昭儀篋內，孫斃季龍抱中。"]'),
('7579bc12-addd-43d4-b329-15eef331dca0','冬夜讀几案間雜書得六言二十首  其二○','劉克莊','宋','宋诗','song-poetry','','[]','南朝有脂粉氣，李唐誇錦繡堆。',28,'全唐诗/poet.song.200000.json','["南朝有脂粉氣，李唐誇錦繡堆。", "接休文聲響去，夢太白脚板來。"]'),
('b2349d88-7031-48f3-a2b3-5e9d2dff13a7','哭伯姊二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','弟爲龜湖妹製碑，伯姬舍我復何之。',64,'全唐诗/poet.song.200000.json','["弟爲龜湖妹製碑，伯姬舍我復何之。", "今彤史筆嗟誰炳，古錦囊詩獨姊知。", "起絮撒鹽才有間，燎鬚作粥力安施。", "瀾湍石畔霜風冷，行路無情亦涕洟。"]'),
('8095042e-0826-4cea-b9e0-d176e1cbe7d5','哭伯姊二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','幼以木蘭爲長兄，豈堪垂老隔幽明。',64,'全唐诗/poet.song.200000.json','["幼以木蘭爲長兄，豈堪垂老隔幽明。", "空疎誰更譏匡鼎，友愛何曾詈屈平。", "服已降朞從變禮，聖猶尚左况諸生。", "追嚴不必伊蒲供，自有松風與澗聲。"]'),
('ced0f928-f51b-4568-98f3-83533cbaf623','答王掀將士','劉克莊','宋','宋诗','song-poetry','','[]','明時無復精英氣，化作祥風及慶雲。',64,'全唐诗/poet.song.200000.json','["明時無復精英氣，化作祥風及慶雲。", "馬鬣安能埋此骨，□□亦可與斯文。", "當年賓客誰珠履，今日郎君尚練裙。", "獨有後村翁尚在，匹雛無力漫殷勤。"]'),
('290eff31-e0ca-4c3b-958f-1220104ac395','新元二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','朝三暮四昔尚童，踰七望八今成翁。',64,'全唐诗/poet.song.200000.json','["朝三暮四昔尚童，踰七望八今成翁。", "見佛未肯右肩袒，對客嘗稱左耳聾。", "叩額有疏拜墀下，斷腕無麻納禁中。", "自憐老病菁華竭，不及花枝歲歲紅。"]'),
('727ed656-d369-410a-9b7b-8deb5912522d','新元二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','朝來微霰閣輕陰，攬鏡空添雪滿簪。',64,'全唐诗/poet.song.200000.json','["朝來微霰閣輕陰，攬鏡空添雪滿簪。", "官送桃符猶懶寫，兒酬椒酒勿多斟。", "病於懽事全然淡，老覺春寒未易禁。", "惟有改詩成一癖，消磨不盡少年心。"]'),
('b52664db-534e-4ded-b0b6-121ff1e4c1ca','夢館宿二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','花木扶疎月露清，昔人來此比登瀛。',32,'全唐诗/poet.song.200000.json','["花木扶疎月露清，昔人來此比登瀛。", "不知做得神仙未，身在喬松頂上行。"]'),
('0ff5c193-1b3a-4862-b9cc-9ddf459641d9','夢館宿二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','罡風誤送到蓬萊，昔種琪花今已開。',32,'全唐诗/poet.song.200000.json','["罡風誤送到蓬萊，昔種琪花今已開。", "僮鶴來迎俱嘆息，老仙又老似前回。"]'),
('8d8fdea0-1476-4756-ba66-3650c7ed6eed','挽南雄林使君','劉克莊','宋','宋诗','song-poetry','','[]','東路歸何及，南柯夢忽醒。',48,'全唐诗/poet.song.200000.json','["東路歸何及，南柯夢忽醒。", "居然鳴輓鐸，都未製齋鈴。", "官已題華表，名空錄御屏。", "遥知泉下意，猶待竹溪銘。"]'),
('99dfc7cb-31ee-4906-9760-d44e55adcbd7','題趙西里詩卷二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','紫芝仲白飛仙去，常恐英才不復生。',64,'全唐诗/poet.song.200000.json','["紫芝仲白飛仙去，常恐英才不復生。", "人歎斯文逢厄運，天留此老主齊盟。", "執鞭孰可爲之御，序齒吾猶事以兄。", "未必時人能著價，後千百載話頭行。"]'),
('3fd2578a-c133-4f25-9990-2a9eba9b4fd2','題趙西里詩卷二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','不向鶑邊繫寶鞍，海門東畔把魚竿。',64,'全唐诗/poet.song.200000.json','["不向鶑邊繫寶鞍，海門東畔把魚竿。", "無蒲萄酒博太守，有竹枝歌傳小蠻。", "到處名山留屐齒，看來元氣在毫端。", "繡娃辛苦描新樣，肯信春風放牡丹。"]'),
('c259f648-20d0-4980-87f2-0834acd31fd0','燈夕守舍','劉克莊','宋','宋诗','song-poetry','','[]','百口惟翁懶入闉，讙傳畫隼出行春。',64,'全唐诗/poet.song.200000.json','["百口惟翁懶入闉，讙傳畫隼出行春。", "冶容淇上多遊女，群飲街頭有醉人。", "聽黑簫韶成假寐，映青藜杖是前身。", "不知誰侍傳柑宴，早爲君王靖塞塵。"]'),
('a047b62a-031a-48e9-bf36-b6f7cc8970d3','無題二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','江北塵高戰鼓酣，惜無赤壁順風帆。',64,'全唐诗/poet.song.200000.json','["江北塵高戰鼓酣，惜無赤壁順風帆。", "城池險固爲樓百，郡邑蕭條有戶三。", "明主依然勞聖慮，諸君豈得尚清談。", "嗚呼頗牧不復作，誰與兒郎共苦甘。"]'),
('563eace6-a9de-4140-b9ba-3b79224e20c1','無題二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','夕烽一夕徹甘泉，鑄印分弓玉座前。',64,'全唐诗/poet.song.200000.json','["夕烽一夕徹甘泉，鑄印分弓玉座前。", "天狗如雷防急變，佛貍死卯竟譌傳。", "漢家豈可無三策，胡運何曾有百年。", "漸覺風寒逼堂奧，寄聲諸老急籌邊。"]'),
('6f7d7ae4-f03e-41a2-9a3d-8c988ab02e5d','即事二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','禿翁未敢佚餘生，洗竹澆蘭立課程。',64,'全唐诗/poet.song.200000.json','["禿翁未敢佚餘生，洗竹澆蘭立課程。", "辛苦謀身無甕算，殷勤娛耳有瓶笙。", "罏寒燒葉回春意，燭盡携書就月明。", "一欠伸間分夢覺，何須它日曲池平。"]'),
('c5cb9612-7776-4591-928e-6f22f857f3fb','即事二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','生涯草草旋安排，先架茅堂次竹齋。',64,'全唐诗/poet.song.200000.json','["生涯草草旋安排，先架茅堂次竹齋。", "傍榾柮邊名燠室，有榕樹處當凉臺。", "且饒林下一人去，莫問門前幾客來。", "新買溪西山數畝，便思輦石更移梅。"]'),
('086302a9-2253-450b-9d6f-745d2bb1d5d4','久雨一首','劉克莊','宋','宋诗','song-poetry','','[]','春來能得幾朝晴，病叟深藏似凍蠅。',64,'全唐诗/poet.song.200000.json','["春來能得幾朝晴，病叟深藏似凍蠅。", "獨夜山房惟燭影，暮年家樂只簷聲。", "墊巾此老猶標致，裹飯何人訪死生。", "村北村南泥滑滑，且宜高卧閉柴荆。"]'),
('925a423d-5975-4255-8667-880e7a117ba9','春寒二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','東皇太乙漫行春，無頼封姨未霽嗔。',64,'全唐诗/poet.song.200000.json','["東皇太乙漫行春，無頼封姨未霽嗔。", "薄酒不紅皺靴面，濕薪難直曲鉤身。", "埋腰健羨單傳者，墮指深慙遠戍人。", "莫笑布衾如鐵冷，也勝去傍相君茵。"]'),
('b933fdc0-9e69-4acb-9059-3e0cea964131','春寒二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','百藝惟詩老始工，未應凍死杜陵翁。',64,'全唐诗/poet.song.200000.json','["百藝惟詩老始工，未應凍死杜陵翁。", "聳肩偏怯春衣薄，曝背尤貪曉日紅。", "草鼓煖於狨坐子，蒲龕清似肉屏風。", "幾時天地回生意，只費陽和一點功。"]'),
('fec4bf7a-37b1-45e3-a80a-b7d126b7ede4','二月十八日過梅庵追懷主人二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','猶記尋梅負酒瓢，當時賓主正豐標。',64,'全唐诗/poet.song.200000.json','["猶記尋梅負酒瓢，當時賓主正豐標。", "通宵縱飲燒銀燭，攙早催開喚玉簫。", "摘艷人亡誰共賞，戴花翁在老無憀。", "重來只是新華表，不忍攀枝更折條。"]'),
('18b17053-7c94-4a73-ae0b-845399da1967','二月十八日過梅庵追懷主人二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','慣作梁園座右賓，非惟管鮑亦朱陳。',64,'全唐诗/poet.song.200000.json','["慣作梁園座右賓，非惟管鮑亦朱陳。", "自從石友幽明隔，誰訪瑶妃寂寞濱。", "花若無情還有恨，樹猶如此况於人。", "不知宋玉歸何處，口誦招魂一愴神。"]'),
('2b8d2e41-6ba0-47c1-ab17-a159f579b0a1','林貴州哀詩二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','四壁空留宅，雙旌漫典州。',48,'全唐诗/poet.song.200000.json','["四壁空留宅，雙旌漫典州。", "無錢堆別屋，有石壓歸舟。", "縱未封孫叔，猶當廟柳侯。", "吾銘皆實錄，亦足繼前修。"]'),
('ef600d12-5294-43f9-9f5b-6e5c5966c479','林貴州哀詩二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','歲晚淹留潦霧間，朱幡雖寵變蒼顔。',64,'全唐诗/poet.song.200000.json','["歲晚淹留潦霧間，朱幡雖寵變蒼顔。", "潁川鳳下來何晚，浪泊鳶飛去不還。", "道遠返喪新燧改，州貧無賻旅囊慳。", "新邱莫嘆封塋儉，絕勝癡人錦裹山。"]'),
('f1277515-f277-4e6f-91cf-851931ae4b02','待制趙公伯泳哀詩二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','趙氏源流自副樞，至公清節亢門閭。',64,'全唐诗/poet.song.200000.json','["趙氏源流自副樞，至公清節亢門閭。", "緒言猶接淳熙際，親擢何慚慶曆初。", "班馬定爲廉吏傳，韓歐無責諫臣書。", "可憐衮斧忠邪學，僅向甘泉扈屬車。"]'),
('155361f4-fb5a-40b6-81f0-703d3597491d','待制趙公伯泳哀詩二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','憶昔鵷行接武趨，與君肝膽素相孚。',64,'全唐诗/poet.song.200000.json','["憶昔鵷行接武趨，與君肝膽素相孚。", "孤忠不忍欺明主，健論真堪立懦夫。", "公是意林曾續否，退之手註尚存無。", "暮年數出交遊淚，莫怪星星滿鬢鬚。"]'),
('e6fb0939-d073-4aaa-92e0-94f39dcf90cf','禽言九首 杜鵑','劉克莊','宋','宋诗','song-poetry','','[]','門前客勸不如住，樹頭鳥勸不如去。',48,'全唐诗/poet.song.200000.json','["門前客勸不如住，樹頭鳥勸不如去。", "廷尉重來客又集，丞相欲去門人泣。", "客誤主人固不少，哀哉人有不如鳥。"]'),
('70cf25f5-6716-4fbe-a43c-0deffd0e4aae','禽言九首 接客','劉克莊','宋','宋诗','song-poetry','','[]','向來客至投轄留，而今避客如避仇。',64,'全唐诗/poet.song.200000.json','["向來客至投轄留，而今避客如避仇。", "山禽儆我似有理，何不握髮更倒屣。", "禽兮禽兮汝豈知，人生衰旺各有時。", "主人老病客勿怪，爨冷樽空無管待。"]'),
('468616a6-a1db-4194-a77b-a6b16f711707','禽言九首 姑惡','劉克莊','宋','宋诗','song-poetry','','[]','有鳥有鳥林間呼，聲聲句句唯怨姑。',96,'全唐诗/poet.song.200000.json','["有鳥有鳥林間呼，聲聲句句唯怨姑。", "夜挑錦字嫌眠懶，晨執帨巾嗔起晚。", "老人食性尤難準，冰天求魚冬責笋。", "爺娘錯計遣嫁夫，悔不長作閨中姝。", "新婦新婦牢記著，人生百年更苦樂。", "他時堂上作阿家，莫教新婦云姑惡。"]'),
('2a757384-037d-44bf-9400-41c3e1b5e011','禽言九首 行不得哥哥','劉克莊','宋','宋诗','song-poetry','','[]','羊腸汝尚行不得，而况汝兄脚無力。',64,'全唐诗/poet.song.200000.json','["羊腸汝尚行不得，而况汝兄脚無力。", "何曾知有陟岡詩，聲聲叫兄不容釋。", "四達之逵如掌平，井廩危道慎無行。", "禽鳥微類猶有情，鼻亭公豈不愛兄。"]'),
('2f1fbc2a-4dc1-4544-b602-f57960141687','禽言九首 提葫蘆','劉克莊','宋','宋诗','song-poetry','','[]','朝愁暮愁愁不已，生爲愁人死愁鬼。',48,'全唐诗/poet.song.200000.json','["朝愁暮愁愁不已，生爲愁人死愁鬼。", "百禽唯爾尤可喜，勸我移住醉鄉裏。", "劉伶畢卓善自謀，生前死後不識愁。"]'),
('87e28ae1-3ff8-4a12-9914-4e2c0501eab4','禽言九首 脫布袴','劉克莊','宋','宋诗','song-poetry','','[]','貴家紈袴金梭織，貧家布袴纔蔽膝。',48,'全唐诗/poet.song.200000.json','["貴家紈袴金梭織，貧家布袴纔蔽膝。", "半夜打門持文書，脫袴貰酒待里胥。", "何時贖袴要禦寒，亦爲官掩催租瘢。"]'),
('a916f1df-5f62-4ed4-8a9e-f5d4a447aebd','禽言九首 布穀','劉克莊','宋','宋诗','song-poetry','','[]','牆壁雖有勸農文，不如禽語尤殷勤。',64,'全唐诗/poet.song.200000.json','["牆壁雖有勸農文，不如禽語尤殷勤。", "春泥滑滑陂水滿，晨出下秧薄暮返。", "烏呼三農養一兵，汝曹努力勿惰耕。", "朱門日高眠未起，却嫌布穀聲聒耳。"]'),
('49fae482-f400-4887-849e-a2384b261b51','禽言九首 婆餠焦','劉克莊','宋','宋诗','song-poetry','','[]','阿婆八十雙鬢皤，屑麥爲餠將奉婆。',64,'全唐诗/poet.song.200000.json','["阿婆八十雙鬢皤，屑麥爲餠將奉婆。", "小家新婦拙烹調，不覺鐺熱令餠焦。", "高堂日晏婆停筯，小姑訶婢郎譴婦。", "新婦歛手前謝過，別就熱鐺翻一箇。"]'),
('f66403f6-9a7e-4cc3-bf71-26f40b2ead0b','禽言九首 郭公','劉克莊','宋','宋诗','song-poetry','','[]','郭公郭公曾君國，魂化爲鳥憾未釋。',64,'全唐诗/poet.song.200000.json','["郭公郭公曾君國，魂化爲鳥憾未釋。", "滿目山河屬別人，舊時宮殿歸不得。", "更姓改物今千春，歷歷記憶常如新。", "郭公蜀帝兩癡絕，自古失國知幾人。"]'),
('92f406c7-e26b-4242-94e2-1b92c0e30978','題近藁二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','吾年開八秩，形槁更心灰。',48,'全唐诗/poet.song.200000.json','["吾年開八秩，形槁更心灰。", "禪縛病居士，詩殃凍秀才。", "無功上麟閣，有案在烏臺。", "攻苦三千首，誰曾著價來。"]'),
('e86aa2fd-d3d3-4d59-872a-48c275dbd68e','題近藁二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','世間小家數，不瘦失之寒。',48,'全唐诗/poet.song.200000.json','["世間小家數，不瘦失之寒。", "都未飽鯨膾，徒然烹蟣肝。", "於今無對壘，亙古有荒壇。", "改竄無全句，明朝更取看。"]'),
('8081f187-30dc-4eee-995e-105a4dafd8d0','瓦送','劉克莊','宋','宋诗','song-poetry','','[]','瓦送繡行均一去，如公之去獨賢哉。',64,'全唐诗/poet.song.200000.json','["瓦送繡行均一去，如公之去獨賢哉。", "國僑存校如迂闊，涑水辭樞冀挽回。", "聊爲先師主精舍，不煩殘客到翹村。", "半山未是忘情者，重拜頭廳便出來。"]'),
('16949433-82f3-48e5-998c-4b99954109dd','村居即事六言十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','磐石時時垂釣，茅簷旦旦負暄。',28,'全唐诗/poet.song.200000.json','["磐石時時垂釣，茅簷旦旦負暄。", "小杓行魚羹飯，長竿晒犢鼻褌。"]'),
('18ee6e4d-397e-41e5-9f58-c59e021e04bc','村居即事六言十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','呵凍畫灰鍛詩，傍人笑汝白癡。',28,'全唐诗/poet.song.200000.json','["呵凍畫灰鍛詩，傍人笑汝白癡。", "五百年有名世，七十翁如小兒。"]'),
('6bb6e819-b85f-4d17-90f9-e8d5fd242fac','村居即事六言十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','鈍根無慧能偈，信必有梵志詩。',28,'全唐诗/poet.song.200000.json','["鈍根無慧能偈，信必有梵志詩。", "黄吻少年忘語，龐眉尊者不知。"]'),
('2e78967d-643e-4027-a575-240056c69e8c','村居即事六言十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','老蚌剖胎枯矣，雄雞斷尾棄之。',28,'全唐诗/poet.song.200000.json','["老蚌剖胎枯矣，雄雞斷尾棄之。", "刎頸交誰捄汝，犁舌獄無出時。"]'),
('909518ba-2fd7-45db-af86-bb9a28a3e490','村居即事六言十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','有時散髮松風，有時一劍秋空。',28,'全唐诗/poet.song.200000.json','["有時散髮松風，有時一劍秋空。", "講易白牛谿上，題詩黄鶴樓中。"]'),
('3f3a7c78-6748-4edf-943a-6993f04b3e75','村居即事六言十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','風窗有竹相敲，地爐無葉可燒。',28,'全唐诗/poet.song.200000.json','["風窗有竹相敲，地爐無葉可燒。", "亂書翻覆未了，一燈明滅頻挑。"]'),
('11ac658e-ff6e-4d16-bc2d-5ee900f200aa','村居即事六言十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','一把算未能下，萬戶棋苦不高。',28,'全唐诗/poet.song.200000.json','["一把算未能下，萬戶棋苦不高。", "老子腹中無物，渠儂笑裏有刀。"]'),
('8658a267-c7c2-46a2-8e4d-ed17fb095aa8','村居即事六言十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','坐處在細旃上，立時傍紅雲邊。',28,'全唐诗/poet.song.200000.json','["坐處在細旃上，立時傍紅雲邊。", "寧罰公幹磨石，可使劉陶鑄錢。"]'),
('b1c2e646-b2d4-45d7-b137-babff5b33234','村居即事六言十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','髮脫禿鶖無異，背傴橐駝逼真。',28,'全唐诗/poet.song.200000.json','["髮脫禿鶖無異，背傴橐駝逼真。", "不是進賢冠者，亦非靈壽杖人。"]'),
('538d0daa-6298-478b-8a08-90a16e106a1f','村居即事六言十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','敝縕袍足蔽體，惡草具可享賓。',28,'全唐诗/poet.song.200000.json','["敝縕袍足蔽體，惡草具可享賓。", "犢車榮過九錫，鮓飯甘於八珍。"]'),
('8b5fe2f3-44da-4b92-bb69-37bbf60ef793','春夜溫故六言二十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','侍中譎取玉带，尚書苦愛貂蟬。',28,'全唐诗/poet.song.200000.json','["侍中譎取玉带，尚書苦愛貂蟬。", "家破謫黎母矣，塚穿無髑髏焉。"]'),
('d2c3a681-79ab-48ae-aca8-82ee910af1b6','春夜溫故六言二十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','私怨有公論者，反噬非人情哉。',28,'全唐诗/poet.song.200000.json','["私怨有公論者，反噬非人情哉。", "穎叔發修陰事，資深歎軾奇才。"]'),
('69443693-e4e1-4c52-9ee5-77ca726f6b6a','春夜溫故六言二十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','鼎鑊烹東都黨，烟瘴磨元祐人。',28,'全唐诗/poet.song.200000.json','["鼎鑊烹東都黨，烟瘴磨元祐人。", "但看紙上陳迹，始知陛下至仁。"]'),
('87027414-ceb2-4ca7-ba9a-f1b489f360bc','春夜溫故六言二十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','骨朽是非始定，怒炎毀譽未公。',28,'全唐诗/poet.song.200000.json','["骨朽是非始定，怒炎毀譽未公。", "太平呼奇宰相，野狐目半山翁。"]'),
('d9687649-5a52-4dbd-8fa6-2e4f931c39eb','春夜溫故六言二十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','燕山張皇薄伐，艮嶽文飾太平。',28,'全唐诗/poet.song.200000.json','["燕山張皇薄伐，艮嶽文飾太平。", "黼賀尅復受賞，瓘憂分裂有萌。"]'),
('e0f6fe86-1b71-4f4e-b986-a3a436506768','春夜溫故六言二十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','門前客已去矣，屋裏人安在哉。',28,'全唐诗/poet.song.200000.json','["門前客已去矣，屋裏人安在哉。", "寒雀張羅可得，春燕啣泥不來。"]'),
('6ad9a154-48f2-42de-80c4-7ab5bf28131c','春夜溫故六言二十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','丞相訓子尤儉，夫人送女已非。',28,'全唐诗/poet.song.200000.json','["丞相訓子尤儉，夫人送女已非。", "盥面用瓦盆子，籍足以錦地衣。"]'),
('adb2549b-048a-4497-9f8b-6a9ca03f372a','春夜溫故六言二十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','出入息頃冷暖，翻覆手間雨雲。',28,'全唐诗/poet.song.200000.json','["出入息頃冷暖，翻覆手間雨雲。", "斬頤從教萬段，賣頒不直分文。"]'),
('b049367d-1e42-4de6-896f-e455ff444c9a','春夜溫故六言二十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','京檜皆黄髮老，攸熺各黑頭公。',28,'全唐诗/poet.song.200000.json','["京檜皆黄髮老，攸熺各黑頭公。", "當時號爲小相，至今歎作頑童。"]'),
('b44d8dd2-29fa-4b6d-9723-5607bc301a71','春夜溫故六言二十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','選人片言授鉞，貴臣萬里建侯。',28,'全唐诗/poet.song.200000.json','["選人片言授鉞，貴臣萬里建侯。", "平洮致綠石研，復燕得碧雲油。"]'),
('3c31629e-3675-4868-bc98-e9a6a30a6166','春夜溫故六言二十首  其一一','劉克莊','宋','宋诗','song-poetry','','[]','拔舌犯世深忌，枕肱夸師緒言。',28,'全唐诗/poet.song.200000.json','["拔舌犯世深忌，枕肱夸師緒言。", "徂徠生爲鬼怪，伊川死尚還魂。"]'),
('2cfb1553-8e32-48d1-ba06-7733e5b49506','春夜溫故六言二十首  其一二','劉克莊','宋','宋诗','song-poetry','','[]','子長交遊莫捄，孫盛門戶幾危。',28,'全唐诗/poet.song.200000.json','["子長交遊莫捄，孫盛門戶幾危。", "執簡而往誤矣，閣筆相視得之。"]'),
('da24dc94-40c6-4752-b1da-dc2519333fa2','春夜溫故六言二十首  其一三','劉克莊','宋','宋诗','song-poetry','','[]','書姦書盜不隠，諱周諱魯若私。',28,'全唐诗/poet.song.200000.json','["書姦書盜不隠，諱周諱魯若私。", "使亂賊懼直筆，於定哀多微辭。"]'),
('5aac4c7c-66c9-4dce-a12b-16400fb752d7','春夜溫故六言二十首  其一四','劉克莊','宋','宋诗','song-poetry','','[]','向來動脚已謬，末後濡尾轉非。',28,'全唐诗/poet.song.200000.json','["向來動脚已謬，末後濡尾轉非。", "伏生力辭不至，申公不合而歸。"]'),
('a6158f0f-6140-45c9-a3db-81e8f7bb5bfd','春夜溫故六言二十首  其一五','劉克莊','宋','宋诗','song-poetry','','[]','一部日錄付壻，三經新義傳兒。',28,'全唐诗/poet.song.200000.json','["一部日錄付壻，三經新義傳兒。", "躋翁超乎亞聖，贊父光於仲尼。"]'),
('671a0bc9-e780-4aa9-aba5-6b6d6123af13','春夜溫故六言二十首  其一六','劉克莊','宋','宋诗','song-poetry','','[]','懲舒之志甚銳，祚宋之言可悲。',28,'全唐诗/poet.song.200000.json','["懲舒之志甚銳，祚宋之言可悲。", "濃墨書姦黨石，長繩拽粹德碑。"]'),
('25a9b70c-2604-48f2-9c6f-a40e6f079d79','春夜溫故六言二十首  其一七','劉克莊','宋','宋诗','song-poetry','','[]','圖覇卧薪嘗膽，爲農拾穗行歌。',28,'全唐诗/poet.song.200000.json','["圖覇卧薪嘗膽，爲農拾穗行歌。", "短衾斂首形矣，高官如跋疐何。"]'),
('cc234e7d-a555-46ea-9186-68713196e392','春夜溫故六言二十首  其一八','劉克莊','宋','宋诗','song-poetry','','[]','絕交書謝伊輩，養生論真吾師。',28,'全唐诗/poet.song.200000.json','["絕交書謝伊輩，養生論真吾師。", "詩無風刺尤妙，史有天刑勿爲。"]'),
('371231fd-6ce8-4b6f-8d6e-441515fe45e9','春夜溫故六言二十首  其一九','劉克莊','宋','宋诗','song-poetry','','[]','辨才師苦死愛，文皇帝得許癡。',28,'全唐诗/poet.song.200000.json','["辨才師苦死愛，文皇帝得許癡。", "溫韜劫陵大盜，蕭翼穿窬小兒。"]'),
('d8bb6756-dc0d-4c6d-8fc6-aa7b4518b400','春夜溫故六言二十首  其二○','劉克莊','宋','宋诗','song-poetry','','[]','相郎穴厨而竊，王相坎壁以藏。',28,'全唐诗/poet.song.200000.json','["相郎穴厨而竊，王相坎壁以藏。", "十襲爲傳家寶，一點無入己贓。"]'),
('3a806c8b-d28f-4ffd-ad14-be1ede35ad7e','挽林韶州  其一','劉克莊','宋','宋诗','song-poetry','','[]','墮落紅巾手，崎嶇白刃間。',48,'全唐诗/poet.song.200000.json','["墮落紅巾手，崎嶇白刃間。", "死難令北面，囚尚著南冠。", "漢使無金贖，相如與璧還。", "都將雙鬢雪，換得兩輪丹。"]'),
('c425ddd6-804e-4144-8ef5-a61c315eabc9','挽林韶州  其二','劉克莊','宋','宋诗','song-poetry','','[]','東起平戎策，鈴齋晝掩扉。',48,'全唐诗/poet.song.200000.json','["東起平戎策，鈴齋晝掩扉。", "身留嶠南老，餉至洛中稀。", "瘴自茅花起，喪同薏苡歸。", "不知湯介子，朝論是耶非。"]'),
('89b404b9-592c-422f-88dd-c3aab3e53f10','和黄戶曹投贈二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','羞問胡奴乞米炊，君恩樸斷老儋祠。',64,'全唐诗/poet.song.200000.json','["羞問胡奴乞米炊，君恩樸斷老儋祠。", "蚤賡殿閣微凉作，晚課田園雜興詩。", "洛下共遊無在者，巖頭末句欲傳誰。", "天公別有相裨補，素髮星星兩鬢垂。"]'),
('62a18ec2-3281-40f3-b5f2-674cdef5b361','和黄戶曹投贈二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','巫醫末技有師生，古道今人鮮復行。',64,'全唐诗/poet.song.200000.json','["巫醫末技有師生，古道今人鮮復行。", "受子雲玄誰卒業，附韓公傳不埋名。", "虱猶可以箭鋒貫，蠅豈能增秤尾輕。", "頗欲他時觀續集，定將蒼老換朱榮。"]'),
('419412ee-18d8-41c5-8f2c-39c081b48924','又二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','萊菔可虀秔可炊，絕勝遠訪碧溪祠。',64,'全唐诗/poet.song.200000.json','["萊菔可虀秔可炊，絕勝遠訪碧溪祠。", "渠能去伴舒爲誥，時有來聽鼎說詩。", "江夏奇童今屬子，金華仙伯更傳誰。", "錦囊倒贈貧家了，不管旁觀笑橐垂。"]'),
('36833224-a569-4817-b5fe-3ef2b7885543','又二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','詩家事業可憐生，骨朽人間有集行。',64,'全唐诗/poet.song.200000.json','["詩家事業可憐生，骨朽人間有集行。", "鍛鍊鬼猶驚險語，折磨天亦妬虛名。", "長騎馿背嫌肩聳，欲拔鯨牙恨力輕。", "吟得擅場成底事，不如黄策挹浮榮。"]'),
('8cb981d8-381e-46c1-af3d-03b77968b831','答楊公朝','劉克莊','宋','宋诗','song-poetry','','[]','昔抱遺編事悅堂，蟇陵宰樹想荒凉。',32,'全唐诗/poet.song.200000.json','["昔抱遺編事悅堂，蟇陵宰樹想荒凉。", "問君鄉土生悲感，家住秦溪又姓楊。"]'),
('23c7b986-3c92-41f8-9bf4-994ace93b245','鶴會三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','晚覺方家總寓言，儋書只說谷神存。',32,'全唐诗/poet.song.200000.json','["晚覺方家總寓言，儋書只說谷神存。", "不煩姹女來丹竈，忽有嬰兒出顖門。"]'),
('cfece5c9-903b-4975-9f5f-95f0208f4ae9','鶴會三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','肉眼安能辨聖凡，有時巾褐過城南。',32,'全唐诗/poet.song.200000.json','["肉眼安能辨聖凡，有時巾褐過城南。", "亦無肘後堪傳汝，且向純陽兩字參。"]'),
('37b57ee9-0669-468b-be73-21ffd9d2d666','鶴會三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','投不貲軀火宅中，須臾鬢雪換顔紅。',32,'全唐诗/poet.song.200000.json','["投不貲軀火宅中，須臾鬢雪換顔紅。", "暮年頗欲從翁去，共過蓬萊聽水風。"]'),
('5dde1053-c60d-4d38-8f0a-7e3a0d0ed107','林知錄和余梅百詠','劉克莊','宋','宋诗','song-poetry','','[]','一已爲多况百哉，得君詩卷久驚猜。',64,'全唐诗/poet.song.200000.json','["一已爲多况百哉，得君詩卷久驚猜。", "乍疑姑射山頭比，誰喚勾芒雪裏迴。", "委壤可憐渠有命，傾城豈是子無媒。", "直須著意描香影，和靖宗人合詠梅。"]'),
('9e2b3449-9aac-4414-b0d5-00e45bc6a8de','送林知錄','劉克莊','宋','宋诗','song-poetry','','[]','狗監知才子，雌堂惜上賓。',48,'全唐诗/poet.song.200000.json','["狗監知才子，雌堂惜上賓。", "歸船載畫重，清俸買書貧。", "已作扶犁叟，難留拄笏人。", "洛英如見問，爲說卧漳濱。"]'),
('6f6a2c0b-09ab-40e3-a7cb-97a9e37cc18b','周天益辭歸延平','劉克莊','宋','宋诗','song-poetry','','[]','自說鐔津上，辛勤葺數楹。',48,'全唐诗/poet.song.200000.json','["自說鐔津上，辛勤葺數楹。", "一家僑寄活，隻手拮据成。", "俗薄詩人厄，州貧太守清。", "聞君不由徑，想見攬衣迎。"]'),
('22027778-7a52-4089-9437-6c3b691d5a5c','送仙遊黄尉','劉克莊','宋','宋诗','song-poetry','','[]','三載仙谿上，蕭然少府廳。',48,'全唐诗/poet.song.200000.json','["三載仙谿上，蕭然少府廳。", "不曾填格日，但見纂圖經。", "黄綬離卑冗，青衿冒典刑。", "泉潮相接壤，尤可奉親庭。"]'),
('4291ce42-e4d4-422a-a72a-a2a0ad94ce35','贈貴上人','劉克莊','宋','宋诗','song-poetry','','[]','貴公葬法妙蓍龜，眼力尤高異管窺。',64,'全唐诗/poet.song.200000.json','["貴公葬法妙蓍龜，眼力尤高異管窺。", "先世曾從牧堂學，前身疑是涅槃師。", "服寒食散方誰驗，營土饅頭計已遲。", "我卜寢丘將斬草，重來莫負老人期。"]'),
('e7fecf8a-5f74-46f8-a1bc-4a34f35fe1fd','次韵黄戶曹問訊二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','理窟騷壇兩罷休，倒持麈柄讓名流。',64,'全唐诗/poet.song.200000.json','["理窟騷壇兩罷休，倒持麈柄讓名流。", "向來袒裼欲暴虎，老去短衣聊飲牛。", "斂退始知顔巷樂，迂疎空抱杞天憂。", "名山何處無靈藥，長笑癡人入海求。"]'),
('3774b946-d76a-4323-9a8d-a014c375dcc1','次韵黄戶曹問訊二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','殘年宜去亦宜休，出處輸渠第一流。',64,'全唐诗/poet.song.200000.json','["殘年宜去亦宜休，出處輸渠第一流。", "華表歸三千歲鶴，具區有四十蹄牛。", "吟薰風殿曾微諷，祖夕陽亭尚隠憂。", "乾鵲噪簷無別喜，書筒詩卷遠相求。"]'),
('3e2bec40-667d-44b6-ae8b-25bb721d7d76','寄題楊𢡟卿孝感堂','劉克莊','宋','宋诗','song-poetry','','[]','哭時聞者亦欷歔，雙鶴隨聲下碧虛。',64,'全唐诗/poet.song.200000.json','["哭時聞者亦欷歔，雙鶴隨聲下碧虛。", "帝出絲綸照穹壤，官施綽楔表門閭。", "今無陶侃誰能爾，古有蘇耽莫是渠。", "華髮史儋曾載筆，尚能濃墨爲君書。"]'),
('52e9a2be-e4f3-476c-b83f-ef93f64065e2','摘玉堂紅皺玉  其一','劉克莊','宋','宋诗','song-poetry','','[]','顆顆苞甘液，年年飫老饕。',24,'全唐诗/poet.song.200000.json','["顆顆苞甘液，年年飫老饕。", "絕勝九千歲，三度竊蟠桃。"]'),
('cb47bbbe-efec-43e2-9dc3-ed00c13197c9','摘玉堂紅皺玉  其二','劉克莊','宋','宋诗','song-poetry','','[]','珍貴均摩勒，甘滋過醴泉。',24,'全唐诗/poet.song.200000.json','["珍貴均摩勒，甘滋過醴泉。", "謂天不吾享，豈不厚誣天。"]'),
('a0548de7-9025-47f5-9c0b-9c79ab659797','樗庵採荔  其一','劉克莊','宋','宋诗','song-poetry','','[]','村叟相持捋白髭，羨儂健似去年時。',32,'全唐诗/poet.song.200000.json','["村叟相持捋白髭，羨儂健似去年時。", "野儒枯槁無師授，傳得單方服荔枝。"]'),
('415e8e01-3de1-414b-b9ea-d41b5273536d','樗庵採荔  其二','劉克莊','宋','宋诗','song-poetry','','[]','墜殻紛紛滿樹間，更拋牆外費防閑。',32,'全唐诗/poet.song.200000.json','["墜殻紛紛滿樹間，更拋牆外費防閑。", "暗中仍被揶揄笑，此老冬烘可熱瞞。"]'),
('5b92baf6-00b4-418f-b4bf-47f0a8b6af44','余平生不至廬山六月廿八日夜夢同孫季蕃游焉林木參天瀑聲如雷山中物色良是一剎甚幽邃傍人告曰此中有不出院僧余與季蕃欣然訪之語未終而覺將曉矣窗外簷溜淋浪紀以二詩  其一','劉克莊','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','似與孫郎有宿期，共穿紫翠探幽奇。',64,'全唐诗/poet.song.200000.json','["似與孫郎有宿期，共穿紫翠探幽奇。", "水簾噴雪非常爽，火傘張空了不知。", "蒙衲僧寧非惠遠，結茅人莫是凝之。", "惜今粉繪無名筆，尚可追摹入拙詩。"]'),
('e5915f34-339f-4ec9-b41b-5b916c9953d4','余平生不至廬山六月廿八日夜夢同孫季蕃游焉林木參天瀑聲如雷山中物色良是一剎甚幽邃傍人告曰此中有不出院僧余與季蕃欣然訪之語未終而覺將曉矣窗外簷溜淋浪紀以二詩  其二','劉克莊','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','泉聲㶁㶁樹蒼蒼，云有高僧占一房。',64,'全唐诗/poet.song.200000.json','["泉聲㶁㶁樹蒼蒼，云有高僧占一房。", "糧絕罕曾起烟火，佛來不肯下禪床。", "緇流誰可傳宗旨，黄敕難招坐道場。", "何必真分一間住，偶爲但過亦清凉。"]'),
('f67eb137-f063-49b8-bb00-36c63ba47e77','虎暴二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','趫捷超山徑，咆哮噉土牆。',48,'全唐诗/poet.song.200000.json','["趫捷超山徑，咆哮噉土牆。", "昔無當道卧，今有稅人場。", "班特歸欄早，韓盧入竇忙。", "四方多伏弩，未可恃雄强。"]'),
('262e5987-1cbd-4fed-8da2-01db228278c2','虎暴二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','噬至飽而止，出爲饑所驅。',48,'全唐诗/poet.song.200000.json','["噬至飽而止，出爲饑所驅。", "東鄰棧失羖，西舍廐亡駒。", "浪說裴旻射，難施抱朴符。", "雌雄已堪畏，况挾小於菟。"]'),
('49a01fff-2e99-4d0b-856c-54b42ea5092f','初秋感事三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','徧閲同參入涅槃，傍觀盡怪老僧頑。',64,'全唐诗/poet.song.200000.json','["徧閲同參入涅槃，傍觀盡怪老僧頑。", "有詩傳世天機淺，無史藏山筆鉞閑。", "夢境瞿莊更喚醒，醉鄉陶阮夾扶還。", "吾廬寂寂人稀至，不是先生愛掩關。"]'),
('063ee712-089f-47b5-8b13-8fe333382dc5','初秋感事三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','跌蕩當年賦兩京，晚拋筆硯事春耕。',64,'全唐诗/poet.song.200000.json','["跌蕩當年賦兩京，晚拋筆硯事春耕。", "達空函啟已心懶，讀夾注書猶眼明。", "金匱舊聞虛論次，香奩少作悔流行。", "而今老病都休也，起聽秋聲百感生。"]'),
('8b7e8c56-70dd-4cc9-8d52-1b6d3f02de44','初秋感事三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','恩放歸田又數期，少猶迂闊况衰遲。',64,'全唐诗/poet.song.200000.json','["恩放歸田又數期，少猶迂闊况衰遲。", "日非夸父追能及，山豈愚公力可移。", "前席虛懷何日報，細旃密啟有天知。", "太陽所燭皆萌達，不照牆陰藿與葵。"]'),
('1f3a2103-4a81-47a2-8e1b-0a2726913db6','贈宇文貢士','劉克莊','宋','宋诗','song-poetry','','[]','君家忠節著先朝，廟院如今稍寂寥。',64,'全唐诗/poet.song.200000.json','["君家忠節著先朝，廟院如今稍寂寥。", "晉代褒勛侯謝澹，唐人詔姓取顔標。", "地寒訪我門羅爵，天定看君世珥貂。", "欲掃空齋同夜話，山荒黄獨尚無苗。"]'),
('ebe6d1a8-5d75-41be-b71f-78c5dae1f440','跋青陽尉古賦','劉克莊','宋','宋诗','song-poetry','','[]','青陽少府筆如椽，袖出騷人體物篇。',64,'全唐诗/poet.song.200000.json','["青陽少府筆如椽，袖出騷人體物篇。", "往昔上林推蜀客，後來赤壁有坡仙。", "自言避地僑江表，誰誦凌雲向上前。", "螢雪一生家萬里，漢庭給札定何年。"]'),
('1eda8430-92e5-461c-9f9a-fcd035807c2d','尉姪寄百雀圖','劉克莊','宋','宋诗','song-poetry','','[]','猶子知余嗜，封來半尺綃。',48,'全唐诗/poet.song.200000.json','["猶子知余嗜，封來半尺綃。", "誰將一兔穎，寫作百鷦鷯。", "具體侔針粟，卑飛集葦苕。", "笑他九萬里，辛苦上雲霄。"]'),
('814f9a98-c2ed-414a-b7bc-414d313a175a','夜坐二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','依約前生是蠹魚，坐窗不覺曉鐘餘。',64,'全唐诗/poet.song.200000.json','["依約前生是蠹魚，坐窗不覺曉鐘餘。", "都忘還笏休官了，渾是擔簦應舉初。", "亥豕安能承謬誤，雪螢尚欲補空疎。", "玄花生眼蜩鳴耳，貪校新抄數板書。"]'),
('6aed0800-9ca4-44b9-b7df-e9a4171436f5','夜坐二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','世法人情已盡拋，深林自占一枝巢。',64,'全唐诗/poet.song.200000.json','["世法人情已盡拋，深林自占一枝巢。", "病來不飲疎歡伯，老去惟書作淡交。", "馬尾動煩刊筆誤，蠅頭尚可就燈抄。", "山空月落商歌起，不管秋風捲屋茅。"]'),
('eff29944-874a-40ac-8e23-9b79eff1069f','秋旱繼以大風即事十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','雖作堯時擊壤民，田家憂樂尚關身。',32,'全唐诗/poet.song.200000.json','["雖作堯時擊壤民，田家憂樂尚關身。", "抱珠難起龍公睡，走石誰撩颶毋嗔。"]'),
('b234ce58-a856-41d1-b8bd-ba090cfc98a2','秋旱繼以大風即事十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','蘋末蕭蕭忽怒飛，松公欲仆竹君欹。',32,'全唐诗/poet.song.200000.json','["蘋末蕭蕭忽怒飛，松公欲仆竹君欹。", "無人委曲鎸風伯，晚稻方花最怕吹。"]'),
('e098cb32-ab10-45dc-9e56-53973dbeb1a9','秋旱繼以大風即事十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','作苦三時逸在冬，安知一簣尚虧功。',32,'全唐诗/poet.song.200000.json','["作苦三時逸在冬，安知一簣尚虧功。", "愁聞地籟吹羊角，不見天瓢滴馬鬃。"]'),
('2f0aa86c-c126-4d05-bd5f-6228e5782a18','秋旱繼以大風即事十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','曾立龍墀忝近臣，深知玉座最憂民。',32,'全唐诗/poet.song.200000.json','["曾立龍墀忝近臣，深知玉座最憂民。", "近傳奎畫蠲租賦，稽首觚稜祝聖人。"]'),
('efa0636b-e9fd-46a3-8764-4bfe7fb50f69','秋旱繼以大風即事十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','吳中見說亦枯焦，勺水如金汲路遥。',32,'全唐诗/poet.song.200000.json','["吳中見說亦枯焦，勺水如金汲路遥。", "但有清塵無灑道，不能破塊止鳴條。"]'),
('bf78ce99-bedf-4321-9a55-b274921f1fac','秋旱繼以大風即事十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','抱甕區區溉旱苗，忍饑終勝似操瓢。',32,'全唐诗/poet.song.200000.json','["抱甕區區溉旱苗，忍饑終勝似操瓢。", "飲堯井水耕堯野，偶作樵歌亦譽堯。"]'),
('1193fdc4-498e-4c21-a3fd-aae18a1d0fe4','秋旱繼以大風即事十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','古人一念感而通，不待焚巫祭雨工。',32,'全唐诗/poet.song.200000.json','["古人一念感而通，不待焚巫祭雨工。", "湯反諸身防六事，漢移其咎責三公。"]'),
('aefd392a-31a2-4b5d-8adf-628c79179e9c','秋旱繼以大風即事十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','老農相戒早輸官，何日爰書得少寬。',32,'全唐诗/poet.song.200000.json','["老農相戒早輸官，何日爰書得少寬。", "明府安知簾外事，路人却見水中瘢。"]'),
('719c3cbd-2066-440b-95c8-353fdb109f88','秋旱繼以大風即事十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','禹功遠矣世猶思，誰穀吾州頼兩陂。',32,'全唐诗/poet.song.200000.json','["禹功遠矣世猶思，誰穀吾州頼兩陂。", "待與閟宮碑歲月，併爲神作送迎詩。"]'),
('894929db-422c-4a80-812f-d8febaed4c46','秋旱繼以大風即事十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','少耽章句老明農，無意爲文忽自工。',32,'全唐诗/poet.song.200000.json','["少耽章句老明農，無意爲文忽自工。", "戲作小詩說場圃，細看似可續豳風。"]'),
('90062234-591b-4efe-bd48-958f1a136a37','雜興十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','蒼苔滿意上庭除，應爲新來客屨疎。',64,'全唐诗/poet.song.200000.json','["蒼苔滿意上庭除，應爲新來客屨疎。", "老圃寧無螬半李，貧家尚有鼠餘蔬。", "身光退士吟招隠，兒勸尊公賦遂初。", "已與山靈盟歃了，龍鍾斷不就安車。"]'),
('28d611e6-ccae-481b-9025-d77a691a7162','雜興十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','曾忝開元供奉班，君恩全護放還山。',64,'全唐诗/poet.song.200000.json','["曾忝開元供奉班，君恩全護放還山。", "諸公縱欲俎豆汝，老子安能筆硯間。", "試拂毛錐嗟已禿，便扶靈壽亦何顔。", "迴頭猿鶴休相笑，猶勝周顒去不還。"]'),
('25106cd2-e297-42ae-ab43-216be1e3b48a','雜興十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','少喜清談拙自謀，行年至此復焉求。',64,'全唐诗/poet.song.200000.json','["少喜清談拙自謀，行年至此復焉求。", "歸休誰肯爭幽谷，貧殺猶堪買沃洲。", "笛作曾垂安石淚，扇遮難護彥回羞。", "伯陽老去差姦黠，真出函關不少留。"]'),
('4893ecc7-4efc-461d-baa1-e761aab16518','雜興十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','旋插疎籬設矮扉，僅容老子自娛嬉。',64,'全唐诗/poet.song.200000.json','["旋插疎籬設矮扉，僅容老子自娛嬉。", "國蝸角上何嫌小，巢鳥窠邊不覺危。", "石槨無陳雞絮者，朱門有設雀羅時。", "平泉花木奇樟檜，辛苦栽培竟屬誰。"]'),
('71312aba-347d-4f2f-a2d5-6fbb29bdd498','雜興十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','鬢髮蕭蕭牙齒疎，耄荒不記兔園書。',64,'全唐诗/poet.song.200000.json','["鬢髮蕭蕭牙齒疎，耄荒不記兔園書。", "有時待月□□榭，驀地看花命小車。", "早慕兩龔辭病去，晚從二仲卜鄰居。", "阿戎解執牙籌耳，嵇阮中間却頓渠。"]'),
('f6ea699a-529b-4a1b-8a63-3c4ef80591d7','雜興十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','何止才疎亦命慳，暮年身世寄田間。',64,'全唐诗/poet.song.200000.json','["何止才疎亦命慳，暮年身世寄田間。", "望塵早不游金谷，投筆今難戍玉關。", "日禱泥龍晴自若，晝騎秧馬夕方還。", "跳丸只了東西走，不道能蒼壯士顔。"]'),
('63a235f3-108e-4ffe-89ce-2de70e5fe468','雜興十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','淳熙以後紹熙前，曹馬灰寒不復燃。',64,'全唐诗/poet.song.200000.json','["淳熙以後紹熙前，曹馬灰寒不復燃。", "寧作歸來詞引避，可爲勸進表求全。", "斜川妙語超言外，廣武狂談發酒邊。", "頼有遺文堪可質，世誰陶阮豈其然。"]'),
('a0b80d8f-c15c-4c3d-b74e-70c50539786b','雜興十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','諸公衮衮一番新，留得山林著放臣。',64,'全唐诗/poet.song.200000.json','["諸公衮衮一番新，留得山林著放臣。", "鞍破馬移它廐去，巢空燕覺主家貧。", "甥陪棋局何須客，兒舉籃輿不覓人。", "膜外浮榮酒中趣，看來二者孰關身。"]'),
('0990d48d-1b37-4b84-8d8e-b14e500ff111','雜興十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','迴首危途尚可驚，三家村裏送餘生。',64,'全唐诗/poet.song.200000.json','["迴首危途尚可驚，三家村裏送餘生。", "入無奧主常孤立，歸有鄰翁可耦耕。", "駡坐不聞因耳重，懸車已决覺身輕。", "小詩何必諸公誦，自向閒時詠太平。"]'),
('cf1c40db-9580-44b5-8451-3bcf97c8a758','雜興十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','古書踳駁承訛久，新義支離折衷難。',64,'全唐诗/poet.song.200000.json','["古書踳駁承訛久，新義支離折衷難。", "孔墨達觀無異道，觸蠻角立有爭端。", "壁中科斗經傳寫，甕裏醯雞味筆殘。", "老子暮年親勘破，束書閣上不須看。"]'),
('d6d50880-7131-4c6b-9d84-df6470cd5988','太守宋監丞新三先生祠刊二劉遺文以二詩紀實  其一','劉克莊','宋','宋诗','song-poetry','','[]','兩翁仕不至丞郎，名節能流百世芳。',64,'全唐诗/poet.song.200000.json','["兩翁仕不至丞郎，名節能流百世芳。", "窮巷號爲通德里，舊書藏在善和坊。", "古楹日敝加丹刻，老柏年深益黛蒼。", "太守懷賢崇教化，鄉先生盍祭于鄉。"]'),
('ed89b052-b2f7-41a1-98c8-0fa5fc603ec2','太守宋監丞新三先生祠刊二劉遺文以二詩紀實  其二','劉克莊','宋','宋诗','song-poetry','','[]','俱事重華著直聲，百年藏藁未流行。',64,'全唐诗/poet.song.200000.json','["俱事重華著直聲，百年藏藁未流行。", "世評諫疏如劉向，公讀遺書感樂生。", "里有襄陽耆舊傳，史無齊魯大臣名。", "孤孫白首荒家學，甘作滕民負耒耕。"]'),
('94e01e21-a1b1-4983-9706-e45fc7437263','使君次韻再賦二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','當年雙璧甲科郎，未羨燕山五桂芳。',64,'全唐诗/poet.song.200000.json','["當年雙璧甲科郎，未羨燕山五桂芳。", "奏賦何曾因狗監，諫書直乞罷鷹坊。", "聚螢窗冷韋編蠹，下馬陵蕪宰樹蒼。", "不是使君來北海，邦人豈識鄭公鄉。"]'),
('9d1fbb53-dff1-4e0f-b728-3c18c53ac163','使君次韻再賦二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','下車不識疾呼聲，郡政清平教亦行。',64,'全唐诗/poet.song.200000.json','["下車不識疾呼聲，郡政清平教亦行。", "曹相治齊賓蓋老，何侯在楚厚龔生。", "甘棠通國俱懷惠，遺藁因公得記名。", "老受一廛無以報，先疇不腆尚堪耕。"]'),
('b7f71a37-45be-48ec-91e0-0a439e96a216','芙蓉六言四首  其一','劉克莊','宋','宋诗','song-poetry','','[]','東林百草摇落，老圃數株白紅。',28,'全唐诗/poet.song.200000.json','["東林百草摇落，老圃數株白紅。", "楚客空悲歲晏，班姬錯怨秋風。"]'),
('df23eed2-8444-498b-bf1b-c6277a58b35b','芙蓉六言四首  其二','劉克莊','宋','宋诗','song-poetry','','[]','雪白露初泣曉，酒紅日欲平西。',28,'全唐诗/poet.song.200000.json','["雪白露初泣曉，酒紅日欲平西。", "王姬何彼穠矣，美人清揚婉兮。"]'),
('6204e9a6-dc3e-4477-9f8e-c543c12b42f0','芙蓉六言四首  其三','劉克莊','宋','宋诗','song-poetry','','[]','月地不離人世，花城豈必仙家。',28,'全唐诗/poet.song.200000.json','["月地不離人世，花城豈必仙家。", "且容康節向月，不羨曼卿主花。"]'),
('8853ae31-bdf3-4ef4-9e3a-4ae66bbbb7ff','芙蓉六言四首  其四','劉克莊','宋','宋诗','song-poetry','','[]','羞作太真妃帳，寧爲屈大夫裳。',28,'全唐诗/poet.song.200000.json','["羞作太真妃帳，寧爲屈大夫裳。", "帝賞此花高節，別賜一名拒霜。"]'),
('d24c0fa1-ca86-4460-a916-f8d276f2c3be','端明無惰趙公哀詩二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','憶昔並居封駁地，相期叶力共推車。',64,'全唐诗/poet.song.200000.json','["憶昔並居封駁地，相期叶力共推車。", "慣看東閣批黄敕，同向南衙沮白麻。", "高興竟歸安石墅，大疑猶訪魏舒家。", "僅存一鑑今亡矣，想見昕朝亦嘆嗟。"]'),
('3be8704b-c98e-41c2-9ad2-2866aa9f41c2','端明無惰趙公哀詩二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','惜身顧影世滔滔，歎息斯人振古豪。',64,'全唐诗/poet.song.200000.json','["惜身顧影世滔滔，歎息斯人振古豪。", "中壘老猶獻封事，三閭去尚作離騷。", "無金可遺貧如故，加璧難招節更高。", "有淚數行芻一束，若爲飛渡浙江濤。"]'),
('41f218b8-06d9-4a6b-9d44-bdf6de3f941e','惜筍二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','主人尤愛竹，老病鮮窺園。',48,'全唐诗/poet.song.200000.json','["主人尤愛竹，老病鮮窺園。", "粟鼠競携子，籜龍空長孫。", "化爲玉版去，留得錦綳存。", "雖有監臨者，貪眠晝閉門。"]'),
('afad8d7d-bd13-448d-b513-1188d60be411','惜筍二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','手移孤竹氏，遍地長孫枝。',48,'全唐诗/poet.song.200000.json','["手移孤竹氏，遍地長孫枝。", "挺挺堪傳嫡，疎疎欲咎誰。", "汝饞猶可忍，吾俗恐難醫。", "雖有監臨法，寬柔不忍施。"]'),
('0765b004-8449-402f-8c8a-ede98f4e5701','贈天台陳相士','劉克莊','宋','宋诗','song-poetry','','[]','徑草齊腰人跡稀，凌晨忽有叩柴扉。',64,'全唐诗/poet.song.200000.json','["徑草齊腰人跡稀，凌晨忽有叩柴扉。", "遠携吾子出疆贄，來看先生杜德機。", "許燕頷侯行且驗，評鳶肩夭是耶非。", "惜無斗酒堪澆汝，一曲勞歌贈北歸。"]'),
('2fb69c5a-43b9-4e95-9a90-4b361e2dccf7','贈日者程士熙','劉克莊','宋','宋诗','song-poetry','','[]','竹溪滿口相稱說，韓慥林間一輩流。',64,'全唐诗/poet.song.200000.json','["竹溪滿口相稱說，韓慥林間一輩流。", "少不如人今已老，天之命我子難修。", "桑蓬壯志無成就，箕斗虛名有悔尤。", "試爲端蓍占歲晚，幾囤棗實幾蹄牛。"]'),
('06f38c78-1fff-4840-91c8-a742063b8ee1','挽鄭永福','劉克莊','宋','宋诗','song-poetry','','[]','竹間梧畔故應佳，非但才高詩亦葩。',64,'全唐诗/poet.song.200000.json','["竹間梧畔故應佳，非但才高詩亦葩。", "世胄蚤通樞相譜，里人知是大魁家。", "誰言陶令纔爲米，不遣潘郎再種花。", "□□雲深華表遠，北風無頼送哀笳。"]'),
('ab2f7162-3ae1-40ff-9cc9-aa202556de6a','寄題趙尉若鈺蘭所六言四首  其一','劉克莊','宋','宋诗','song-poetry','','[]','平生憎鮑魚肆，何處割山麝房。',28,'全唐诗/poet.song.200000.json','["平生憎鮑魚肆，何處割山麝房。", "試與君評花品，不如渠有國香。"]'),
('344e1ff0-7e63-46df-be48-3bd38e1f9fc2','寄題趙尉若鈺蘭所六言四首  其二','劉克莊','宋','宋诗','song-poetry','','[]','屈子平章荃蕙，荀卿區別芷槐。',28,'全唐诗/poet.song.200000.json','["屈子平章荃蕙，荀卿區別芷槐。", "志潔真飲露者，性惡似漸滫來。"]'),
('d496a449-aa98-4ae8-99b7-c7d03239836b','寄題趙尉若鈺蘭所六言四首  其三','劉克莊','宋','宋诗','song-poetry','','[]','高標可敬難狎，幽香似有如無。',28,'全唐诗/poet.song.200000.json','["高標可敬難狎，幽香似有如無。", "世間少別花者，海上多逐臭夫。"]'),
('98e4ac66-3d4c-43a0-80c7-86e71857c36e','寄題趙尉若鈺蘭所六言四首  其四','劉克莊','宋','宋诗','song-poetry','','[]','遶林尋香不見，對花寫貌失真。',28,'全唐诗/poet.song.200000.json','["遶林尋香不見，對花寫貌失真。", "癡人鼻孔無辨，俗子毫端有塵。"]'),
('7bfff010-5bf2-4cab-856c-86c44de3df6d','答括士李同二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','憶昔駸駸逼要津，迂疎誰遣批龍鱗。',64,'全唐诗/poet.song.200000.json','["憶昔駸駸逼要津，迂疎誰遣批龍鱗。", "羞爲慶曆一不肖，妄意熙寧三舍人。", "鬼質若非天奪魄，纍臣豈有地容身。", "江湖社友應相問，爲說蕭蕭雪鬢新。"]'),
('481240ce-0d7d-4018-88fe-b12c0b762b9d','答括士李同二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','禿翁門巷冷涔涔，僮報詩人遠見尋。',64,'全唐诗/poet.song.200000.json','["禿翁門巷冷涔涔，僮報詩人遠見尋。", "微露毫芒足奇怪，少加煅煉愈高深。", "肯來鄴下從公幹，待向關中說季心。", "黄鵠池邊需應制，勸君莫學凍蛩吟。"]'),
('9692f167-dfbb-46e2-971d-5eabbde553a0','贈永福黄國孫','劉克莊','宋','宋诗','song-poetry','','[]','尚記鳴琴錦水濱，華宗贊府偶同寅。',64,'全唐诗/poet.song.200000.json','["尚記鳴琴錦水濱，華宗贊府偶同寅。", "涉哦松筆規隨我，傳種花詞膾炙人。", "潘令鬢毛兩堆雪，崔丞詩賦一微塵。", "覽君姓氏詢鄉里，舊事關心感慨頻。"]'),
('a39fba82-6c2d-437e-b6e4-d8ae8940c656','强甫西上','劉克莊','宋','宋诗','song-poetry','','[]','平進差賢似躁求，乃翁豈不爲兒謀。',64,'全唐诗/poet.song.200000.json','["平進差賢似躁求，乃翁豈不爲兒謀。", "今寒畯士難京秩，古子男邦亦小侯。", "翹館詎宜頻造請，孤山雖好勿淹留。", "誰言此老心如鐵，臨別無端作許愁。"]'),
('c8d24514-b392-4e19-8fcb-a8c0e29a944a','挽薛潮州','劉克莊','宋','宋诗','song-poetry','','[]','醇謹真賢胄，廉能亦吏師。',48,'全唐诗/poet.song.200000.json','["醇謹真賢胄，廉能亦吏師。", "潘花一手種，韓木百年思。", "良友招魂些，遺民墮淚碑。", "今無黄絹筆，書墓嘆吾衰。"]'),
('90348dd5-bf81-4276-84cb-577af2d79293','留別表弟方時父二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','四壁蕭蕭落葉聲，招留聊試子交情。',64,'全唐诗/poet.song.200000.json','["四壁蕭蕭落葉聲，招留聊試子交情。", "不應華屋延珠履，得似蓬窗共鐵檠。", "襆被都無三宿戀，重裘未覺一寒生。", "暮年彼此懽悰薄，相對清談聽斷更。"]'),
('a7318baf-a58d-41c9-8202-6fea5885c1ee','留別表弟方時父二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','憶昔分携今再閏，君猶黑鬢我霜顛。',64,'全唐诗/poet.song.200000.json','["憶昔分携今再閏，君猶黑鬢我霜顛。", "絕憐盧弟真才子，若比殷兄尚少年。", "渭北幾時重把酒，山陰作麽便迴船。", "未知後會平安否，搔首臨風意惘然。"]'),
('c4660d34-a712-44ee-bbe2-c23df0409b2d','輓方宜人二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','貧道我兒孝，姑云此婦賢。',48,'全唐诗/poet.song.200000.json','["貧道我兒孝，姑云此婦賢。", "諸郎丹穴種，夫子玉堂仙。", "□□□寧忍，煎膠法不傳。", "多情潘騎省，應賦悼亡篇。"]'),
('be4b119d-8d86-4735-b984-38e4275a6489','輓方宜人二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','分斷金釵股，全遮玉鏡輝。',48,'全唐诗/poet.song.200000.json','["分斷金釵股，全遮玉鏡輝。", "竟令鸞獨舞，愁見雉雙飛。", "月照梁鴻案，塵凝孟母機。", "平生竺乾學，至此是真歸。"]'),
('d2d2e828-9ad3-4835-9189-caff128dc301','記顔二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','不凍肩山聳，方暄鬢雪濃。',48,'全唐诗/poet.song.200000.json','["不凍肩山聳，方暄鬢雪濃。", "或云壽者相，敢道德人容。", "補助無靈藥，扶持頼瘦筇。", "傍觀莫相笑，年事合龍鍾。"]'),
('5eace4fe-d117-4e27-8dcc-bcf2d686dd9b','記顔二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','恰纔猶兩髧，倏忽已雙皤。',48,'全唐诗/poet.song.200000.json','["恰纔猶兩髧，倏忽已雙皤。", "昔似衛洗馬，今成郭橐駝。", "窩中老康節，龕裏活彌陀。", "縱使加冠劍，其如醜怪何。"]'),
('2ee89630-60d4-4a6c-9704-063e6dc4ab1c','田舍即事十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','閩土資生少，農家作苦多。',48,'全唐诗/poet.song.200000.json','["閩土資生少，農家作苦多。", "尚能蓋牛屋，未肯入雞窠。", "社裏戴花舞，原頭拾穗歌。", "設令生漢代，堪冠力田科。"]'),
('f71bcb42-ac1f-4230-97e4-93af93c2016d','田舍即事十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','場圃先修築，囷倉次補完。',48,'全唐诗/poet.song.200000.json','["場圃先修築，囷倉次補完。", "坐居鄰叟下，身雜役夫間。", "荷蓧侵星出，肩禾束藴還。", "小窗殘卷在，未敢便偷閑。"]'),
('07c0f0a8-81bf-4a25-afb8-770d1d260d39','田舍即事十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','此日田舍漢，當年省禁臣。',48,'全唐诗/poet.song.200000.json','["此日田舍漢，當年省禁臣。", "絲綸隔世事，蓑笠暮年身。", "龍棄真初祖，羊求在近鄰。", "南朝足名士，吾獨愛吾真。"]'),
('fc6f805d-cdcc-4543-b157-397ac31f32df','田舍即事十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','事國嘗陳力，明農晚乞骸。',48,'全唐诗/poet.song.200000.json','["事國嘗陳力，明農晚乞骸。", "擊鮮兒勿費，執醤老難偕。", "僅可從沮溺，安能望賜回。", "幾曾識奇字，門外客休來。"]'),
('fab1d156-cafe-44df-a565-14a2ef4cfe94','田舍即事十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','小築三家聚，新篘萬戶春。',48,'全唐诗/poet.song.200000.json','["小築三家聚，新篘萬戶春。", "昔豪幾腐脅，今病罕沾唇。", "太古華胥氏，豐年畏壘人。", "超然市朝外，未易葛天民。"]'),
('c00056d8-b87b-4c19-bbb0-437876b9fdb6','田舍即事十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','疇昔元疎懶，如今轉耄荒。',48,'全唐诗/poet.song.200000.json','["疇昔元疎懶，如今轉耄荒。", "都忘高士傳，僅記庶人章。", "棲畝牛羊飽，開囷雀鼠忙。", "老農識慙愧，先議道官倉。"]'),
('4ffbaaa6-8ccd-444e-8b47-ec66192bb7f1','田舍即事十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','小榭無丹雘，低牆略塈茨。',48,'全唐诗/poet.song.200000.json','["小榭無丹雘，低牆略塈茨。", "辛勤趨穡事，快活過花時。", "懶獻嘉禾頌，閑賡滯穗詩。", "幸生太平世，不樂復何爲。"]'),
('43394ff2-134c-4adf-82f0-eff95c6c1303','田舍即事十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','淺甽須穿浚，荒畦要糞除。',48,'全唐诗/poet.song.200000.json','["淺甽須穿浚，荒畦要糞除。", "何嘗舍耒出，亦或带經鋤。", "古有神農學，今傳氾勝書。", "野儒曾涉獵，未可議空疎。"]'),
('11e22928-3e4e-4f5c-b077-2ea436e03224','田舍即事十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','比屋篝車滿，深林鼓笛喧。',48,'全唐诗/poet.song.200000.json','["比屋篝車滿，深林鼓笛喧。", "簇花迎婦擔，拋果浴兒盆。", "古禮曾求野，先民或灌園。", "子孫記吾語，切勿羨華軒。"]'),
('d09961d9-c097-4398-8cc9-d01996498b6a','田舍即事十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','凋邑租符緊，荒祠木偶新。',48,'全唐诗/poet.song.200000.json','["凋邑租符緊，荒祠木偶新。", "吏談長官健，巫託社公嗔。", "烹犬看承客，吹螺降送神。", "二豪懷肉返，去誑別村人。"]'),
('a6f6efd5-7279-444b-8e93-6972c76b949f','輓方倅巖仲二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','上世師朱氏，慈闈祖艾軒。',48,'全唐诗/poet.song.200000.json','["上世師朱氏，慈闈祖艾軒。", "惓惓纂遺緒，歷歷識前言。", "柳記多先友，遷書頼外孫。", "悲哉此奇士，寂寞向寒原。"]'),
('c43a9cb9-5d90-41ca-9a40-dd843a4d0dd6','輓方倅巖仲二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','身後青名在，辛勤卜此阡。',48,'全唐诗/poet.song.200000.json','["身後青名在，辛勤卜此阡。", "書丹翰林筆，埋玉息庵錢。", "葛帔孤誰託，蒿簪婦亦賢。", "許丞無事業，千古以廉傳。"]'),
('90f4234d-9146-413e-a2fe-96bba2fe8bb5','輓鄭郎公衛夫婦二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','燈窗磨歲月，竹帛勒功名。',48,'全唐诗/poet.song.200000.json','["燈窗磨歲月，竹帛勒功名。", "晦迹溪西隠，終身谷口耕。", "似山猶有漏，於佛悟無生。", "尚喜家駒駿，何慚輔嗣甥。"]'),
('3b2d191f-537c-4bca-ac32-3c7c9d02191d','輓鄭郎公衛夫婦二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','遺言傳屬纊，內則冠幽閨。',48,'全唐诗/poet.song.200000.json','["遺言傳屬纊，內則冠幽閨。", "劉尹真長妹，黔婁處士妻。", "鸞離暮年恨，鶴弔凍雲迷。", "慧性無生滅，幡花導向西。"]'),
('d92f23aa-9e06-4157-9de2-87277c8fd42b','題同班小錄  其一','劉克莊','宋','宋诗','song-poetry','','[]','猶記甲申引見，傳頭幾度春風。',28,'全唐诗/poet.song.200000.json','["猶記甲申引見，傳頭幾度春風。", "短夢聽鈞天樂，一生泣鼎湖弓。"]'),
('17b42755-b0c1-40d8-9532-a2a7a54e7ece','題同班小錄  其二','劉克莊','宋','宋诗','song-poetry','','[]','周章鶴碧朝服，咫尺猩紅御袍。',28,'全唐诗/poet.song.200000.json','["周章鶴碧朝服，咫尺猩紅御袍。", "風號先帝陵木，霜著孤臣鬢毛。"]'),
('aae3345e-970b-4db7-9f88-0c8a52ba4dd2','題同班小錄  其三','劉克莊','宋','宋诗','song-poetry','','[]','帳殿久移南內，橋山已隔西興。',28,'全唐诗/poet.song.200000.json','["帳殿久移南內，橋山已隔西興。", "同時謁帝評事，回首不忘茂陵。"]'),
('ea9c3325-0777-4b09-95d1-997c5e55d927','丁巳啟建二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','一息營升斗，留翁寂寞濱。',24,'全唐诗/poet.song.200000.json','["一息營升斗，留翁寂寞濱。", "白頭携暮子，來作祝堯人。"]'),
('5ce6b811-ee43-46c8-bbe8-6b33f6b39b67','丁巳啟建二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','有意祝靈椿，無堪獻野芹。',24,'全唐诗/poet.song.200000.json','["有意祝靈椿，無堪獻野芹。", "玉杯真繆巧，金鏡最忠勤。"]'),
('5e7593e3-d5b7-47d8-9c96-e33f1c9db4b9','夜坐二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','坐久烏薪盡，呼童掃葉忙。',48,'全唐诗/poet.song.200000.json','["坐久烏薪盡，呼童掃葉忙。", "海風過雪冷，冬夜抵年長。", "故紙真糟粕，枯骴孰臭香。", "老無閑記性，讀罷轉頭忘。"]'),
('12e56e2f-72b6-4ca1-b743-6417af809fe2','夜坐二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','併擁三重絮，猶新二尺檠。',48,'全唐诗/poet.song.200000.json','["併擁三重絮，猶新二尺檠。", "屋高先見月，城遠忽聞更。", "藜杖光芒歇，茅柴力量輕。", "若非簷鐵響，淡殺老書生。"]'),
('43adc7d2-1b0e-4c79-a5d7-2233db81ae3a','南山感舊  其一','劉克莊','宋','宋诗','song-poetry','','[]','髫齔隨二親，旅泊承天寺。',24,'全唐诗/poet.song.200000.json','["髫齔隨二親，旅泊承天寺。", "姆抱殿上嬉，忽覩瞿曇氏。"]'),
('4b69890d-0abf-45eb-a111-b9e108fd3240','南山感舊  其二','劉克莊','宋','宋诗','song-poetry','','[]','自從出腹來，未嘗識奇偉。',24,'全唐诗/poet.song.200000.json','["自從出腹來，未嘗識奇偉。", "顧瞻忽眩晃，冷汗如潑水。"]'),
('e87cbed2-ea76-4f5a-a911-0404822e5d14','南山感舊  其三','劉克莊','宋','宋诗','song-poetry','','[]','戰掉病三日，湯熨乃能起。',24,'全唐诗/poet.song.200000.json','["戰掉病三日，湯熨乃能起。", "譬如秦武陽，震慴白帝子。"]'),
('72841d26-31fe-4219-9893-92cf2010c217','南山感舊  其四','劉克莊','宋','宋诗','song-poetry','','[]','彈指七十年，顔髮遽如此。',24,'全唐诗/poet.song.200000.json','["彈指七十年，顔髮遽如此。", "棒喝夾攻之，碓磨備嘗矣。"]'),
('fc9a9b09-b282-4fc1-86f1-ce0c74b38f22','南山感舊  其五','劉克莊','宋','宋诗','song-poetry','','[]','既具頂門眼，逐得少林髓。',24,'全唐诗/poet.song.200000.json','["既具頂門眼，逐得少林髓。", "南山梵王宮，規模自唐始。"]'),
('1860df85-0c6a-4f72-87a1-9a0bb7fda9c3','南山感舊  其六','劉克莊','宋','宋诗','song-poetry','','[]','輪奐絕鉅麗，像設尤卓詭。',24,'全唐诗/poet.song.200000.json','["輪奐絕鉅麗，像設尤卓詭。", "瓣香大雄前，恍然憶稚齒。"]'),
('1c731b65-b088-4aaa-a083-893592c862f3','南山感舊  其七','劉克莊','宋','宋诗','song-poetry','','[]','儂久離怖畏，佛亦生歡喜。',24,'全唐诗/poet.song.200000.json','["儂久離怖畏，佛亦生歡喜。", "却看丈六身，僬僥國人爾。"]'),
('b069ae01-3641-4049-8f74-801e55565542','挽陳建昌','劉克莊','宋','宋诗','song-poetry','','[]','一麾踰嶠幾星霜，歲晚乘雲覲帝傍。',64,'全唐诗/poet.song.200000.json','["一麾踰嶠幾星霜，歲晚乘雲覲帝傍。", "方喜吾丘來春計，又聞翁子去懷章。", "百弓別業雖清曠，九尺長身已老蒼。", "原上悲風吹宰樹，傷心雞絮莫携將。"]'),
('0fee8c84-755e-499e-9065-793c15347792','連日寒甚懷强甫二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','同雲作色日潜輝，咄咄玄冥未霽威。',64,'全唐诗/poet.song.200000.json','["同雲作色日潜輝，咄咄玄冥未霽威。", "驛使能無一枝寄，客程應有六花飛。", "烏公恩重宜親謁，絳老年高可蚤歸。", "想見仙霞三尺雪，布衾如鐵起添衣。"]'),
('9abee2ff-0be2-49e8-bb7d-fad7895616f6','連日寒甚懷强甫二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','人生各有稻粱謀，暫去家庭作遠遊。',64,'全唐诗/poet.song.200000.json','["人生各有稻粱謀，暫去家庭作遠遊。", "年事但看翁齒髮，天寒深念汝衣裘。", "履霜我獨知琴操，立雪誰來問話頭。", "但願茅簷相保守，千書說不盡離愁。"]'),
('662bfb9b-7972-446b-8f5b-1bc2a9af6cb2','夜讀傳燈雜書六言八首  其一','劉克莊','宋','宋诗','song-poetry','','[]','曾爲魔女攝入，亦被罔明喚迴。',28,'全唐诗/poet.song.200000.json','["曾爲魔女攝入，亦被罔明喚迴。", "錦覆陷穽可畏，鐵鑄門關勿開。"]'),
('eac3092e-9954-4b7b-9f43-d426c19639e8','夜讀傳燈雜書六言八首  其二','劉克莊','宋','宋诗','song-poetry','','[]','稍喜世緣漸薄，尚嫌家事相關。',28,'全唐诗/poet.song.200000.json','["稍喜世緣漸薄，尚嫌家事相關。", "种子入豹林谷，龐公遯鹿門山。"]'),
('b472e917-2bc3-49a0-8f8e-b1e1fbd5248d','夜讀傳燈雜書六言八首  其三','劉克莊','宋','宋诗','song-poetry','','[]','達人蘧蘧夢覺，獃漢屑屑往來。',28,'全唐诗/poet.song.200000.json','["達人蘧蘧夢覺，獃漢屑屑往來。", "剪斷郭郎線索，送還趙老燈臺。"]'),
('d51958f0-b558-4f76-8160-51a4c17dae47','夜讀傳燈雜書六言八首  其四','劉克莊','宋','宋诗','song-poetry','','[]','神秀元來得法，誌公了不見幾。',28,'全唐诗/poet.song.200000.json','["神秀元來得法，誌公了不見幾。", "半夜一鉢南邁，明朝隻履西歸。"]'),
('8266f119-8415-4dda-9da8-ee3b0eb45633','夜讀傳燈雜書六言八首  其五','劉克莊','宋','宋诗','song-poetry','','[]','麟經之筆既絕，蠶室之書遂行。',28,'全唐诗/poet.song.200000.json','["麟經之筆既絕，蠶室之書遂行。", "聃非二子同傳，齊魯兩生失名。"]'),
('a12a1340-eff6-410e-aea4-b13725c1c402','夜讀傳燈雜書六言八首  其六','劉克莊','宋','宋诗','song-poetry','','[]','悠然東籬把菊，登彼西山采薇。',28,'全唐诗/poet.song.200000.json','["悠然東籬把菊，登彼西山采薇。", "重華去我已久，神農沒矣安歸。"]'),
('db1d97f7-2bd8-4b0b-acc9-c944b7f5dc97','夜讀傳燈雜書六言八首  其七','劉克莊','宋','宋诗','song-poetry','','[]','贈半山翁甚美，責臨淄公不輕。',28,'全唐诗/poet.song.200000.json','["贈半山翁甚美，責臨淄公不輕。", "大蘇肯念舊惡，小宋猶有宿酲。"]'),
('f1b428a1-1905-41f2-8091-22b9fb5a7ab5','夜讀傳燈雜書六言八首  其八','劉克莊','宋','宋诗','song-poetry','','[]','孫以獻公稱祖，妻以康子謚夫。',28,'全唐诗/poet.song.200000.json','["孫以獻公稱祖，妻以康子謚夫。", "何必議郎博士，千秋萬歲稱呼。"]'),
('819858b5-3379-4865-a9cb-41a05d44f12f','仲晦昆仲求近稿戲答二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','過去生平一念差，偶因薄技忝清華。',64,'全唐诗/poet.song.200000.json','["過去生平一念差，偶因薄技忝清華。", "寧吟韓子將歸操，不草韋郎起復麻。", "綺語預愁無間獄，綸言見笑當行家。", "而今老矣全瘖了，匹似枯株不著花。"]'),
('e58b6b81-5b84-40f0-98e2-bcef01051bb0','仲晦昆仲求近稿戲答二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','辛苦搜腸更撚鬚，適資談者指瑕瑜。',64,'全唐诗/poet.song.200000.json','["辛苦搜腸更撚鬚，適資談者指瑕瑜。", "中郎碑好猶名愧，吏部銘高未免諛。", "餘忿燕泥能道否，遺言鶴唳可聞乎。", "從今一字休思索，千古文人一律愚。"]'),
('836a3b5b-f8d2-4e7d-9983-59e07a1bb89d','贈洪道人圓定','劉克莊','宋','宋诗','song-poetry','','[]','道人三昧力，手閲幾巖磚。',48,'全唐诗/poet.song.200000.json','["道人三昧力，手閲幾巖磚。", "既用功追琢，何憂質得堅。", "玉因石攻美，月以斧修圓。", "非遇良工剖，陶泓不受鎸。"]'),
('7d714605-fd3d-4eb9-86e7-19802ecb572a','歲晚試筆一首','劉克莊','宋','宋诗','song-poetry','','[]','憶與諸賢共造廷，暮年屈指略凋零。',64,'全唐诗/poet.song.200000.json','["憶與諸賢共造廷，暮年屈指略凋零。", "顔郎衫色有時紫，潘令鬢毛無日青。", "小草自應慙遠志，落英猶足制頹齡。", "左丞豈識吾詩者，舉向村姑倚樹聽。"]'),
('f8b8d502-8677-4069-a027-487d21061544','題研六言四首  其一','劉克莊','宋','宋诗','song-poetry','','[]','噓呵肌理泉潤，拊摩德性玉溫。',28,'全唐诗/poet.song.200000.json','["噓呵肌理泉潤，拊摩德性玉溫。", "可謂無毫髮恨，何曾犯斧鑿痕。"]'),
('54970b5f-1da7-41de-a977-7aed523a2bca','題研六言四首  其二','劉克莊','宋','宋诗','song-poetry','','[]','其面固已晬然，其背貴不可言。',28,'全唐诗/poet.song.200000.json','["其面固已晬然，其背貴不可言。", "寧捧以供李白，勿舉以擲鄭畋。"]'),
('92793255-b23d-4d70-9a22-37e72624ae91','題研六言四首  其三','劉克莊','宋','宋诗','song-poetry','','[]','無駁雜者其色，不磷緇者其德。',28,'全唐诗/poet.song.200000.json','["無駁雜者其色，不磷緇者其德。", "方巖求之不得，後村不求而獲。"]'),
('90ee2674-6505-4164-86a8-33acd5023947','題研六言四首  其四','劉克莊','宋','宋诗','song-poetry','','[]','眼如胡僧之碧，口如老龐之吸。',28,'全唐诗/poet.song.200000.json','["眼如胡僧之碧，口如老龐之吸。", "子雲要伴玄草，添丁勿翻墨汁。"]'),
('a1b4cc40-23a4-49de-9b92-14409304be51','縱筆二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','虛費燈窗一世勤，老師曾許與斯文。',64,'全唐诗/poet.song.200000.json','["虛費燈窗一世勤，老師曾許與斯文。", "玉臺不善諧新詠，金匱猶堪記舊聞。", "淺學安能演繁露，華堂苦愛誦微雲。", "史香騷艷無窮盡，歎息何人共摘熏。"]'),
('f376fe35-61cb-4544-9f57-c58ca2811554','縱筆二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','風月佳時一放懷，幸無章綬束筋骸。',64,'全唐诗/poet.song.200000.json','["風月佳時一放懷，幸無章綬束筋骸。", "眵昏端以親燈故，憂患皆從識字來。", "受業門人留不住，載醪客子儘教迴。", "閉門自了身心事，寄語時賢莫浪猜。"]'),
('1332fc69-f4e6-479d-ad42-b17c706fa1fa','示畫者','劉克莊','宋','宋诗','song-poetry','','[]','眉宇巑岏鬢禿殘，愧君模寫向冰紈。',64,'全唐诗/poet.song.200000.json','["眉宇巑岏鬢禿殘，愧君模寫向冰紈。", "削瓜古有形相肖，擲果今無衆聚觀。", "且可夷猶狎鷗鷺，不消夭矯比龍鸞。", "去爲將相開生面，莫貌山翁骨相寒。"]'),
('a4c60780-4b33-4ba7-9da1-ce0a7383335c','書感','劉克莊','宋','宋诗','song-poetry','','[]','恩賜殘骸得返耕，孤臣安敢厭承明。',64,'全唐诗/poet.song.200000.json','["恩賜殘骸得返耕，孤臣安敢厭承明。", "羊腸曾有單車覆，牛背那無一笛橫。", "俗子休疑眉宇異，癡人錯望耳毫生。", "老身雖厄心常泰，聽取商歌遶屋聲。"]'),
('54614085-1c89-4005-a7cb-e9440bbb407f','對卷','劉克莊','宋','宋诗','song-poetry','','[]','妙在心通與理融，卓然有見是英雄。',64,'全唐诗/poet.song.200000.json','["妙在心通與理融，卓然有見是英雄。", "大儒晚作韓考異，往哲曾非墨尚同。", "折角爭希郭有道，鬀眉求似狄梁公。", "可憐老學孤無助，月落參橫讀未終。"]'),
('fc42f6ca-cc1f-490f-8dfe-905dbc2f16fa','立春二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','絲切登盤菜，花垂插鬢幡。',24,'全唐诗/poet.song.200000.json','["絲切登盤菜，花垂插鬢幡。", "老人總無分，回施與諸孫。"]'),
('0036dacf-3921-4152-8dfe-45a12ea670b2','立春二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','枯槁蒙膏潤，誰非喜雨人。',24,'全唐诗/poet.song.200000.json','["枯槁蒙膏潤，誰非喜雨人。", "兒童翻懊惱，惜不看鞭春。"]'),
('ac8b02a6-b9e6-4379-8780-a72015a3b75b','忿慾一首','劉克莊','宋','宋诗','song-poetry','','[]','忿慾傷生甚斧斨，易言懲窒味尤長。',64,'全唐诗/poet.song.200000.json','["忿慾傷生甚斧斨，易言懲窒味尤長。", "古人明著佩韋戒，前輩猶煩按劍防。", "養似鬭鷄逢紀渻，避如决鹿見毛嬙。", "小齋掃去閑書畫，專揭吾詩置座傍。"]'),
('aa2fc1ed-2cb8-4ffc-928a-751875e12595','觀儺二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','烟燻野狐怪，雨熄畢方譌。',24,'全唐诗/poet.song.200000.json','["烟燻野狐怪，雨熄畢方譌。", "惟有三彭黠，深藏不畏儺。"]'),
('b59071fe-7140-4f81-9164-632e7f9a6724','觀儺二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','祓除嘯梁祟，驚走散花魔。',24,'全唐诗/poet.song.200000.json','["祓除嘯梁祟，驚走散花魔。", "切莫敺窮鬼，相從歲月多。"]'),
('16f8d0f3-53e0-4e8d-9517-58485fc57bbf','歲除二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','兒童燒爆竹，婦女治椒花。',24,'全唐诗/poet.song.200000.json','["兒童燒爆竹，婦女治椒花。", "獨有龍鍾叟，凄凉感歲華。"]'),
('a4a13b3f-cf21-45d9-b122-346de96b8ad2','歲除二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','冰銜常恁麽，雪鬢轉皤然。',24,'全唐诗/poet.song.200000.json','["冰銜常恁麽，雪鬢轉皤然。", "一事差堪喜，詩多似去年。"]'),
('71187c96-c527-49d3-b3af-46cf7492a3c0','戊午元日二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','過去光陰箭離弦，河清易俟鬢難玄。',64,'全唐诗/poet.song.200000.json','["過去光陰箭離弦，河清易俟鬢難玄。", "再加孔子從心歲，三倍周郎破賊年。", "耄齒阻陪鳩杖列，瞽言曾獻獸樽前。", "磻溪淇澳吾何敢，且學香山也自賢。"]'),
('fdf6e0c9-b903-49d3-b569-8d12d562f3e6','戊午元日二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','敗絮蕭然擁病身，久疎朝謁作閒人。',64,'全唐诗/poet.song.200000.json','["敗絮蕭然擁病身，久疎朝謁作閒人。", "公卿各趁黄麾仗，賓客誰看烏角巾。", "菱照無情難諱老，杏梢作意已撩春。", "卧聞兒女夸翁健，詩句年光一樣新。"]'),
('a143e5d6-3d5f-4dd6-aadc-154195f8bb83','送山甫銓試二首并寄强甫  其一','劉克莊','宋','宋诗','song-poetry','','[]','二昆南北各驅馳，季復隨群試有司。',64,'全唐诗/poet.song.200000.json','["二昆南北各驅馳，季復隨群試有司。", "蕃衍皆因先世積，荒嬉端爲乃翁慈。", "爭名古有笞兒語，任運吾無責子詩。", "萬一原夫能末綴，採蒲裹粽待歸期。"]'),
('1f7d9519-7a0b-4617-8318-3f6305839900','送山甫銓試二首并寄强甫  其二','劉克莊','宋','宋诗','song-poetry','','[]','家事如今亦盡傳，此冠未挂待何年。',64,'全唐诗/poet.song.200000.json','["家事如今亦盡傳，此冠未挂待何年。", "忍拋老漢□□畔，去傍渠儂水鏡邊。", "逆旅我能幾時客，自家□□□人憐。", "歸鴻數寄平安字，莫遣衰翁望眼穿。"]'),
('650e6535-ea21-4ca4-90b5-1a328231c666','挽南皋劉二先生  其一','劉克莊','宋','宋诗','song-poetry','','[]','久無羔雁聘遺賢，白首邱園氣最全。',64,'全唐诗/poet.song.200000.json','["久無羔雁聘遺賢，白首邱園氣最全。", "聊與荆公續詩選，不聞譙叟入經筵。", "講師翁庶幾三昧，樸學余纔說一篇。", "兩侍細旃莫推挽，諛儒此愧若爲湔。"]'),
('4028ed48-f274-46a5-99d9-68e08860f4bc','挽南皋劉二先生  其二','劉克莊','宋','宋诗','song-poetry','','[]','少時已誦水心銘，今息庵文可並行。',64,'全唐诗/poet.song.200000.json','["少時已誦水心銘，今息庵文可並行。", "椿算過如大君子，蒲輪莫致老先生。", "縱無掌故來傳詔，盍有門人與易名。", "嘗辱蓬山授經說，蟇陵道遠一傷情。"]'),
('08349440-66b6-4856-84ba-350055fc7644','天基節口占二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','報道東方欲辨晨，强扶衰憊起冠紳。',64,'全唐诗/poet.song.200000.json','["報道東方欲辨晨，强扶衰憊起冠紳。", "差賢眇者與跛者，竊比封人祝聖人。", "野老豈知蒙帝力，農夫稍有告余春。", "不須景慕斜川叟，且作田間擊壤民。"]'),
('b13a8017-a888-41ca-be0a-fd67e7c88e49','天基節口占二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','赫風隠隠聽宮縣，曾立紅雲一朵邊。',64,'全唐诗/poet.song.200000.json','["赫風隠隠聽宮縣，曾立紅雲一朵邊。", "天語下詢顔不遠，帝歌自作墨猶鮮。", "臺郎誰是玄都舊，輿尉安知絳老年。", "散吏宮花能幾許，諸孫爭怕落人先。"]'),
('9823fcb0-caab-4b0a-951e-8086c5034bf5','人日','劉克莊','宋','宋诗','song-poetry','','[]','元日至人日，未有不晴時。',48,'全唐诗/poet.song.200000.json','["元日至人日，未有不晴時。", "剝復觀周易，吟哦及杜詩。", "將開戶北向，折到杏南枝。", "不得東風力，余寒豈易支。"]'),
('4eb02dc8-d969-4581-afff-d157a6b08860','君疇仰晦茂功蒙仲和余差鬚韵二詩再答二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','懊悔平生擇術差，誓將秋實代春華。',64,'全唐诗/poet.song.200000.json','["懊悔平生擇術差，誓將秋實代春華。", "幸無大節汙青史，曾有狂言壞白麻。", "已約宗雷同入社，且饒燕許自成家。", "傍人不必爭殘線，禿筆何因肯再花。"]'),
('17ebfb4a-f69c-43ad-958c-8805bc9cef40','君疇仰晦茂功蒙仲和余差鬚韵二詩再答二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','衡與脩皆捋虎鬚，不論公幹與元瑜。',64,'全唐诗/poet.song.200000.json','["衡與脩皆捋虎鬚，不論公幹與元瑜。", "譏彈山寺詩爲謗，指點滄洲疏似諛。", "毛垢人將吹洗汝，涅磨渠不磷緇乎。", "勸君刊落閑枝葉，佩服高柴一字愚。"]'),
('a5689aec-10af-400c-a373-62a6080ebdc1','挽趙漕克勤禮部二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','渠觀英游轉首空，玄都葵麥幾春風。',64,'全唐诗/poet.song.200000.json','["渠觀英游轉首空，玄都葵麥幾春風。", "米郎筆絕九霄上，子駿星移五管東。", "雅拜從渠投石友，遺言以子爲山公。", "定應去判芙蓉館，不墮蠻雲蜑雨中。"]'),
('8a210f3a-ed5b-45d8-a07f-52b1de83eeee','挽趙漕克勤禮部二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','息影空山與世疎，感君意氣獨勤渠。',64,'全唐诗/poet.song.200000.json','["息影空山與世疎，感君意氣獨勤渠。", "頗憐鳳閣舍人老，猶寄羊城使者書。", "化鶴安知耽是我，騎鯨難問白何如。", "豈無蓴鯽堪携去，衰病誰扶上素車。"]'),
('76f3cb3d-22d7-4cac-9f72-e47aa3b6d8c2','燈夕二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','久矣龐公懶入城，偶逢節序尚牽情。',64,'全唐诗/poet.song.200000.json','["久矣龐公懶入城，偶逢節序尚牽情。", "盛鴟夷酒出行樂，鑄褭蹄金難買晴。", "不與賢豪競華轂，且隨兒女看優棚。", "老儒更爲明時喜，聞說西南黑祲清。"]'),
('fe47baa8-463b-4932-8eab-f4d518d0c869','燈夕二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','本子流傳自柳榮，著行線綵鬭鮮明。',64,'全唐诗/poet.song.200000.json','["本子流傳自柳榮，著行線綵鬭鮮明。", "似從傀儡家傳出，又說熙河帥教成。", "邊地烽烟差向裏，中州燈火尚承平。", "何嘗夜奪崑崙隘，真爲君王奏凱聲。"]'),
('2b75123b-16a7-4d90-8690-54751bf9fc62','又和宋侯三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','春風纔扇已微和，燈市新年笑語多。',64,'全唐诗/poet.song.200000.json','["春風纔扇已微和，燈市新年笑語多。", "時有老農行拾穗，豈無太史筆歸禾。", "少留樓上三通鼓，休記雲間第一歌。", "傳說遨頭詩句好，曹劉牆短不難過。"]'),
('2ba018b0-6485-420f-b036-38749268d71f','又和宋侯三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','鈴齋教令得民和，月色今宵十倍多。',64,'全唐诗/poet.song.200000.json','["鈴齋教令得民和，月色今宵十倍多。", "節物人家俱插柳，霽華田舍可鞭禾。", "坐中客醉僛僛舞，陌上花開緩緩歌。", "老子尚堪牽率在，夜歸已有木魚過。"]'),
('5584a3fa-f773-4cf7-9796-560224ffb03f','又和宋侯三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','梨園部裏奏雲和，衰惰煩公發藥多。',64,'全唐诗/poet.song.200000.json','["梨園部裏奏雲和，衰惰煩公發藥多。", "有囀春鶑觴客酒，無如龍馬暴民禾。", "盍陪天下傳柑宴，且聽民間秀麥歌。", "歸對蓬窗燈一點，却疑太乙夜相過。"]'),
('ffa49b20-807b-467d-bed9-b9eef373a379','和居厚弟一首','劉克莊','宋','宋诗','song-poetry','','[]','處處笙歌雜誦謠，盍簪一笑共今宵。',64,'全唐诗/poet.song.200000.json','["處處笙歌雜誦謠，盍簪一笑共今宵。", "宛然上齒尊三老，非若班廷序百僚。", "鄉飲詎宜先仗出，虞人不必以弓招。", "明時各適鳶魚性，在野尤和似在朝。"]'),
('abf3f118-2538-4a2f-a443-05c3d9bad95c','送質甫姪銓試','劉克莊','宋','宋诗','song-poetry','','[]','處和昔牧羅浮郡，不載南州一物還。',64,'全唐诗/poet.song.200000.json','["處和昔牧羅浮郡，不載南州一物還。", "醖藉汝何慚小阮，空疎吾謬作梁山。", "步趨諸老先生後，遨兀齋郎太祝間。", "華髮病翁無喜事，直須春榜一開顔。"]'),
('266d3173-0ccd-4b5f-b92c-c3beb90a0876','宋侯和燈夕詩再用韵二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','茜袂黄眉出滿城，賢侯遊豫順民情。',64,'全唐诗/poet.song.200000.json','["茜袂黄眉出滿城，賢侯遊豫順民情。", "鼓聲足驗村田樂，月色遥占輦路晴。", "定有儒臣映藜仗，又聞京尹折蓮棚。", "祠官一瓣無它祝，但願旄頭盡掃清。"]'),
('2a3cd1a7-2ca8-4145-b95e-85c1ba447c46','宋侯和燈夕詩再用韵二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','近傳桂管置行營，想見臨淮號令明。',64,'全唐诗/poet.song.200000.json','["近傳桂管置行營，想見臨淮號令明。", "書載舞干文德遠，曲名破陣武功成。", "小兒隊整遺風在，大將壇荒舊址平。", "未得軍前實消息，强歌安得有歡聲。"]'),
('51e751c6-cc72-414a-a24d-e628edbb6bd8','挽林計院二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','材名漢廷選，文學孔門科。',48,'全唐诗/poet.song.200000.json','["材名漢廷選，文學孔門科。", "不仿治安策，宜賡喜起歌。", "三麾老龔遂，一榻病維摩。", "此事懸於命，吁嗟可奈何。"]'),
('83eb3cb4-fc84-4340-9ce1-84848d0eb576','挽林計院二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','檢點齊年友，凋零重可悲。',48,'全唐诗/poet.song.200000.json','["檢點齊年友，凋零重可悲。", "君逢庚子鵩，我歎甲辰雌。", "鷗社同盟少，蟇陵會哭誰。", "暮齡多感慨，鄰笛更須吹。"]'),
('ae306156-d9a3-4ea8-a7dd-ed49b1becde4','錄漢唐事六言五首  其一','劉克莊','宋','宋诗','song-poetry','','[]','漁陽之鼓動地，蚩尤之旗竟天。',28,'全唐诗/poet.song.200000.json','["漁陽之鼓動地，蚩尤之旗竟天。", "梨園弟子按樂，竹宮方士求仙。"]'),
('24d3bb90-d6f1-4bea-b1f2-d2eaf6857884','錄漢唐事六言五首  其二','劉克莊','宋','宋诗','song-poetry','','[]','群雄競起問鼎，老賊傍觀朵頤。',28,'全唐诗/poet.song.200000.json','["群雄競起問鼎，老賊傍觀朵頤。", "汾陰三趾去矣，桐江一絲繫之。"]'),
('ebc370a2-d09b-4876-9d5d-00b985514c8e','錄漢唐事六言五首  其三','劉克莊','宋','宋诗','song-poetry','','[]','二聖已重勸了，西京無一塵飛。',28,'全唐诗/poet.song.200000.json','["二聖已重勸了，西京無一塵飛。", "白衣山人辭去，青袍拾遺步歸。"]'),
('0f84a12a-6a8c-490c-83b2-38cb6680bd30','錄漢唐事六言五首  其四','劉克莊','宋','宋诗','song-poetry','','[]','文叔親臨卧所，君房邀過台司。',28,'全唐诗/poet.song.200000.json','["文叔親臨卧所，君房邀過台司。", "脚加帝腹一笑，身居鼎足尚癡。"]'),
('7152e20d-4a89-477f-93ae-20e380fc1cdf','錄漢唐事六言五首  其五','劉克莊','宋','宋诗','song-poetry','','[]','燕許秉筆封岱，歐虞揮翰登瀛。',28,'全唐诗/poet.song.200000.json','["燕許秉筆封岱，歐虞揮翰登瀛。", "寧死開元貞觀，勿生天寶廣明。"]'),
('d73a03c2-bfd4-4810-aac6-7dea496ef3d6','答章林伯','劉克莊','宋','宋诗','song-poetry','','[]','自笑狂吟浪竊名，敢將孤壘敵長城。',64,'全唐诗/poet.song.200000.json','["自笑狂吟浪竊名，敢將孤壘敵長城。", "才高君策追風驃，計急吾陳背水兵。", "遠道書來如面見，異時序反託詩行。", "殘年無復遊吳楚，樽酒何由得細評。"]'),
('bb02c7ea-e6a0-49eb-aaaa-5bf9223d9f93','南康趙明府贈予四詩和其首篇二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','曾掌蘭臺纂舊聞，亦瞻玉座和來薰。',64,'全唐诗/poet.song.200000.json','["曾掌蘭臺纂舊聞，亦瞻玉座和來薰。", "戇愚漫有誅姦筆，疎拙元無乞巧文。", "執簡自知愧南董，免冠誰肯救朱雲。", "消磨不盡惟詩在，社友尋盟意尚勤。"]'),
('36b65591-8453-45f5-89b1-3d21a0f51957','南康趙明府贈予四詩和其首篇二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','二老風流接見聞，餘香未遠尚堪薰。',64,'全唐诗/poet.song.200000.json','["二老風流接見聞，餘香未遠尚堪薰。", "明師豈不使人巧，老僕安能重子文。", "策蹇何由追抹電，化龍吾亦願爲雲。", "從來作聖功夫處，不在生知在積勤。"]'),
('43b40d94-3ac7-4383-bd62-95480ae794ff','送黄戶曹','劉克莊','宋','宋诗','song-poetry','','[]','拂榻遲居久，今纔問戍瓜。',48,'全唐诗/poet.song.200000.json','["拂榻遲居久，今纔問戍瓜。", "海鄉真佛國，府主似包家。", "友喜吟添稿，胥驚判有花。", "筍柑妙天下，長鋏不須嗟。"]'),
('b9f7478c-ea61-4ff3-9d79-f192ee59e41a','君疇仲晦蒙仲再和余差鬚二詩警齋侍郎又繼之趁韵走謝  其一','劉克莊','宋','宋诗','song-poetry','','[]','丹爐爆裂話頭差，攬鏡顔蒼兩鬢華。',64,'全唐诗/poet.song.200000.json','["丹爐爆裂話頭差，攬鏡顔蒼兩鬢華。", "不記省中詠薇藥，徑歸韋曲問桑麻。", "卿雲方薦漢郊廟，郊島難鳴唐國家。", "誰向玄都君子說，有春風處有桃花。"]'),
('fbda2dfe-6d98-44b3-ad20-e60afdba8c4e','君疇仲晦蒙仲再和余差鬚二詩警齋侍郎又繼之趁韵走謝  其二','劉克莊','宋','宋诗','song-poetry','','[]','垢衣忘澣虱游鬚，豈有村情似長瑜。',64,'全唐诗/poet.song.200000.json','["垢衣忘澣虱游鬚，豈有村情似長瑜。", "作聖德詩無乃怪，進文鑑序近於諛。", "熱中人有讒余者，殿後天將壽我乎。", "晚覺陶翁嗔子懶，不如坡老願兒愚。"]'),
('3669b00e-cacf-4fff-b9c4-9d8cc8abb5b4','奉酬吳洪二公三和之什  其一','劉克莊','宋','宋诗','song-poetry','','[]','千層墜爲一毫差，還了魚鬚脫革華。',64,'全唐诗/poet.song.200000.json','["千層墜爲一毫差，還了魚鬚脫革華。", "數尺了無懷內錦，三斤空有話頭麻。", "早曾謁帝吟薰殿，晚欲逃儒入墨家。", "自笑老人心尚駿，故吾不換換新花。"]'),
('212422a9-fde4-4eea-aab0-a48c19f908fe','奉酬吳洪二公三和之什  其二','劉克莊','宋','宋诗','song-poetry','','[]','衰容懶鑷白髭鬚，新詠難追紀少瑜。',64,'全唐诗/poet.song.200000.json','["衰容懶鑷白髭鬚，新詠難追紀少瑜。", "攀檻公曾排禹佞，下帷我亦鄙弘諛。", "瓶沽何必太玄也，褐博嘗聞大勇乎。", "捽茹膾肝均一飽，不知誰聖復誰愚。"]'),
('cf320012-da94-4f3b-9f95-dae857aa66f2','答卓常簿二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','神仙富貴擬皆差，已把雲臺讓仲華。',64,'全唐诗/poet.song.200000.json','["神仙富貴擬皆差，已把雲臺讓仲華。", "幸有庾郎三種韭，別無滕叔兩車麻。", "斬新句子包諸體，放潑腔兒令一家。", "白白紅紅滿山谷，不知天女散何花。"]'),
('7880bc2a-a2bc-46ff-b2aa-26f7f8d000f4','答卓常簿二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','點點新霜上鬢鬚，深藏誰辨握中瑜。',64,'全唐诗/poet.song.200000.json','["點點新霜上鬢鬚，深藏誰辨握中瑜。", "曾爲上寢斜封濫，可使人譏曲學諛。", "已作鳳飛天外者，安能鳬泛水中乎。", "近來贈誄多虛美，自考平生合謚愚。"]'),
('d16f567c-7e8b-4961-9007-3346254c3b71','諸公和差鬚二詩不已又得二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','壯志蹉跎隠事差，瓣香稽首向南華。',64,'全唐诗/poet.song.200000.json','["壯志蹉跎隠事差，瓣香稽首向南華。", "歲收別業無千絹，晨起齋厨止一麻。", "麥飯何妨薦寒食，榆錢元不濟貧家。", "金瓶爛熳簪姚魏，誰問幽蘭澗底花。"]'),
('a54abf6f-491d-4882-87f9-27d1c249e3c1','諸公和差鬚二詩不已又得二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','乏蕭生表褚公鬚，那更癡年已倍瑜。',64,'全唐诗/poet.song.200000.json','["乏蕭生表褚公鬚，那更癡年已倍瑜。", "愛北征詩窮愈壯，鄙東封稿死猶諛。", "譽臣亦有毀臣者，知我寧無罪我乎。", "惜取寶珍常自照，底須揭日耀群愚。"]'),
('ea618a86-307f-47e9-aec9-e4f6dbac6705','陪宋侯趙倅過倉部弟家園賓主有詩次韵二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','駕鷄棲尾隼輿行，取次亭臺若幻成。',64,'全唐诗/poet.song.200000.json','["駕鷄棲尾隼輿行，取次亭臺若幻成。", "五畝季方榮獨樂，一麾侯豈厭承明。", "芳時別駕聯鑣出，歸晚華燈夾道迎。", "留得廣平春却否，傳聞已有璽書旌。"]'),
('27511be6-f78d-4da0-a35a-cf481b6be746','陪宋侯趙倅過倉部弟家園賓主有詩次韵二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','偶陪小隊謝池行，雲澹風輕雨未成。',64,'全唐诗/poet.song.200000.json','["偶陪小隊謝池行，雲澹風輕雨未成。", "夢草詩情全老退，見花病眼尚分明。", "即今樵笛村童和，當日金蓮院吏迎。", "得向騷壇分半席，絕勝一品與三旌。"]'),
('29820a71-0194-4d5f-a5d5-ea8018a127b2','次韵使君劭農一首','劉克莊','宋','宋诗','song-poetry','','[]','朱幡奉詔省春耕，掃去陰霾旋放晴。',64,'全唐诗/poet.song.200000.json','["朱幡奉詔省春耕，掃去陰霾旋放晴。", "應有羅敷隨馬看，不煩桃葉渡江迎。", "棠陰民各爲封植，木德侯方體發生。", "少借一年天肯否，要看穡寶得秋成。"]'),
('79803868-4bba-49ea-8bda-334197ab494e','中𡼢春祀二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','少者游方老守閭，獨携魚菽薦幽墟。',32,'全唐诗/poet.song.200000.json','["少者游方老守閭，獨携魚菽薦幽墟。", "何時汝輩無行役，歲歲爲翁策蹇馿。"]'),
('92c3d187-39e4-43d8-95cc-9c9c1c9b778e','中𡼢春祀二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','歸鞍常苦夕陽催，小憩聊分飲胙盃。',32,'全唐诗/poet.song.200000.json','["歸鞍常苦夕陽催，小憩聊分飲胙盃。", "萬一得年如小父，尚堪十度掃松來。"]'),
('8bca49d6-45c3-4900-a12c-87fcb4ab6279','延平湯使君惠雙溪樓記跋以小詩','劉克莊','宋','宋诗','song-poetry','','[]','吾評此記前無古，歷歷溪山在目中。',64,'全唐诗/poet.song.200000.json','["吾評此記前無古，歷歷溪山在目中。", "潦後數椽誰樸斲，雲間千尺忽青紅。", "比滁亭筆尤高簡，與洛橋碑角長雄。", "父老皆云侯苦節，咄嗟幻出化人宮。"]'),
('bfc27aec-5492-4444-aeec-98157be21825','次韻別宋希仁','劉克莊','宋','宋诗','song-poetry','','[]','四山寂寞南塘死，此事今誰得緒餘。',64,'全唐诗/poet.song.200000.json','["四山寂寞南塘死，此事今誰得緒餘。", "耳冷不聞前輩論，眼明猶讀後生書。", "我如蒲柳驚秋早，君似芙蕖出水初。", "此別未知重面日，可堪回首送軒車。"]'),
('f9022126-ef08-4d97-a2d4-1bd3f6854881','題張遯夫詩卷','劉克莊','宋','宋诗','song-poetry','','[]','憶昔乘雲覲帝傍，一時聳聽鳳鳴陽。',64,'全唐诗/poet.song.200000.json','["憶昔乘雲覲帝傍，一時聳聽鳳鳴陽。", "久無老子出幽谷，曾有謫仙流夜郎。", "嘿似銅人姑勿論，憂能玉汝義何傷。", "唾壺麈尾俱麾去，只挈隨身古錦囊。"]');
